INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000002811', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "수불사추모공원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "최기희", "companyno": "127-89-10088", "telephone": "031-832-6222", "faxnum": null, "homepage": "subulsa.kr/greeting", "fulladdress": "경기도 연천군 청산면 전영로215번길 153-16, 수불사추모공원 ", "zipcd": "11020", "latitude": null, "longitude": null, "sidonm": "경기도 연천군", "orgid": "4140000", "orgidnm": "경기도 연천군", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "수불사는 경기도 연천군 청산면에 위치한 절로, 연천군청에서 남쪽으로 8.6km 떨어진 산자락 평지에 있습니다. 청산면은 동쪽은 포천군 창수면, 서쪽과 북쪽은 전곡읍, 남쪽은 동두천시와 포천군 신북면에 접합니다. 이 절은 종현산이 솟아 있는 험한 산지를 이루고 있으며, 해발고도 100∼200m의 구릉성 산지와 평지를 가지고 있습니다. 장탄리는 한탄강변에 자리한 강변마을로, 1895년 지방관제 개정으로 연천군에 편입되었습니다. 최근에는 수불사에서 동양최대 와불이 조성되어 있는 곳입니다.", "traffpublic": "전곡역에서10분 거리 위치, 전곡터미널 버스 1시간 간격 운행 수불사 입구에서 하차", "traffowner": "네비에 연천수불사 입력 후 안내 받을 수 있습니다. ", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 20, "waitroom": true, "handicap": true}, "lastUpdateDate": "2024/08/30", "priceitemdate": "2024/08/30"}'::jsonb, '{"hallRent": [{"item": "1층 프리미엄관 일반실 1단", "category": "개인단", "subcategory": null, "rentcontent": "관리비-(5년) 일시 납 : 300,000원", "facilityamt": 3500000, "facilityamtm": "3,500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "1층 프리미엄관 일반실 2단", "category": "개인단", "subcategory": null, "rentcontent": "관리비-(5년) 일시 납 : 300,000원", "facilityamt": 4500000, "facilityamtm": "4,500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "1층 프리미엄관 일반실 3단", "category": "개인단", "subcategory": null, "