INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001030', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(재)용인추모원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "노석환", "companyno": "142-82-00708", "telephone": "031-283-1601", "faxnum": null, "homepage": "www.yich.co.kr", "fulladdress": "경기도 용인시 기흥구 중부대로 972 (상하동, 재단법인용인추모원)", "zipcd": "17089", "latitude": "37.2492386", "longitude": "127.1553066", "sidonm": "경기도 용인시 기흥구", "orgid": "4050000", "orgidnm": "경기도 용인시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "1.용인 유일의 재단법인 봉안당(납골당)-\r\n   민법 및 장사등에 관한 법률에 의거 설립된 재단법인으로 유사시\r\n   지자체가 법인을 관리하여 안치된 유골의 영구적인 관리가 법적으로 보장됩니다\r\n\r\n2.고인과 후손 모두 만족하는 입지-\r\n  용인의 중심부에 위치하며, 교통과 도시 접근성이 편리합니다\r\n\r\n3.고급스럽고 영구적인 고품격 안치단-\r\n  브론즈(동)안치단으로 전자파와 수맥차단 효과가 높고 외관이 수려합니다\r\n\r\n4.모셔진 유골은 재단법인에 \"영구안치\"됩니다 ", "traffpublic": "■ 버스 \r\n□ 고속직행\r\n► 5001번(양재동.강남역 방향) 효자고개 승/하차 \r\n► 5005번(서울역.남대문 방향) 효자고개 승/하차\r\n► 5600번(수서,송파,잠실 방향) 효자고개 승/하차\r\n□ 일반버스\r\n► 효자 고개(구 용인정신병원)에서 하차-도보 5분\r\n ▫ 66 : 수원역 ↔ 에버랜드\r\n ▫ 10 : 수원역 ↔ 백암\r\n ▫ 690 : 수지구청 ↔ 용인터미널\r\n ▫ 820 : 정자역(분당선) ↔ 명지대\r\n ▫ 88 : 용인터미널 ↔ 삼성반도체\r\n\r\n■ 지하철\r\n□ 분당선: 기흥역 하차--용인시청방향 버스 탑승--효자고개 하차--도보 5분\r\n□ 용인경전철 : 삼가역 하차--수원방향 버스탑승--효자고개 하차--도보 5분", "traffowner": " 서울 강남에서 30분 거리\r\n\r\n■ 수원TG(신갈오거리)방향에서 오실때\r\n □ 효자고개 정상 우측 진입로 이용\r\n\r\n■ 용인TG(용인시청)방향에서 오실때\r\n□ 용인정신병원앞 유턴후 효자고개 정상 우측 진입로 이용", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 100, "waitroom": true, "handicap": true}, "lastUpdateDate": "2019/06/19", "priceitemdate": "2019/06/19"}'::jsonb, '{"hallRent": [{"item": "1층 유니크 가족단", "category": "기타", "subcategory": n