INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000002457', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "마라나타하늘정원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "주경훈", "companyno": "610-82-82315", "telephone": "02-6413-1764", "faxnum": null, "homepage": "www.maranathagh.co.kr", "fulladdress": "경기도 가평군 가평읍 호반로 2424-22 (달전리, 오륜비전빌리지)", "zipcd": "12422", "latitude": null, "longitude": null, "sidonm": "경기도 가평군", "orgid": "4160000", "orgidnm": "경기도 가평군", "firstcharnelcnt": 30, "renewyears": 30, "renewcount": 1, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "함께함이 소중한 기쁨이 된 사람 언제나 따뜻한 위로가 된 사람\r\n 고인은 천국에서도 언제나처럼 사랑하며 살고 있을 것입니다.\r\n그리운 마음 속 그 분과 함께한 시간들이 아름다운 추억이 되어 만날 수 있도록\r\n 마라나타하늘정원이 소중하고 특별하게 모시겠습니다. ", "traffpublic": "•수도권 7호선 군자역 → 경춘선 상봉역 환승 → 경춘선 가평역 하차 → 일반버스 33-14, 33-32(가평역) → 가평군상수도사업소 하차 → 오륜 비전빌리지까지 약 500m 도보이동 → 마라나타하늘정원\r\n•잠실역 롯데월드 정류장 7000번 승차 → 가평 공영버스정류장 하차 → 가평터미널정류장 승차 33-14, 33-32 → 가평군상수도사업소 하차 → 오륜비전빌리지까지 약 500m 도보이동 → 마라나타하늘정원\r\n•서울시 지하철 2호선 강변역 -> 동서울 종합터미널 -> 가평시외버스터미널 ", "traffowner": "\r\n◦올림픽대로 – 서울양양고속도로 → 화도IC → 46번 국도 → 대성리 → 청평 → 가평오거리에서 우회전 남이섬 방향 → 가평역 삼거리에서 직진 \r\n◦서울양양고속도로 - 설악IC → 가평대교 → 75번 국도 → 장승고개 우측", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 100, "waitroom": true, "handicap": true}, "lastUpdateDate": "2020/11/17", "priceitemdate": "2020/11/17"}'::jsonb, '{"hallRent": [{"item": "안치단(1단)-개인단(일시납입기준)", "category": "개인단", "subcategory": null, "rentcontent": "가로 28Cm, 세로 26Cm", "facilityamt": 1500000, "facilityamtm": "1,500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "안치단(2단)-개인단(일시납입기준)", "category": "개인단", "subcategory": null, "rentcontent":