INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000002496', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "무궁화추모공원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "박두용", "companyno": "308-82-08275", "telephone": "041-734-3844", "faxnum": null, "homepage": "www.neverend.kr", "fulladdress": "충청남도 논산시 벌곡면 황룡재로553번길 148-71 (양산리)", "zipcd": "33026", "latitude": "36.226043", "longitude": "127.256935", "sidonm": "충청남도 논산시", "orgid": "4540000", "orgidnm": "충청남도 논산시", "firstcharnelcnt": 30, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "무궁화 추모공원은 충남 논산시 벌곡면 황룡재로553번길 148-71에 있는 납골당입니다. 2020년 8월에 준공하고 2020년 12월에 개원하였습니다. 부모님이나 조상님 또는 가족, 지인을 모시고자 하는 분들은 우선 무궁화 추모공원에 전화 또는 방문을 하셔서 미리 접수를 하시고, 가까운 화장장에서 유해나 유골을 화장을 하신 뒤에 이곳 무궁화 추모공원으로 유골함을 모시고 오시면 됩니다. 누구에게나 분양합니다. 언제든지 연락 환영합니다.", "traffpublic": "기차로 오시는 분은 논산역이나 계룡역에 내리셔서 택시로 오시면 됩니다. 논산역에 내리셔서 시내버스로 오시려면 벌곡으로 오는 340번 버스를 타고 오시면 됩니다. 약 1시간 간격으로 있습니다.", "traffowner": "자가용으로 오시는 분은 고속도로 이용을 추천합니다. 양촌IC에서 10분, 계룡IC에서 15분 정도 소요됩니다. 논산, 계룡, 대전, 세종, 금산, 익산, 전주, 공주, 부여 등 가까운 곳에 계시는 분은 국도로 오셔도 충분히 빨리 오실 수 있습니다. 이곳 주소는 충남 논산시 벌곡면 황룡재로553번길 148-71 무궁화추모공원입니다. 041-7834-3844 010-9706-3106", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 30, "waitroom": true, "handicap": true}, "lastUpdateDate": "2021/12/10", "priceitemdate": "2021/12/10"}'::jsonb, '{"hallRent": [{"item": "개인 1단", "category": "개인단", "subcategory": null, "rentcontent": "VIP실", "facilityamt": 2450000, "facilityamtm": "2,450,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "개인 2단", "category": "개인단", "subcategory": null, "rentcontent": "VIP실", "facilityamt": 3850000,