INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000900', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "모악추모공원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "최윤실", "companyno": "418-82-06628", "telephone": "1577-3525", "faxnum": null, "homepage": "www.moakpark.co.kr", "fulladdress": "전라북도 전주시 완산구 우림로 714 (용복동)", "zipcd": "560297", "latitude": "35.7661325", "longitude": "127.0749837", "sidonm": "전북특별자치도 전주시 완산구", "orgid": "4640000", "orgidnm": "전북특별자치도 전주시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "\r\n\r\n아름다운 歸鄕   모악추모공원\r\n\r\n- 재단법인 관리 운영으로 안정성 및 영속성 유지\r\n- 어머니의 품처럼 따스하고 품격이 느껴지는 시설\r\n- 모악산 자락에 위치한 천혜의 자연 환경\r\n\r\n", "traffpublic": "버스 이용시\r\n\r\n① 79번 버스 : 전주역 → 대학병원 입구 → 시외버스 터미널 → 금암광장 → 전동성당 → 용머리고개\r\n                   → 효자광장 → 해성중.고등학교 → 중인 삼거리 → 구덕마을(하차)\r\n\r\n② 79번 버스 : 금산사 → 용화동 → 하운교 → 청도리 → 독배마을 → 구덕마을(하차)", "traffowner": "① 중인동 나들목에서 3분 소요\r\n② 중인동 삼거리에서 5분 소요\r\n③ 평화동 사거리에서 7분 소요\r\n④ 전주 IC에서 15분 소요(자동차 전용도로 이용)", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 150, "waitroom": true, "handicap": true}, "lastUpdateDate": "2025/11/18", "priceitemdate": "2025/11/18"}'::jsonb, '{"hallRent": [{"item": "[일반실]개인단 1단", "category": "개인단", "subcategory": null, "rentcontent": "영구분양", "facilityamt": 4000000, "facilityamtm": "4,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "[일반실]개인단 2단", "category": "개인단", "subcategory": null, "rentcontent": "영구분양", "facilityamt": 5100000, "facilityamtm": "5,100,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "[일반실]개인단 3단", "category": "개인단", "