INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000922', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "신불산추모공원 납골당", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "신불산 추모공원", "companyno": "621-82-68569", "telephone": "055-363-4666", "faxnum": "055-363-0590", "homepage": "www.sbjs.kr/", "fulladdress": "경상남도 양산시 어실로 602-1 (어곡동)", "zipcd": "626220", "latitude": "35.3899337", "longitude": "129.0094088", "sidonm": "경상남도 양산시", "orgid": "5380000", "orgidnm": "경상남도 양산시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "부산, 울산에서 30분 거리의 가장 가까운 수목장 시설입니다. \r\n\r\n본 재단법인은 신불산 공원묘원부터 41년동안 부산시민, 울산시민, 경남도민을 위해 장사시설을 운영하고 있으며, 최근 화장률이 높아지는 시대의 흐름에 발맞추어 납골당과 수목장 시설을 개소하게 되었습니다.\r\n\r\n특징1. 가까운 거리(30분)\r\n부산시와 울산시에는 수목장이 없습니다. 경남에서도 30분 거리에는 본건 시설이 유일합니다. 거창과 남해에 공설 수목장이 있지만, 부산시민과 울산시민이 가실 수 있는 거리는 아니라고 생각합니다. 가깝습니다. 신불산 부산수목장.\r\n\r\n특징2. 신뢰성 있는 41년 전통의 운영\r\n본 법인은 신불산 공원묘원부터 41년간 장사시설을 운영해왔습니다. 무허가 수목장과 분양사기 납골당이 너무나도 많습니다. 하루아침에 조상님 계신 곳이 없어질 수도 있습니다. 본 법인은 41년간의 역사를 통해 그 신뢰성을 입증받았으며, 이를 이어 나가겠습니다.\r\n\r\n특징3. 극락왕생의 명당\r\n본 시설은 신불산 공원묘원 때부터 풍수지리적 명당으로 다수의 유명인이 묘자리로 선택한 점은 주지의 사실입니다. 앞으로도 부산시민, 울산시민, 경남도민께서 조상의 은덕을 누릴 수 있게 수목장과 납골당으로 만나뵙겠습니다.\r\n\r\n감사합니다. 055-363-4666", "traffpublic": "양산역에서 택시를 타고 15~20분 타고 오십니다. ", "traffowner": "양산 에덴밸리, 경남 외국어고등학교에 인접해 있으며 네이버/다음에 ''신불산 추모공원''을 검색하시면 바로 위치 확인 가능합니다.", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 55, "waitroom": true, "handicap": false}, "lastUpdateDate": "2023/03/23", "priceitemdate": "2023/03/23"}'::jsonb, '{"hallRent": [{"item": "1단", "category": "개인단", "subcategory": null, "rentcontent": "개인단, 관리비 32,000원/년", "faci