INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000030', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "영모묘원 대원전", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "박두용", "companyno": "403-82-02917", "telephone": "063-836-4311", "faxnum": null, "homepage": null, "fulladdress": "전라북도 익산시 왕궁면 호반로 173-45 (동봉리, 영모묘원납골당)", "zipcd": "54575", "latitude": "36.0013887", "longitude": "127.0915934", "sidonm": "전북특별자치도 익산시", "orgid": "4680000", "orgidnm": "전북특별자치도 익산시", "firstcharnelcnt": 30, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "전국에서 가장 아름다운 사설공원묘지", "traffpublic": "<영모묘원 대중교통 이용>\n금마면에서\n금마면 ~ 왕궁면 지역 버스 운영하고 있습니다.\n남부터미널(서울)에서 왕궁 농공단지하차하면 콜버스로 영모묘원에 오실 수 있습니다.\n1.금마터미널에서 출발하는 DIT(콜버스,버스와 택시의 장점) 25인승 운영\n2.전화 1533-3421 (원하는 시간의 30분전에 전화주세요)\n3.이용시간 : 월요일~금요일(오전9시~오후5시)\n  연중 공휴일과 토요일, 일요일 운행 안함\n4.노선버스 이용 : 콜버스 운행 안하는 일정에 이용합니다.\n  출발하는 곳은 금마터미널\n  버스번호 5740, 5750\n   (번호5740 출발시간 7:00  17:30  19:35 / 번호5750 출발시간 9:05  18:35)\n   노선버스는 남부터미널 왕궁농공단지 하차장에서 조금 걸어서 승하차합니다.\n*카카오맵에서 버스번호 검색하면 운행코스를 확인할 수 있습니다\n*익산역을 이용하신다면 \n  중앙동 방향에서 내리시고, 일반버스 ''안종옥안과'' 정류장에서 버스번호2100번을 타고 금마터미널까지 오시면 금마터미널에서 출발하는 콜버스나 노선버스를 이용합니다.\n\n *영모묘원에서 나가시는 대중교통은 콜버스 1533-3421 이용하시고, 노선버스는 회차되므로 영모묘원에서 승차시간을 예정할 수 있습니다.", "traffowner": null, "facilities": {"mealroom": true, "supermarket": false, "parking": true, "parkingCount": 1000, "waitroom": true, "handicap": true}, "lastUpdateDate": "2023/07/19", "priceitemdate": "2023/07/19"}'::jsonb, '{"hallRent": [{"item": "대원전1층 1단", "category": "개인단", "subcategory": null, "rentcontent": "30㎝x30㎝x30㎝", "facilityamt": 1800000, "facilityamtm": "1,800,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0