INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000145', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "부산추모공원 봉안당", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "부산시설공단", "companyno": "605-82-05242", "telephone": "051-790-5100", "faxnum": null, "homepage": "https://memorialpark.bisco.or.kr/memorialpark/index.asp", "fulladdress": "부산광역시 기장군 정관읍 정관로 225 (두명리, 부산추모공원)", "zipcd": "46001", "latitude": "35.3467592", "longitude": "129.1601588", "sidonm": "부산광역시 기장군", "orgid": "6260000", "orgidnm": "부산광역시", "firstcharnelcnt": 15, "renewyears": 5, "renewcount": 3, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "저희 부산추모공원은 영락공원 봉안시설의 만장에 따른 공설장사시설 확충 필요, 화장중심의 장사정책에 부응하는 현대적 시설개발의 필요성 대두, 장사에 대한 긍정적 인식으로 생활속 공간창출이라는 조성배경으로 2008년 2월 14일부터 봉안업무를 개시하여 운영중에 있습니다.", "traffpublic": "버스 ·지하철 : 노포동 지하철 역 하차 → 시내버스 37번 환승 → 부산추모공원(예상소요시간 : 20분)   \r\n8번 마을버스\r\n기장 - 좌천삼거리 - 정관면사무소 - 한진해모로 - 부산추모공원 - 월평삼거리 \r\n일반 37번\r\n노포동 지하철역 - 부산추모공원 - 한진해모로 - 정관면사무소 - 좌천삼거리 - 월내 \r\n일반 188번\r\n반송 - 기장도서관 - 좌천삼거리 - 정관면사무소 \r\n일반 107번\r\n벡스코 - 해운대경찰서 - 철마면사무소 - 정관면사무소 \r\n급행 1008번 \r\n동래지하철역 - 부산대학교 - 정관면사무소 - 좌천원자력의학원 \r\n급행 1010번 \r\n서면 롯데백화점 - 부산시청 - 연산교차로 - 곰내터널입구 - 한진해모로 \r\n※ 188,107,1008번 버스 이용 시 정관면사무소에서 일반 37번으로 환승하시면 됩니다.\r\n    1010번 버스 이용 시 한진해모로에서 일반37번으로 환승하시면 됩니다.", "traffowner": "국도 이용시 \r\n노포TG→노포동 지하철 역→여락고가교→임기마을→법기마을→개곡마을→임곡마을→정관과적검문소→\r\n월평삼거리 (정관방면 우회전)→추모공원 (총연장 : 13.59㎞, 예상소요시간 : 20분) \r\n  \r\n고속도로 이용시 \r\n구서IC(벡스코방면)→오륜터널→회동교차로(정관신도시방면)→개좌터널→곰내터널→정관로(월평교차로방면 좌회전)→\r\n부산추모공원(총연장20㎞, 예상소요시간 : 20분) ", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 511, "waitroom": true, "handicap": false}, "lastUpdateDate": "2017/11/24", "priceite