INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001064', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "천주교 서울대교구 평화묘원 봉안묘", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "(재)천주교 서울대교구 유지재단", "companyno": "201-82-00972", "telephone": "031-532-9723", "faxnum": null, "homepage": null, "fulladdress": "경기도 포천시 화현면 영일로368번길 66 (지현리)", "zipcd": "11124", "latitude": null, "longitude": null, "sidonm": "경기도 포천시", "orgid": "5600000", "orgidnm": "경기도 포천시", "firstcharnelcnt": 30, "renewyears": 30, "renewcount": 3, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "천주교 서울대교구 평화묘원 시설 이용 자격 조건\r\n1.망자(망인):::천주교 신자 직계 가족 및 조상님[묘주(계약자=후손)가 교우(신자)면 조상님은 신자(교우)여부 무관]\r\n2.묘주(계약자):::천주교 교우[[[신자[세례(영세)받은 교적이 있는 천주교 교우]]]", "traffpublic": "[버스.직행(시외)버스]\r\n\"\"\"동서울터미널(2호선 강변역)\"\"\"에서 \"\"\"도평리,사창리,와수리\"\"\" 행 시외버스(직행버스)매표소에서 \"\"\"일동터미널(포천시 일동면)\"\"\"매표 후 승차하시어 50분~1시간 소요 후 첫번째 정류장 \"\"\"일동터미널\"\"\"에서 내리시어 시내버스 의정부역 행 \"\"\"138-5번\"\"\"승차하시어 15분~20분 후 \"\"\"길명1리 평화묘원\"\"\"정류장에 내리셔서 도보로 5분~10분 문암교 다리건너 500m 직진하시어 평화묘원 관리사무소 방문하시면 더 더욱  정성을 다하여 모시도록하겠습니다.\r\n\r\n[전철.지하철]\r\n\"\"\"1호선 의정부역\"\"\" 하차 후 의정부역 광장 앞 경복대학교 스쿨버스 승강장장 옆 시내버스 정류장에서 도평리 사창리 와수리행 (138-5번) (138-7번) (138-8번)시내버스 승차하시고 1시간 30분 후 만세교 삼거리 자나서 \"\"\"길명1리 평화묘원\"\"\"버스정류장에서 내리셔서 문암교 다리 건너 도보로 5~10분 소요 후 평화묘원 정문 에 도착 하시어 관리사무소를 방문 하시면 정성껏 모시도록 하겠습니다.  ", "traffowner": "***구리~포천 고소도로*** ( 2017년 6월 30일 개통)\r\n :::신북 IC 진출 후 만세교에서 일동방향으로 우회전 후 약5km 직진 후 길명1리 평화묘원 버스정류장에서 우회전 진입\r\n***서울 태릉~포천 국도 및 지방도로***\r\n신내동, 태릉 지나서 47번 국도 김화, 일동 방향 신내 IC, 구리 IC, 퇴계원 IC, 내곡리, 진접 장현, 내촌, 베어스타운 스키장, 운악산(화현면 소재)을 지나 일동 IC 진출 후 다시 포천 방향 37번 국도로  좌회전 진입하여 길명 IC 출구로 나와 내리막 좌회전 후 포천 방향 5km 운행 후 평화묘원 간판 표석(한내레미콘.경기아스콘 철간판)에서 좌회전 후 문암교 다리 건너 500m 직진 후 묘원 주차장에 주차하시고  관리사무소 방문하시면 더 더욱  정성을 다하여 모시도록하겠습니다.", "facilities": {"mealroom": true, "supermarket": false, "parking": true, "parkingCount": 500, "waitroom": true, "handicap": true}, "lastUpdateDate": "2015/06/13", "priceitemdate": "2015/06/13"}'::jsonb, '{"hallRent": [{"item": "일반 단장형(봉안담)", "category": "개인단", "subcategory": null, "rentcontent": "1층", "facilityamt": 1800000, "facilityamtm": "1,800,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반 단장형(봉안담)", "category": "개인단", "subcategory": null, "rentcontent": "2층", "facilityamt": 1900000, "facilityamtm": "1,900,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반 단장형(봉안담)", "category": "개인단", "subcategory": null, "rentcontent": "3층", "facilityamt": 2300000, "facilityamtm": "2,300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반 단장형(봉안담)", "category": "개인단", "subcategory": null, "rentcontent": "4층", "facilityamt": 2300000, "facilityamtm": "2,300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반 단장형(봉안담)", "category": "개인단", "subcategory": null, "rentcontent": "5층", "facilityamt": 1900000, "facilityamtm": "1,900,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반 단장형(봉안담)", "category": "개인단", "subcategory": null, "rentcontent": "6층", "facilityamt": 1800000, "facilityamtm": "1,800,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반 단장형(봉안담) 관리비", "category": "개인단", "subcategory": null, "rentcontent": "일반 단장형(봉안담) 관리비 30년분", "facilityamt": 300000, "facilityamtm": "300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반 합장형(봉안담)", "category": "부부단", "subcategory": null, "rentcontent": "1층", "facilityamt": 3600000, "facilityamtm": "3,600,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반 합장형(봉안담)", "category": "부부단", "subcategory": null, "rentconten