INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001732', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "재단법인 로엠(봉안시설)", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "강연승", "companyno": "312-82-01494", "telephone": "1544-4471-", "faxnum": "041-567-0535", "homepage": "www.hurian.com", "fulladdress": "충청남도 천안시 동남구 광덕면 광덕로 383 (신덕리)", "zipcd": "31222", "latitude": "36.6844698", "longitude": "127.1429436", "sidonm": "충청남도 천안시 동남구", "orgid": "4490000", "orgidnm": "충청남도 천안시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "■ 연혁\r\n   -. 1982 재단법인 천안공원묘원 설립\r\n   -. 1983 국내 최초 선진국형 공원식 묘역 조성\r\n   -. 1992 국내 최초 가족봉안묘 개발ㆍ분양\r\n   -. 1998 국내 최초 가족 봉안묘 [피라미드정원] 개발ㆍ분양\r\n   -. 1999 국내 최초 럭셔리 벽체식 [운당] 개발ㆍ분양\r\n   -. 2008 태학지역 묘역 추가 조성\r\n   -. 2013 보건복지부 장관 표창\r\n   -. 2015 럭셔리 벽체식 모델 2차 분양\r\n   -. 2015 국내 최초 공원묘원 사생대회 개최\r\n   -. 2015 국내 최초 공원묘원 야외음악회 개최\t\t\t\r\n\r\n■ 철학\r\n   \"산자에게는 휴식을 죽은자에게는 평온을\"\r\n\r\n■ 경영방침\r\n\"기본에 충실하자\" - 모든것은 기초가 튼튼해야 건실한 결과물을 얻을 수 있다.\r\n\r\n■ 천안공원은\r\n   ☞ 대한민국 최대 규모(조성면적 30만평)\r\n   ☞ 공원묘원 최대 조경율(40%)\r\n   ☞ 차원이 다른 관리시스템(상시 관리 체제)\r\n   ☞ 재무적 안정성(무차입)\r\n\r\n재단법인 천안공원묘원은 1982년 7월 19일에 설립되어 국내 최초의 공원형 묘지를 개발하였고 다양한 봉안묘를 개발하여 국내외 특허 및 실용신안 등록을 하는 등 선진 장묘 문화를 선도해왔습니다.\r\n\r\n천안공원은 고인을 모시는 것은 따뜻한 어머니의 품에 안기듯 포근함을 주어야 한다는 설립유지를 받들어 가족이 함께 쉴 수 있는 휴양지처럼 아름답고 편안한 묘지조성에 힘쓰고 있습니다.\r\n\r\n또한 고객을 대상으로 매년 정기적인 소식지를 발간하여 천안공원의 소식과 함께 변화하는 장사문화 등 고객에게 다양한 소식들을 전하고 있습니다.\r\n\r\n리더들의 특별한 안식처가 되어온 천안공원은 현재에 만족하지 않고, 차원이 다른 안식의 격과 푸른 자연이 벗하는 명품 장묘 문화로 대한민국을 대표하는 세계 수준의 공원으로 앞장서 나갈 수 있도록 노력하겠습니다.\r\n\r\n☞ 봉안(납골)묘, 매장묘 365일 상담 가능 ☏ 1544-4471", "traffpublic": "■ 천안역ㆍ천안종합터미널에서\r\n   ▶ 버스이용시 : 약 50분 소요\r\n      -. 행정리 하차 : 700번, 701번, 710번, 711번\r\n      -. 공원 입구 하차 : 660번\r\n   ▶ 택시이용시 : 약 30분 소요\r\n\r\n■ 천안아산(KTX)역에서\r\n   ▶ 택시이용시 : 약 30분 소요", "traffowner": "■ 네비게이션 : ''천안공원묘원''으로 검색\r\n■ 남천안 IC(약 15분 소요) 또는 남풍세 IC(약 10분 소요)이용\r\n※ 주소 : 충남 천안시 동남구 광덕면 광덕로 383(신덕리)", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 1000, "waitroom": true, "handicap": false}, "lastUpdateDate": "2025/12/31", "priceitemdate": "2025/12/31"}'::jsonb, '{"hallRent": [{"item": "가족봉안묘(공작,사용료+15년관리비+시설물)", "category": "기타", "subcategory": null, "rentcontent": "33.05㎡, 봉안24기", "facilityamt": 28000000, "facilityamtm": "28,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "가족봉안묘(다솜,사용료+15년관리비+시설물)", "category": "기타", "subcategory": null, "rentcontent": "26.44㎡, 봉안20기", "facilityamt": 24200000, "facilityamtm": "24,200,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "가족봉안묘(화목S,사용료+15년관리비+시설물)", "category": "기타", "subcategory": null, "rentcontent": "14.67㎡, 봉안8기", "facilityamt": 15400000, "facilityamtm": "15,400,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [{"item": "육개장", "category": "식사", "subcategory": "-", "rentcontent": null, "facilityamt": 10000, "facilityamtm": "10,000", "sale": true, "saleNm": "판매"}, {"item": "추어탕", "category": "식사", "subcategory": "-", "rentcontent": null, "facilityamt": 10000, "facilityamtm": "10,000", "sale": true, "saleNm": "판매"}, {"item": "황태해장국", "category": "식사", "subcategory": "-", "rentcontent": null, "facilityamt": 10000, "facilityamtm": "10,000", "sale": true, "saleNm": "판매"}, {"item": "갈비탕", "category": "식사", "subcategory": "-", "rentcontent": null, "facilityamt": 10000, "facilityamtm": "10,000", "sale": true, "saleNm": "판매"}, {"item": "천막설치", "category": "기타", "subcategory": "-", "rentcontent": null, "facilityamt": 150000, "facilityamtm": "150,000", "sale": true, "saleNm": "판매"}, {"item": "봉안개봉비", "category": "기타", "