INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000003', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(재)효원가족공원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "최혁", "companyno": "124-82-13336", "telephone": "031-354-2325", "faxnum": "031-354-2327", "homepage": "www.skypark.co.kr", "fulladdress": "경기도 화성시 향남읍 서봉로755번길 17-15 (동오리)", "zipcd": "445929", "latitude": "37.1432574", "longitude": "126.95489", "sidonm": "경기도 화성시", "orgid": "5530000", "orgidnm": "경기도 화성시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "** 2002년 경기도와 보건복지부에서 재단법인 설립 허가를 받고 처음으로 영업 개시를 시작한 봉안시설\n\n** 19년 노하우의 진실된 봉안시설\n\n** 부채 없이 운영되는 찾아보기 어려운 봉안시설\n\n** 자연 친화적인 봉안시설\n\n** 서울시 7개 자치구 추모의 집(구립시설)을 운영하는 봉안시설\n    (광진,중,종로,동작,성동,성북,도봉구)\n\n**2014년 11월 (재)효원납골공원에서 (재)효원가족공원으로 상호 변경\n", "traffpublic": "1호선 천안행 병점역에서 하차 \n3번 출구 오른쪽 버스 정류장 80,67번 이용 가능\n", "traffowner": "** 서해안고속도로 이용시 출구 발안 IC 에서 10분거리\n\n**과천의왕 고속화도로 이용시 출구 정남IC 10분거리\n\n**경부고속도로 이용시 출구 향남IC 10분거리", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 200, "waitroom": false, "handicap": true}, "lastUpdateDate": "2025/12/23", "priceitemdate": "2025/12/23"}'::jsonb, '{"hallRent": [{"item": "봉안당(일반)", "category": "개인단", "subcategory": null, "rentcontent": "9단 싱글단(영구)", "facilityamt": 1000000, "facilityamtm": "1,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안당(일반)", "category": "부부단", "subcategory": null, "rentcontent": "9단 프리미엄단(영구)", "facilityamt": 2000000, "facilityamtm": "2,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안당(일반)", "category": "개인단", "subca