INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000886', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(재)분당메모리얼파크", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "이규만", "companyno": "129-82-00011", "telephone": "031-704-6508", "faxnum": "031-702-5736", "homepage": "www.bmpark.co.kr", "fulladdress": "경기도 성남시 분당구 새나리로 79 (야탑동)", "zipcd": "463816", "latitude": "37.4034231", "longitude": "127.1640127", "sidonm": "경기도 성남시 분당구", "orgid": "3780005", "orgidnm": "경기도 성남시 분당구", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "분당메모리얼파크 현황\n소재지 : 경기도 성남시 분당구 새나리로79 (야탑동 6번지) 일원\n법인명 : 재단법인 분당메모리얼파크\n공원면적 : 913,929㎡\n대표 : 이사장 이규만\n설립년도 : 1972년\n운영시간 : 9시~17시 (연중 무휴)\n\n분당메모리얼파크는 한국의 여느 추모공원과는 여러 면에서 다릅니다.\n\n한국의 추모공원이 나아가야 할 비전과 방향성을 남들보다 앞서 고민하고 제시해 왔습니다. \n고인을 모시는 곳이지만 살아있는 우리들도 편안하고 행복할 수 있는 공간으로 만들어 왔습니다.\n울창한 숲과 새소리, 개성있는 조각 작품들, 단아한 정원 같은 묘역과 독특한 묘석들, 이미 명소가 되어버린 유명인사들의 영면장소, 코 끝을 찡하게 만드는 저마다의 비문들, 이 모든 것들이 분당메모리얼파크를 다른 곳과 분명하게 차별화시키는 요소들입니다. \n지난 50여년 동안 쌓아온 신뢰 위에 가장 가치있고 품격있는 추모공원으로 거듭나기 위해 노력해 왔습니다.\n\n도심 한 가운데 위치해 있는 자연형 예술 추모공원이 여기 있습니다.\n산책하듯, 편안한 기분으로 저희 분당 메모리얼파크를 찾아주시기 바랍니다.\n\n분양상담 1566-6508 관리사무소 031-704-6508 ", "traffpublic": "분당선 야탑역 4번 출구로 나오셔서 버스 50,60번을 탄 후 종점에서 하차하지 마시고 버스 차고지에서 하차후 도보로 10분 정도 걸으시면 됩니다. 야탑역에서 택시 이용시 15분 정도 소요됩니다. ", "traffowner": "주소:경기도 성남시 분당구 야탑동 6번지(경기도 성남시 분당구 새나리로 79  (야탑동) \r\n\r\n자차이용시 성남 고속버스 터미널 야탑역 사거리에서 분당테크노파크 또는 예비군훈련장 방향으로 분당메모리얼파크 표지판을 따라 찾아 오시면 됩니다.", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 15000, "waitroom": false, "handicap": false}, "lastUpdateDate": "2025/01/04", "priceitemdate": "2025/01/04"}'::jsonb, '{"hallR