INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000953', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(재)자하연 일산(봉안)", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "최선옥", "companyno": "--", "telephone": "031-977-8351", "faxnum": null, "homepage": "www.jahayeon.com", "fulladdress": "경기도 고양시 일산동구 지영로 36-87 (지영동)", "zipcd": "10256", "latitude": "37.708061", "longitude": "126.826156", "sidonm": "경기도 고양시", "orgid": "3940000", "orgidnm": "경기도 고양시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": null, "traffpublic": "①3호선 원당역 6번출구 ->두배로 마트  -> 69번 버스 탑승 ->고봉동행정복센터 하차-> 도보 이동 자하연일산(구 국제공원) 도착\n\n②3호선 화정역 5번출구 -> 홍루이젠  -> 69번 버스 탑승 ->고봉동행정복지센터 하차-> 도보 이동 자하연일산(구 국제공원) 도착 \n\n③경의중앙선 풍산역1출구 --> 이마트 맞은 정류장 -->풍산역 승차 \"정류장 no 20753\"  -->> 87버스 승차 ---> 고봉동행정복센터 하차->\n 도보 이동 자하연일산(구 국제공원) 도착 )\n", "traffowner": "네이게이션 : 경기도 고양시 일산동구 지영로 36-87\r\n\r\n강북강변도로->자유로 장항 I.C -> 지하도 진입 후 사거리인 뉴코아백화점 사거리에서 좌회전->일산경찰서 사거리에서 경찰서를 끼고 봉일천 방면으로 우회전해서 6KM 직진 -> 성석삼거리에서 우회전 후 3.5KM 직진 -> 문봉사거리에서 좌회전 -> 첫 갈라지는 길에서 우회전 -> 자하연 일산", "facilities": {"mealroom": false, "supermarket": false, "parking": false, "parkingCount": null, "waitroom": false, "handicap": false}, "lastUpdateDate": "2025/12/19", "priceitemdate": "2025/12/19"}'::jsonb, '{"hallRent": [{"item": "사용료 요금(평당)", "category": null, "subcategory": null, "rentcontent": "2026년 1월 1일부터 시행", "facilityamt": 2500000, "facilityamtm": "2,500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관리비 요금(평당)", "category": null, "subcategory": null, "rentcontent": "2026년 1월 1일부터 시행", "facilityamt": 33000, "facilityamtm": "33,000", "sale": true, "saleNm": "판매", "avg