INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000002614', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "삼우추모공원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "행안", "companyno": "233-82-70489", "telephone": "055-730-9678", "faxnum": null, "homepage": "m.blog.naver.com/PostView.naver?blogId=jiinni1&logNo=223662143819&navType=by", "fulladdress": "경상남도 거제시 장목면 거제북로 919 (장목리)", "zipcd": "53201", "latitude": "34.980961", "longitude": "128.659673", "sidonm": "경상남도 거제시", "orgid": "5370000", "orgidnm": "경상남도 거제시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "♣ 뛰어난 교통 접근성! ♣ 공식인가 봉안당! ♣ 천혜의 명당! ♣가족 맞춤형 장례서비스 운영! ♣추모와 힐링의 공간! ♣새로운 생활권의 중심!\n● 삼우추모공원은 서부산권(사상구, 사하구, 강서구, 가덕도, 용원), 거제 전 지역, 통영권에서 접근성이 탁월합니다.\n● 장사에 관한 법률에 따라 \"거제시 제2022-1호\"로 인가된 사설 봉안당입니다.\n● 칠천도와 마주한 바닷가에 위치해 있으며, 용구름과 봉황구름이 머물다 간 신비의 장소로, 하늘의 기운을 받은 천혜의 명당입니다.\n● 삼우추모공원은 \"가족 맞춤형 장례 서비스\" 팩키지를 제공하여 봉안당 안치, 바다장 산골, 장례의식, 제사 및 추모를 한번에 진행할 수 있습니다.\n● 해양관광도시 거제시의 아름다운 자연 속에서 가족이 함께 추모하며, 화합과 힐링의 시간을 가질 수 있는 차별화된 장소입니다.\n● 가덕도신공항, 거제북부권 에어시티, 창원-거제 해저터널, 남부내륙철도 등이 연계됨에 따라, 삼우추모공원은 새로운 생활권의 중심지로 떠오를 전망입니다.", "traffpublic": "● 거제 시내버스(30, 32, 33번) -> 장목면 매동마을 하차 -> 하청면 방향 도보 3분", "traffowner": "● [서부산권(사상구, 사하구, 강서구, 가덕도, 용원)] : 거가대로 진입 -> 거가대교 -> 관포IC -> 장목 방향(우회전) -> 도착(20분 소요)\n● [거제] : 거제시청 -> 연초삼거리 좌회전 -> 장목 방향 -> 도착(15분 소요)\n● [통영] : 신거제대교 -> 고현동 -> 연초삼거리 좌회전 -> 장목 방향 -> 도착(45분 소요)", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 50, "waitroom": true, "handicap": true}, "lastUpdateDate": "2024/11/16", "priceitemdate": "2024/11/16"}'::jsonb, '{"hallRent": [{"item": "(2F) 봉안 1,3,4,5관(개인단) 1단", "category":