INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000002055', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "천주교안동교구 봉안경당", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "권혁주", "companyno": "639-82-00046", "telephone": "054-655-1781", "faxnum": null, "homepage": "안동봉안경당.com", "fulladdress": "경상북도 예천군 지보면 지풍로 983-41 (암천리, 농은수련관)", "zipcd": "36855", "latitude": null, "longitude": null, "sidonm": "경상북도 예천군", "orgid": "5230000", "orgidnm": "경상북도 예천군", "firstcharnelcnt": 20, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "영혼의 안식처 \"봉안경당\"\r\n주님, 세상을 떠난 모든 이에게 영원한 안식을 주소서\r\n천주교 안동교구에서 봉안 경당을 새로이 마련하였습니다.\r\n", "traffpublic": "안동고속버스터미널에서 276번 지보방향 → 농은수련원하차\r\n", "traffowner": "자가용을 이용하실 경우중부내륙고속도로 → 점촌함창IC → 예천읍 → 호명면 → 구담리 → 농은수련원(점촌함창톨게이트 ~ 농은수련원 :46Km)\r\n당진영덕고속도로 → 상주IC → 풍양면 → 농은수련원(상주톨게이트 ~ 농은수련원 : 37Km)\r\n중앙고속도로 → 서안동IC(네비게이션 검색 옵션에 따라 의성IC 진출 후 국도 이용으로 안내하는 경우가 있으나 반드시 서안동IC로 진출하세요) → 풍산읍 → 풍천면 → 구담리 → 농은수련원(서안동톨게이트 ~ 농은수련원:17Km)\r\n", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": null, "waitroom": true, "handicap": true}, "lastUpdateDate": "2025/01/09", "priceitemdate": "2025/01/09"}'::jsonb, '{"hallRent": [{"item": "1단(개인)", "category": "개인단", "subcategory": null, "rentcontent": "사용료:300만원/관리비: 연간 5만원(1인당)/초기 20년 관리비: 100만원/안치비:20만원", "facilityamt": 4200000, "facilityamtm": "4,200,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "1단(부부)", "category": "부부단", "subcategory": null, "rentcontent": "사용료:500만원/관리비: 연간 5만원(1인당)/초기 20년 관리비: 100만원/안치비:20만원", "facilityamt": 6200000, "facilityamtm": "6,200,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avg