INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000033', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "추모공원 하늘문", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "송춘식", "companyno": "128-92-14700", "telephone": "031-962-7579", "faxnum": "031-964-1691", "homepage": "www.hi1009.com", "fulladdress": "경기도 고양시 덕양구 보광로106번길 46 (벽제동)", "zipcd": "412510", "latitude": "37.7245643", "longitude": "126.9095315", "sidonm": "경기도 고양시 덕양구", "orgid": "3940000", "orgidnm": "경기도 고양시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": null, "traffpublic": "지하철 3호천 삼송역 6번 출구에서 마을버스 033, 053 탑승 → 고양동시장 정류장에서 85, 850, 790, 313, 313-1 버스로 환승 → 추모공원하늘문 정류장 하차", "traffowner": "강서구, 인천, 부천 등에서 오실때\r\n외곽순환도로 통일로IC → 벽제 화장터 앞에서 의정부, 장흥 방면으로 우회전 후 4.5km 직진 → 풍림 APT앞 → 삼거리에서 좌회전 후 600m\r\n → 대명 교회 삼거리에서 우회전 후 300m → 벽제삼거리에서 보광사 방면으로 우회전 후 1km 우측\r\n\r\n\r\n\r\n\r\n의정부, 노원, 강북구 등에서 오실때\r\n외곽순환도로 송추IC → 송추 삼거리에서 고양, 인천 방면으로 좌회전 후 6.45km직진 → 풍림 APT앞 삼거리에서 우회전 후 600m\r\n→ 대명 교회 삼거리에서 우회전 후 300m → 벽제삼거리에서 보광사 방면으로 우회전 후 1km 우측", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 100, "waitroom": true, "handicap": true}, "lastUpdateDate": "2026/01/28", "priceitemdate": "2026/01/28"}'::jsonb, '{"hallRent": [{"item": "믿음관 일반실(개인단)", "category": "개인단", "subcategory": null, "rentcontent": "사용료:200만원~800만원/ 관리비:5년 35만원", "facilityamt": 2000000, "facilityamtm": "2,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "믿음관 일반실(부부단)", "category": "부부단", "subcategory": null, "rentcontent": "사용료:400만원~1600만원/ 관리비:5년 70만원", "facilityamt": 4000000, "facilityamtm": "4,000,000", "sale": true