INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000102', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "예원추모관", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "임용구", "companyno": "128-82-09682", "telephone": "1544-4054", "faxnum": null, "homepage": "www.e-yewon.co.kr", "fulladdress": "경기도 고양시 덕양구 통일로 502-1 (대자동)", "zipcd": "412480", "latitude": "37.6778557", "longitude": "126.8878093", "sidonm": "경기도 고양시 덕양구", "orgid": "3940001", "orgidnm": "경기도 고양시 덕양구", "firstcharnelcnt": 99, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "저희 예원추모관은 (재)대자원에서 직영하는, 안정성 높은 고품격 추모공원입니다.\r\n편리한 교통으로 언제든지 고인을 추모하러 오실 수 있으며,\r\n추모관 외부에는 산책과 휴식이 가능한 예원동산 공원을 갖추고 있습니다. ", "traffpublic": "- 3호선 삼송역 하차 8번 출입구 마을버스 항상 대기(25,37,53 번 노란버스)\r\n- 그 외 버스 노선\r\n  : 서울버스 (703. 760, 800)\r\n  : 경기버스 (05,17,30,31,55,99,100,330,333, 850)\r\n  : 광역버스 (9709, 9710)\r\n  : 공항버스 (3700)\r\n- 승차후 서울시립 승화원 정류장 하차 -> 도보로 50 M 이동 -> 도착\r\n\r\n※ 자세한 사항은 홈페이지를 참조바랍니다.", "traffowner": "서울 외곽순환도로 통일로I/C 로 나오셔서, 서울시립 승화원으로 우회전 하시면 초입에 위치.\r\n서울,경기,인천 등지에서 대부분 1시간 이내에 진입 가능\r\n주차장은 서울 시립 승화원 주차장 이용하시면 됩니다. (A,B,C 구역)", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": null, "waitroom": true, "handicap": true}, "lastUpdateDate": "2026/02/07", "priceitemdate": "2026/02/07"}'::jsonb, '{"hallRent": [{"item": "일반실(목련)", "category": "개인단", "subcategory": null, "rentcontent": "사용료:160만원~400만원 관리비:5년 36만원", "facilityamt": 1600000, "facilityamtm": "1,600,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반실(목련)", "category": "부부단", "subcategory": null, "rentcontent": "사용료:320만원~750만원 관리비:5년 72만원", "facilityamt": 3200000