INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000028', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "남한강공원묘원(봉안)", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "(재)한국문화협회", "companyno": "126-82-00332", "telephone": "031-882-6689", "faxnum": null, "homepage": "www.nhg.co.kr ", "fulladdress": "경기도 여주시 가남읍 송삼로 459-35 (금곡리)", "zipcd": "12660", "latitude": null, "longitude": null, "sidonm": "경기도 여주시", "orgid": "4110000", "orgidnm": "경기도 여주시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "\r\n1975년에 개원하여 40여년이상 지나는 동안  남한강공원묘원은 단 한번도 수해,풍해,설해등의 기상재해가 없었습니다. 이는 하늘이 보살피고, 땅의 기운이 살아숨쉬고, 사람이 정성으로 관리하며  또한 이곳에 모셔진 영혼들이 돌봐주신 음덕으로 이루어진 역사라 할 수 있습니다.   \r\n\r\n이중환의 \"택리지\" (1750년)에 실린 글 중에 사대부가 살만한 곳으로 여주를 손 꼽았습니다. 북에서 내려오는 오대산 지맥과 남에서 올라오는 속리산 지맥이 만나서 구릉지를 이루고 두 산 사이에  만난 웅장하거나 급하지않은 강이 흐르는  산의 기는 그 마지막 자리가 가장 강해 풍수지리에서도 이런곳을 명당으로 손 꼽는답니다.  \r\n\r\n하늘과 땅과 사람이 하나가 되는 이곳, 남한강공원묘원 입니다.\r\n\r\n\r\n남한강공원묘원 관리사무소 : 031 882 6688      ", "traffpublic": "버스 : 서울(강남고속버스터미널,동서울터미털)>여주행고속버스이용,여주하차> 점동면 경유  태평리행 버스 승차>금당삼거리 하차 >죄회전 0.5Km 지점", "traffowner": "고속도로: 서울>영동고속도록 여주IC>좌회원 장호원방향으로 5.3Km 지점  점동사거리>우회전 가남면 태평리방향 3.6 Km지점 금당삼거리 하차> 좌회전 0.5Km 지점 ", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 500, "waitroom": false, "handicap": false}, "lastUpdateDate": "2026/01/21", "priceitemdate": "2026/01/21"}'::jsonb, '{"hallRent": [{"item": "사용료", "category": null, "subcategory": null, "rentcontent": "3.3 m2", "facilityamt": 1577000, "facilityamtm": "1,577,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관리비", "category": null, "subcategory": null, "rentconte