INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001369', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "천주교용인공원묘원(봉안)", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "염수정", "companyno": "201-82-00972", "telephone": "031-334-0807", "faxnum": "031-334-0854", "homepage": "yi.catholic.or.kr", "fulladdress": "경기도 용인시 처인구 모현면 오산로 154-62 (오산리, 천주교공원묘지)", "zipcd": "16885", "latitude": "37.322328", "longitude": "127.146474", "sidonm": "경기도 용인시 처인구", "orgid": "4050001", "orgidnm": "경기도 용인시 처인구", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "천주교 서울대교구에서 운영하는 천주교 봉안시설입니다.\r\n\r\n[환불규정]\r\n제7조(사용봉헌금 및 관리비 환불)\r\n  1. 봉안시설 계약 이후 이장 등의 사유로 계약 해지 시 사용봉헌금은 아래와 같이 환불한다.\r\n     관리비는 사용년수를 제외하고 환불한다.\r\n      [ 1년이내 50% / 2년이내 40% / 3년이내 30% / 4년이내 20% / 5년이내 10% / 5년초과 0% ]\r\n  2. 사용봉헌금 및 관리비를 납부한 후 유골을 안치하지 않은 상태에서 30일 이내에 계약해지하는 경우 납부한 사용봉헌금 및 관리비 전액을 환불한다.\r\n  3. 사용봉헌금 및 관리비를 납부한 후 유골을 안치하지 않은 상태에서 30일 이후에 계약해지하는 경우 납부한 사용봉헌금 10%와 해당 년도 관리비를 공제하고 환불한다.", "traffpublic": "지하철 분당선 죽전역 하차 후 택시 이용\r\n지하철 분당선 보정역 하차 후 마을버스 57번 (천주교공원묘지 정류장)\r\n지하철 분당선 오리역 하차 후 60번 광주행 버스\r\n수원역 60번,660번 광주행 버스 이용 (오산리천주교묘지 하차)", "traffowner": "포은대로(1.8km)  → 대지로(1.6km)  → 오산로(2.4km)", "facilities": {"mealroom": true, "supermarket": false, "parking": true, "parkingCount": 300, "waitroom": true, "handicap": true}, "lastUpdateDate": "2018/09/18", "priceitemdate": "2018/09/18"}'::jsonb, '{"hallRent": [{"item": "봉안담 개인형(1단)", "category": "개인단", "subcategory": null, "rentcontent": "10년관리비 포함", "facilityamt": 1600000, "facilityamtm": "1,600,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안담 개인형(2,6,7단)", "cate