INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000116', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "은하수공원 달님의집(봉안당)", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "조소연", "companyno": "306-82-08788", "telephone": "044-850-1340", "faxnum": "044-863-0764", "homepage": "www.sjfmc.or.kr/eunhasu.do", "fulladdress": "세종특별자치시 정안세종로 1527 (산울동, 은하수공원)", "zipcd": "30090", "latitude": "36.5321562", "longitude": "127.245131", "sidonm": "세종특별자치시", "orgid": "5690000", "orgidnm": "세종특별자치시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 1, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "● 365일 고객과 함께하는 품격있는 공설장사시설 은하수공원입니다.\r\n● 장례에서부터 안장까지 최상의 서비스를 제공하겠습니다. \r\n\r\n상담 및 문의) 1599-4411\r\n\r\n[이용조건]\r\n- 제한없이 이용가능\r\n- 단, 거주지에 따라 이용료 차등\r\n\r\n[전액 감면대상]\r\n- 국가유공자로서 6개월 이상 주민등록자 \r\n- 관내 기초생활수급자\r\n- 관내 무의탁 사회복지시설 수용자\r\n- 관내 행려사망자 등 무연고자\r\n- 시장이 특별히 인정하는 자\r\n\r\n[반액 감면대상]\r\n- 국가유공자 중 전액 감면대상에 해당되지 않은 자", "traffpublic": "● 조치원역에서 16번 마을 버스 운행\r\n[주요노선] 조치원역 ↔ 연기리 ↔ 수산리 ↔ 은하수공원\r\n● 대전 반석역에서 1005번 광역 버스 운행\r\n[주요노선] 반석역 ↔ 한솔동 ↔ 고운동 ↔ 은하수공원", "traffowner": "● 조치원방향에서 진입 시 \r\n국도 1호 ⇒ 국도 1호 우회도로 진입 ⇒ 빗돌터널 ⇒ 정안ic방향 우회전(하부도로 진입) \r\n⇒ 하부도로에서 우회전 ⇒ 은하수공원    \r\n● 대전방향에서 진입 시 \r\n대전유성도로(천안,조치원방향) ⇒ 대평교차로 ⇒ 국도 1호 우회도로 진입을 위한 우회전 \r\n⇒ 학나래교 ⇒ 방음판터널 ⇒ 사오리지하차도 ⇒ 주추지하차도 ⇒ 정안ic방향 우회전(하부도로 진입)\r\n⇒ 하부도로에서 좌회전 ⇒ 은하수공원  \r\n● 서울 ⇒ 경부고속도로 ⇒ 천안논산고속도로⇒ 정안ic ⇒ 은하수공원  \r\n● 청주 ⇒ 조치원 ⇒ 국도1호 ⇒ 은하수공원 은하수공원  \r\n● 논산·부여 ⇒ 국도1호 ⇒ 은하수공원  \r\n● 공주 ⇒ 국도36호 ⇒ 국도1호 ⇒ 은하수공원  \r\n● 서산·당진 ⇒ 당진상주고속도로 ⇒ 서세종ic ⇒ 국도36호 ⇒ 국도1호 ⇒ 은하수공원 ", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 20, "waitroom": true, "handicap": true}, "lastUpdateDate": "2024/11/01", "price