INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001349', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "별그리다(THE WALL)", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "박기오", "companyno": "132-82-64762", "telephone": "031-333-1111", "faxnum": "031-774-4710", "homepage": "www.star4ever.com", "fulladdress": "경기도 양평군 양동면 양동금곡1길 331 (삼산리)", "zipcd": "12540", "latitude": null, "longitude": null, "sidonm": "경기도 양평군", "orgid": "4170000", "orgidnm": "경기도 양평군", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "언제나 그랬듯 거기 그렇게 그자리에...\r\n따뜻하고 든든한 그 어깨에 기대듯 눈 맞춰 이야기 나누듯 아름다운 추억과 마주합니다.\r\n\r\n별그리다_더월과 더힐에는 봉안담(납골담)과 봉안묘(납골묘)에 영구적으로 안치하실 수 있으며,\r\n개인형,부부형,가족형등 여러형태로 선택이 가능하십니다.", "traffpublic": "기차이용시\r\n- 중앙선 : 청량리역 → 양동역,삼산역,매곡역 → 택시이용 → 별그리다\r\n고속버스이용시\r\n- 영동선 : 강남고속버스터미널 → 문막하차(원주행) → 택시이용 → 별그리다", "traffowner": "고속도로(동양평IC)이용시 ※2016년 하반기 예정\r\n- 동양평IC 나와 우회전 → 양동농협주유소 우회전 → 삼산역방향 좌회전 → 별그리다 진입로\r\n고속도로(문막IC)이용시\r\n- 문막IC 나와 우회전 → 동화의료기기단지 방면 좌회전 → 안창대교 건너 좌회전 → 양동방향 직진 → 삼산역방향 좌회전 → 별그리다 진입로\r\n국도이용시\r\n- 6번국도를 따라 용문방향으로 → 과적검문소 지나 우회전(양동방면 345번 도로) → 금왕삼거리 우회전 → 여주방향 우회전 → 양동농협주유소 로타리 좌회전 → 삼산역방향 좌회전 → 별그리다 진입로", "facilities": {"mealroom": true, "supermarket": false, "parking": true, "parkingCount": 1300, "waitroom": true, "handicap": true}, "lastUpdateDate": "2025/02/06", "priceitemdate": "2025/02/06"}'::jsonb, '{"hallRent": [{"item": "개인단", "category": "개인단", "subcategory": null, "rentcontent": "개인형(1단~5단으로 구성, 상세금액 문의)", "facilityamt": 2650000, "facilityamtm": "2,650,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "부부단", "category": "부부단", "subcategory": null, "rentcontent": "부