filesize": 3185425}]'::jsonb, '[{"facilitycd": "2000000216", "facilitygroupcd": "TBC0700002", "companyname": "(재)삼성개발공원묘원 엘리시움", "type": "CemeteryDet", "fulladdress": "경기도 광주시 오포로 211-50 (능평동)", "telephone": "031-766-4260", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1465957049538_2000000216_0.png"}, {"facilitycd": "7000000883", "facilitygroupcd": "TBC0700003", "companyname": "삼성개발공원묘원(봉안)", "type": "CharnelDet", "fulladdress": "경기도 광주시 오포로 211-50 (능평동)", "telephone": "031-766-4260", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1468983596917_7000000883_0.JPG"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001618', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(주)청아공원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "김영복", "companyno": "128-81-48994", "telephone": "031-977-9911", "faxnum": null, "homepage": "chungahpark.co.kr", "fulladdress": "경기도 고양시 일산동구 은마길 129 (설문동, 청아공원)", "zipcd": "10252", "latitude": "37.7190308", "longitude": "126.8057226", "sidonm": "경기도 고양시 일산동구", "orgid": "3940000", "orgidnm": "경기도 고양시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "유가족 여러분 안녕하십니까. 대한민국대표납골당 청아공원입니다.\r\n\r\n1999년 허가취득과 함께 건립을 시작한 청아공원은 그동안 우리나라에 뿌리깊게 자리잡아온 매장위주의 장묘문화를 극복하고 화장과 납골이라는 새로운 대안을 제시한 대한민국대표납골당입니다.\r\n\r\n다양하고 세련된 청아공원 내ㆍ외부 시설과 항상 최적화된 상태를 유지할 수 있는 대규모 중앙공조시스템, 그리고 유족들께서 늘 가깝게 추모하실 수있는 위치등 청아공원이 갖추고있는 조건이 유가족들로 하여금 거부감없이 화장이라는 장례문화를 선택하실 수있도록 만들었다는 자부심을 가지고 있습니다.\r\n\r\n청아공원이 걸어오는 동안 많은 분들께서 격려와 함께 따끔한 충고를 아끼지 않으셨고, 그것을 거름삼아 대한민국대표납골당으로 자리매김하였습니다.\r\n\r\n이에 멈추지않고 유가족들께 좀 더 따뜻하고 아름다운 공간으로 다가설 수있도록 더욱 열심히 하겠습니다. 청아공원을 찾아주시는 한분 한분께 진심으로 감사드립니다.\r\n\r\n정성을 다하겠습니다. 부디 건강하시기 바랍니다.\r\n", "traffpublic": "▶ 유가족 셔틀버스 운행(1년 365일 운행)\r\n    정발산역(4번출구) ↔ 청아공원\r\n\r\n▶ 마을버스 60번\r\n    일산역 ↔ 청아공원\r\n\r\n\r\n\r\n", "traffowner": "[자유로에서 오시는길]\r\n▶ 강북강변도로 > 자유로 > 장항IC 진출 ▶ 장항IC > 지하차도 통과후 뉴코아백화점 사거리에서 좌회전 ▶ 일산경찰서 사거리에서 봉일천 방면으로 우회전해서 약 5.5km 직진 ▶ 성석삼거리에서 고양시청 방면으로 우회전해서 약 2km 직진 ▶ 청아공원 간판이 보이는 마골오거리에서 좌회전 신호를 받고 8시 방향으로 좌회전 > 약 1km > 청아공원 도착\r\n\r\n[금촌에서 오시는길]\r\n▶ 금촌에서 통일로를 타고 서울, 봉일천 방향으로 진행 ▶ 봉일천 사거리에서 일산방향으로 우회전해서 약 2km 직진 ▶ SK주유소 지나자마자 청아공원 간판이 보이는 신호에서 좌회전 > 약 1km > 청아공원 도착\r\n\r\n[벽제(통일로)에서 오시는길]\r\n▶ 벽제승화원에서 통일로를 타고 파주, 문산 방향으로 진행 ▶ 고양외국어고등학교 지나 관산삼거리(벽제교)에서 일산, 고봉동 방향으로 좌회전 > 약 5km 직진 ▶ 문봉사거리 지난 후 청아공원 간판이 보이는 마골오거리에서 우회전 > 약 1km > 청아공원 도착\r\n\r\n[의정부에서 오시는길]\r\n▶ 의정부에서 송추방면으로 진행 ▶ 송추지나 원당방향 고가가 나오면 고가 아랫길로 진입한 뒤 우회전 > 통일로 진입 ▶ 벽제에서 오시는 길과 동일\r\n\r\n\r\n\r\n", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 2000, "waitroom": true, "handicap": true}, "lastUpdateDate": "2022/05/19", "priceitemdate": "2022/05/19"}'::jsonb, '{"hallRent": [{"item": "매화홀, 하늘홀, 믿음홀, 청아홀(개인)", "category": "개인단", "subcategory": null, "rentcontent": "550만원 ~ 2,500만원", "facilityamt": 5500000, "facilityamtm": "5,500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "매화홀, 하늘홀, 믿음홀, 청아홀(부부)", "category": "부부단", "subcategory": null, "rentcontent": "1,100만원 ~ 5,000만원", "facilityamt": 11000000, "facilityamtm": "11,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "난초홀, 평화홀, 승리홀(개인)", "category": "개인단", "subcategory": null, "rentcontent": "340만원 ~ 1,500만원", "facilityamt": 3400000, "facilityamtm": "3,400,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "난초홀, 평화홀, 승리홀(부부)", "category": "부부단", "subcategory": null, "rentcontent": "680만원 ~ 3,000만원", "facilityamt": 6800000, "facilityamtm": "6,800,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "국화홀, 대지홀, 은혜홀(개인)", "category": "개인단", "subcategory": null, "rentcontent": "340만원 ~ 1,500만원", "facilityamt": 3400000, "facilityamtm": "3,400,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "국화홀, 대지홀, 은혜홀(부부)", "category": "부부단", "subcategory": null, "rentcontent": "680만원 ~ 3,000만원", "facilityamt": 6800000, "facilityamtm": "6,800,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "중앙홀, 자유홀, 소망홀(개인)", "category": "개인단", "subcategory": null, "rentcontent": "340만원 ~ 1,500만원", "facilityamt": 3400000, "facilityamtm": "3,400,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"it