INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001422', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "흥륜사정토원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "정재준", "companyno": "131-82-02652", "telephone": "032-834-1131", "faxnum": null, "homepage": "www.jungtowon.co.kr", "fulladdress": "인천광역시 연수구 청량로70번길 40-18,흥륜사 정토원 (동춘동)", "zipcd": "21943", "latitude": "37.416408", "longitude": "126.659341", "sidonm": "인천광역시 연수구", "orgid": "3520000", "orgidnm": "인천광역시 연수구", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": null, "traffpublic": "버스\r\n740(마을),8,16,6-A/B,111-2,9000(광역),9008(급행)->송도 유원지 하차\r\n\r\n전철\r\n인천지하철 동춘역 하차 4번 출구 740번 마을버스 이용\r\n동막역 하차 1번 출구에서 8번,908번.6-1B 버스 이용 -> 송도유원지하차\r\n\r\n셔틀버스\r\n송도유원지 -> 흥륜사(오전10시 1차례운행)", "traffowner": "제1경인고속도로 이용시\r\n인천방면 고속도로 끝 사거리 교차로에서 좌회전->송도유원지 방면 직진 -> 송도로타리에서 인천상륙작전기념관 방향 직진 -> 삼거리에서 우회전 -> 다하누 앞에서 좌회전", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": null, "waitroom": true, "handicap": true}, "lastUpdateDate": "2017/10/18", "priceitemdate": "2017/10/18"}'::jsonb, '{"hallRent": [{"item": "연화실", "category": "개인단", "subcategory": null, "rentcontent": "1단~8단 (100만원~600만원) / 1위 1년 관리비 5만원", "facilityamt": 0, "facilityamtm": "0", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "연화실", "category": "부부단", "subcategory": null, "rentcontent": "1단~8단 (200만원~1100만원) / 1위 1년 관리비 5만원", "facilityamt": 0, "facilityamtm": "0", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "연화 특별실", "category": "개인단", "subcategory": null, "rentcontent": "1단~6단 (500만원~1200만원) / 1위 1년 관리비 5만원", "facilit