INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001642', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "서대산추모공원 봉안당", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "윤창호", "companyno": "305-82-61359", "telephone": "041-754-5108", "faxnum": "041-754-4108", "homepage": "www.서대산추모공원.com", "fulladdress": "충청남도 금산군 추부면 서대동기길 100 (서대리)", "zipcd": "32710", "latitude": "36.2175073", "longitude": "127.5280496", "sidonm": "충청남도 금산군", "orgid": "4550000", "orgidnm": "충청남도 금산군", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "1.종교단체봉안당( 한국불교태고종 일불사 대표자 윤창호) \r\n2. 2018.5.28 대표자변경신필 (금산군수)\r\n3.설치허가기수 114,032구 (불교관,기독교관,일반관,무연고관)\r\n3. 충청의 수산 서대산 중턱의 명당터, 대전역에서 승용차 30분, 전국 2시간 접근성 양호 \r\n4. 식당이용가능 : 단체주문시 식사도 가능( 5,000원)\r\n5. 카페 운영\r\n3. 유가족쉼터 운영\r\n\r\n ", "traffpublic": "*시내버스 : 대전에서 501번 -> 마전하차 -> 택시이용\r\n*고속버스 : 대전복합터미널 -> 시외버스터미널(금산) -> 마전하차 -> 택시이용\r\n                                    -> 시내버스 501번 -> 마전하차 -> 택시이용\r\n*기차 : 대전역 -> 시내버스 501번 -> 마전하차 -> 택시이용", "traffowner": "*산내운전면허시험장경유 ->금산방향 -> 금산터널이후 요광리,마전 -> 옥천방향 -> 신평리 -> 신평삼거리에서 군북방향 -> 돼지마당에서 10시방향\r\n*남대전 ic -> 금산방향 ->금산터널이후 요광리,마전 -> 옥천방향 -> 신평리 -> 신평삼거리에서 군북방향 -> 돼지마당에서 10시방향\r\n", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 500, "waitroom": true, "handicap": true}, "lastUpdateDate": "2019/07/22", "priceitemdate": "2019/07/22"}'::jsonb, '{"hallRent": [{"item": "봉안시설", "category": "개인단", "subcategory": null, "rentcontent": "1단. 9단", "facilityamt": 3000000, "facilityamtm": "3,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안시설", "category": "개인단", "subcategory": null, "ren