INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000693', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(재)여주세종추모공원 봉안당", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "신 삼 용", "companyno": "117-82-78103", "telephone": "031-634-4960", "faxnum": null, "homepage": "www.세종공원.co.kr", "fulladdress": "경기도 여주시 흥천면 샘다리길 105 (흥천면  상대리  27-6) ", "zipcd": "12605", "latitude": "37.3511116", "longitude": "127.5114478", "sidonm": "경기도 여주시", "orgid": "4110000", "orgidnm": "경기도 여주시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "재단법인 여주 세종 추모공원은 먼저 가신 이들에 대한 최고의 예우를 다하고 풍수 지리학적으로 최고의 위치이며 \n (조선 제4대왕 세종대왕릉이(사적 제195호)있는곳)사통팔달의 교통망으로후손들이  내집처럼 언제나 편안하게 찾을수 있는 곳으로 하나의 공원(납골당 수목장 자연장 가족납골공원)으로 조성하여 휴식처로 만들어  e-편한 추모공원으로 만들어 갈것을 약속합니다.   \ne=편한 추모공원:  저렴한 사용료. 편리한 교통.풍수지리학적 편안한 안식처.고품격 인테리어  오동나무 안치단. ", "traffpublic": "이천 터미널출발 버스 이천시내 버스      경강전철  세종대왕역에서 택시 10분   신둔역 택시10분           \n23-4 문장삼거리 하차 도보5분\n23-5복대리 입구하차 도보3분\n23-6상대리마을하차 도보5분\n23-7상대리 마을하차 도보5분\n965 시내버스 여주터미널에서출발  복대리이구 하차 961-1시내버스  복대리입구 하차 961-4  복대리입구하차\n여주터미널 출발 흥천면방향 모든버스\n이천 양평간 노선버스 문장삼거리 하차 ", "traffowner": "서울에서 출발시 30분 소요 중부고속도로 제2영동고속도로 흥천.이포I.C 진출 이천 흥천방향  문장초등학교앞좌회전200미터\n88 올림픽대로에서 서울춘천간 고속도로 양평에서  중부내륙고속도로진입  북여주I.C에서진출 이천.흥천방면으로 좌회전 문장삼거리에사3분  서울에서 제2영동고속도로  흥천.이포I.C 에서3분\n양평에서 출발시\n 중부내륙고속도로 북여주I.C에서흥천방향 좌회전  문장사거라 좌회전 세종추모공원\n\n성남에서 출발시\n성남장호원간 자동차 전용도로 광주에서 제2영동고속도로 흥천I,C 좌회전 3분  문장사거리에서 우회전\n\n광주에서 출발시\n성남장호원간 자동차전용도로 이천I.C에서 이포방향 문장사거리 우회전 세종추모원\n이천에서 출발시\n이포대교 양평방향 문장사거리에서 우회전 3분\n\n", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 200, "waitroom": true, "handicap": true}, "lastUpdateDate":