INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000567', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(재)서현추모공원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "정광식", "companyno": "141-82-00364", "telephone": "031-947-4114", "faxnum": null, "homepage": "seohyunpark.com/", "fulladdress": "경기도 파주시 광탄면 명봉산로 277 (용미리)", "zipcd": "10955", "latitude": "37.7470322", "longitude": "126.8573649", "sidonm": "경기도 파주시", "orgid": "4060000", "orgidnm": "경기도 파주시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "안녕하세요 재단법인 서현공원입니다.\r\n\r\n저희 서현재단은 2012년 서울 강북권 최초 및 유일한 경기도지사 허가를 득한 재단법인 추모공원으로서\r\n\r\n종교에 관계없이 총 35,000위를 모실 수 있는 고품격 호텔식 봉안당(납골당)입니다.\r\n\r\n\r\n재단법인 서현공원으로 여러분을 초대합니다.\r\n\r\n1. 아름다운 주변경관과 조경 및 대형야외폭포\r\n\r\n2. 종교별 전용실 운영(기독교 8개실, 천주교 3개실)\r\n\r\n3. 전용 예배실운영(동시100명 착석가능)\r\n\r\n4. 전용 제례실운영(동,서관 총 8개실 운영)\r\n\r\n5. 대형주차시설(동시 200대까지 수용)\r\n\r\n6. 무료셔틀버스운행(운영시간내 수시로 운행)\r\n\r\n7. 사이버추모관 운영(먼 지방이나 해외거주 가족분들이 온라인상 추모할 수 있는 서비스)\r\n\r\n8. 제사음식 주문서비스 제공(삼우재, 49재, 기제사등 활용), 무료제기 제공\r\n\r\n9. 철저한 보안시스템 공원내 100개대의 CCTV관리\r\n\r\n그 외에도 항상 유가족분들이 불편함이 없도록 시설 및 편의시설확충 관리등\r\n그 변화는 아직도 현재진행형인 추모시설입니다.\r\n\r\n감사합니다.\r\n재단법인 서현", "traffpublic": "서울방면 : 9709, 9710, 799, 30, 31, 17, 775, 774번\r\n금촌문산방면 : 38,064,799,17,9709,775,9710번\r\n지하철이용 : 삼송역하차 774,775,17, 31, 30, 99번", "traffowner": "고양과 파주경계지역 위치하여 용미리시립묘지 400구역 맞은편입니다.", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 200, "waitroom": true, "handicap": true}, "lastUpdateDate": "2022/05/03", "priceitemdate": "2022/05/03"}'::jsonb, '{"hallRent": [{"item": "봉안당(일반개인 1단~9단)", "category": "개인단", "subcategory": null, "rentcontent": 