full": "https://15774129.go.kr/BCUser/facilitypic/1642055020245.jpg", "filesize": 594856}, {"fileorder": 4, "filetitle": null, "filename": "KakaoTalk_20220113_150549707_01.jpg", "fileurl": "/BCUser/facilitypic/1642055088630.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1642055088630.jpg", "filesize": 397613}, {"fileorder": 5, "filetitle": null, "filename": "KakaoTalk_20220113_150549707_03.jpg", "fileurl": "/BCUser/facilitypic/1642063596302.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1642063596302.jpg", "filesize": 591141}]'::jsonb, '[{"facilitycd": "7000002597", "facilitygroupcd": "TBC0700003", "companyname": "월봉사연화원", "type": "CharnelDet", "fulladdress": "경기도 이천시 호법면 덕평로497번길 260 (매곡리)", "telephone": "031-638-6796", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1642055069361.jpg"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000002400', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(재)용인공원(아너스톤)", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "김동균", "companyno": "208-82-00992", "telephone": "031-334-3484", "faxnum": null, "homepage": "www.yongin-park.com", "fulladdress": "경기도 용인시 처인구 모현읍 새래로 158-33 (초부리, 용인공원묘지)", "zipcd": "17037", "latitude": "37.29884", "longitude": "127.25447", "sidonm": "경기도 용인시 처인구", "orgid": "4050001", "orgidnm": "경기도 용인시 처인구", "firstcharnelcnt": 5, "renewyears": 99, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[역  사]\r\n조선독립운동가 도산 안창호 선생의 추모사업회 ‘흥사단’에서 출발하였습니다.\r\n설립 이후 현재까지 150만m2 의 장묘 터전에 \r\n무차입 경영을 통해 지난 40년간 안정적으로 운영해 왔습니다. \r\n\r\n본 재단은 2대 김창원 회장(창업주)의 ‘自力經營精神’과 체계적인 공원묘원 운영으로 \r\n재단을 한도약 성장시켰고,지난 35년간 무차입 경영으로 안정적인 재단 운영을 하고 있습니다.\r\n전통적인 매장묘, 격조 높은 봉안묘와 더불어 고품격 봉안담, 다양한 수목장에 이르기까지 \r\n다양한 장묘법을 구현해 왔습니다. \r\n재단법인 용인공원은 정직한 경영과 끊임없이 노력하는 자세로 \r\n한국의 장묘 문화 발전을 선도해 나가겠습니다. \r\n\r\n[연  혁]\r\n1975.6. 재단법인 용인공원 설립\r\n1975.6.21. 洪碩雄 1대 이사장 취임\r\n1975.9. 1차 사설묘지 허가\r\n1976.6. 2차 사설묘지 허가\r\n1979.8. 3차 사설묘지 허가\r\n1981.9. 金昌原 2대 이사장 취임\r\n1987.1. 4차 사설묘지 허가\r\n1991.3. 5차 사설묘지 허가\r\n2002.7. 공원 관리소 신축 및 재단본부 통합\r\n2005.9 가족봉안묘 설치 판매개시\r\n2006.7. 金東均 3대 (현)이사장 취임\r\n2009.10 조직 확대개편, 마케팅본부, 건설본부 신설\r\n2010.3. 기업 new-brand B.I. 변경(KOREAN TRADITIONAL PREMIUM컨셉)\r\n2010.5 고품격 가족묘 \"정명지\"오픈\r\n2010.8 친환경 봉안담 \"하늘담재\"오픈\r\n2011.3 신개념 매장묘 \"정남지\"오픈\r\n2013.1 수목장의 새로운 기준 \"세수연\" 오픈\r\n2014.1 국내최초 묘역찾기 서비스 개시(GPS연동 용인공원 어플리케이션 출시)\r\n\r\n[공원의 특징]\r\n대한민국 공원묘원 최대 녹지비율\r\n대한민국 공원묘원 최대 규모(165만m2)\r\n서울 수도권에서 30분 거리의 대한민국 명당지\r\n기존 조성 묘역 ; 2만5천기 묘소\r\n\r\n홈페이지 : www.용인공원.com\r\n임직원수 : 김동균 이사장외 52명", "traffpublic": "사당역 출발 1500-2번 --> 용인공원 정류장 하차\r\n강변역 출발 1113번 --> 용인공원 정류장 하차\r\n셔틀버스 이용 -용인공원 홈페이지 참조", "traffowner": "<고속도로 이용>\r\n영동고속도로 용인 IC - 45번국도(광주방향)-용인공원 약 6KM\r\n중부고속도로 경안 IC(광고IC) - 45번국도 (용인방향)-용인공원 (약 18KM)\r\n<국도이용>\r\n서울 --> 분당 - 57번지방도록 -43번국도 -외국어대앞 사거리 - 45번국도(용인방면)-용인공원 약 5KM", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 2000, "waitroom": true, "handicap": false}, "lastUpdateDate": "2023/04/17", "priceitemdate": "2023/04/17"}'::jsonb, '{"hallRent": [{"item": "일반 봉안당", "category": "개인단", "subcategory": null, "rentcontent": "노블관 8단 센터 기준", "facilityamt": 22000000, "facilityamtm": "22,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "특별 봉안당", "category": "개인단", "subcategory": null, "rentcontent": "로얄관 5단 상단 기준", "facilityamt": 40000000, "facilityamtm": "40,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반(아너관/노블관) 관리비", "category": "개인단", "subcategory": null, "rentcontent": "개인단 1년 단가", "facilityamt": 110000, "facilityamtm": "110,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반(아너관/노블관) 관리비", "category": "부부단", "subcategory": null, "rentcontent": "부부단 1년 단가(고인2인 기준)", "facilityamt": 220000, "facilityamtm": "220,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "특별(로얄관) 관리비", "category": "개인단", "subcategory": null, "rentcontent": "개인단 1년 단가", "facilityamt": 150000, "facilityamtm": "150,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "특별(로얄관) 관리비", "category": "부부단", "subcategory": null, "rentcontent": "부부단 1년 단가(고인2인 기준)", "facilityamt": 300000, "facilityamtm": "300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료 환불 규정(약정일기준)", "category": "기타", "subcategory": null, "rentcontent": "15일 이내 해지 요청시, 전액 환불", "facilityamt": 0, "facilityamtm": "0", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료 환불 규정(약정일기준)", "category": "기타", "subcategory": null, "rentcontent": "6개월이내 60%, 1년이내 50%, 2년이내 40%, 3년이내 30%, 4년이내 20%, 5년이내 10%, 5년초과 0%", "facilityamt": 0, "facilityamtm": "0", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관리비 환불 규정", "category": "기타", "subcategory": null, "rentcontent": "봉안일로부터 사용기간 일할계산후, 환급", "facilityamt": 0, "facilityamtm": "0", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "ROYAL ROOM", "filename": "로얄관1.PNG", "fileurl": "/BCUser/facilitypic/1592457674672_7000002400_0.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1592457674672_7000002400_0.PNG", "filesize": 162539}, {"fileorder": 2, "filetitle": "NOBLE ROOM", "filename": "노블룸2.PNG", "fileurl": "/BCUser/facilitypic/1592457690858_7000002400_0.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1592457690858_7000002400_0.PNG", "filesize": 224675}, {"fileorder": 3, "filetitle": "NOBLE ROOM", "filename": "노블룸1.PNG", "fileurl": "/BCUser/facilitypic/1592457708927_7000002400_0.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1592457708927_7000002400_0.PNG", "filesize": 244517}, {"fileorder": 4, "filetitle": "HONOR NEST", "filename": "아너네스트.PNG", "fileurl": "/BCUser/facilitypic/1592457725378_7000002400_0.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1592457725378_7000002400_0.PNG", "filesize": 248996}, {"fileorder": 5, "filetitle": "HONOR ROOM", "filename": "아너룸.PNG", "fileurl": "/BCUser/facilitypic/1592457739278_7000002400_0.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1592457739278_7000002400_0.PNG", "filesize": 244291}, {"fileorder": 6, "filetitle": "ROYAL ROOM", "filename": "로얄관2.PNG", "fileurl": "/BCUser/facilitypic/1592457661904_7000002400_0.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1592457661904_7000002400_0.PNG", "filesize": 167759}]'::jsonb, '[{