INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000041', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "하남시 마루공원(봉안시설)", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "하남시장", "companyno": "126-83-04349", "telephone": "031-795-2222", "faxnum": "031-795-0987", "homepage": "www.huic.co.kr/www/contents.do?key=103", "fulladdress": "경기도 하남시 하남대로545번길 22-30 (천현동)", "zipcd": "13024", "latitude": "37.522912", "longitude": "127.2181776", "sidonm": "경기도 하남시", "orgid": "4040000", "orgidnm": "경기도 하남시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 1, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "봉안당 안치대상은 사용 신청자가 다음 각 호의 어느 하나에 해당하는 사실을 증명할 수 있는 \r\n서류를 첨부할 경우로 한다.\r\n   1. 관외 사망자 중 부모, 배우자, 자녀가 사망자의 사망일 현재 관내에 주민등록을 두고 1년 이상 계속하여 거주하고 있는 경우 단, 관외 사망자의 부모, 배우자, 자녀가 존재하지 않는 경우 형제자매가 사망자의 사망일 현재 관내에 주민등록을 두고 1년 이상 계속하여 거주하고 있는 경우\r\n   2. 사망일 현재 관내에 주민등록을 두고 1년 이상 계속하여 거주하다가 사망한 자의 유골 단, 하남시 마루공원 설치 이전 사망자 중 화장하여 관외 봉안당에 안치한 유골의 경우 사망자가 관내에 주민등록을 두고 10년 이상 거주한 사실이 입증된 유골\r\n   3. 관외 사망자 또는 관외 개장유골의 경우 배우자가 기존의 봉안당에 안치되어 있는 유골\r\n   4. 관내에서 사망한 행여 사망자의 유골\r\n   5. 관내 기존묘지에서 개장된 유골\r\n   6. 시장이 필요하다고 특별히 인정하는 경우", "traffpublic": "*2호선\n잠실역(7번출구) : 16, 30-3\n강변역(1번출구) : 13, 13-2\n강남역(5번출구) : 9202\n\n*5호선\n천호역(3번출구) : 13, 13-2, 16, 30\n천호역(6번출구) : 30-3\n강동역(4번출구) : 30-3\n둔촌동역(3번출구) : 마을1\n하남검단산역(4번출구) : 30, 30-3, 9301, 마을1", "traffowner": "\r\n중부고속도로 만남의 광장 ⇒ 하남 ic ⇒ 광주(하남경찰서 방향) ⇒ 400m 직진 후 우회전 굴다리 방향", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 154, "waitroom": false, "handicap": true}, "lastUpdateDate": "2011/06/01", "priceitemdate": "2011/06/01"}'::jsonb, '{"hallRent": [{"item": "개인단", "category": "기타", "subcategory": null, "rentcontent": "관내(최초)/15년", "facilityamt": 500000, "facilityamtm": "500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "개인단", "category": "기타", "subcategory": null, "rentcontent": "관내(연장)/15년", "facilityamt": 400000, "facilityamtm": "400,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "부부단", "category": "기타", "subcategory": null, "rentcontent": "관내(최초)15년", "facilityamt": 700000, "facilityamtm": "700,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "부부단", "category": "기타", "subcategory": null, "rentcontent": "관내(연장)/15년", "facilityamt": 600000, "facilityamtm": "600,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "개인단", "category": "기타", "subcategory": null, "rentcontent": "관외(최초)/15년", "facilityamt": 1000000, "facilityamtm": "1,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "개인단", "category": "기타", "subcategory": null, "rentcontent": "관외(연장)/15년", "facilityamt": 800000, "facilityamtm": "800,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "부부단", "category": "기타", "subcategory": null, "rentcontent": "관외(최초)/15년", "facilityamt": 1400000, "facilityamtm": "1,400,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "부부단", "category": "기타", "subcategory": null, "rentcontent": "관외(연장)/15년", "facilityamt": 1200000, "facilityamtm": "1,200,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "하남시 마루공원(봉안시설)", "filename": "하남시 마루공원(봉안시설).PNG", "fileurl": "/BCUser/facilitypic/3000000041/1707873849202.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000041/1707873849202.PNG", "filesize": 1704557}]'::jsonb, '[{"facilitycd": "1000000252", "facilitygroupcd": "TBC0700001", "companyname": "하남시 마루공원(장례식장)", "type": "FuneralHallDet", "fullad