INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000003002', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "대한불교관음회조계종 백천사 봉안탑", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "최동규", "companyno": "613-82-69475", "telephone": "055-834-4010", "faxnum": null, "homepage": "www.bekchunsa.org/", "fulladdress": "경상남도 사천시 백천길 326-2 (백천동, 백천사)", "zipcd": "52547", "latitude": null, "longitude": null, "sidonm": "경상남도 사천시", "orgid": "5340000", "orgidnm": "경상남도 사천시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "대한불교관음회조계종 백천사(이하 ‘갑’이라 한다)와 봉안당(탑)의 계약자 또는 계약자의 권리, 의무승계자(이하 ‘을’이라 한다)간에 다음과 같이 약정한다. \n\n1. 해당 안치단의 소유권은 ‘갑’에게 있고, ‘을’은 유골을 봉안 후 관리비를 납부하고 영구적으로 사용할 수 있는 권리를 갖는다. \n\n2. ‘갑’은 시설의 쾌적하고 안전한 관리에 최선을 다하여야 하며, 시설유지 및 보호를 위한 제도적 장치를 강구하여야 한다.\n\n3. ‘을’은 주소 및 연락처 기타 변동 사항이 있을 경우, 지체 없이 ‘갑’에게 통지하여야 한다.\n\n4. ‘갑’과 ‘을’이 계약서 작성 후 ‘을’의 요청으로 해지할 경우에 절차는 다음과 같다.\n ①계약 성립후 15일 이내: 환급률 100%\n ②계약 성립후 16일부터 3개월 이내: 환급률 90%\n ③계약 성립후 3개월 초과: 공정거래위원회 ''소비자분쟁해결기준(봉안시설업종) 연차별 환급률''에 따른다.\n ④위약금은 전체 보시금-(전체 보시금x환급률)에 의한다.\n ⑤‘을’은 봉안당 해지확인서를 작성(신분증 사본첨부)하고 ‘갑’은 ‘을’이 납부한 비용에서 위약금을 제외한 금액을 반환하여야 한다.                       \n\n5. ‘을’은 봉안당 비용을 현금 결제할 경우 지정된 계좌(농협 351-1175-6443-13 대한불교관음회조계종 백천사)만 이용해야 하며 입금 후 백천사로 확인전화를 반드시 한다.\n\n6. ‘갑’은 ‘을’에게 봉안당 영구봉안약정서를 발부할 수 있고 ‘을’이 유골을 봉안 후 영구관리비까지 완납한 때 봉안당 영구사용승인서를 발급한다.\n\n7. ‘을’은 영구봉안약정서를 ‘갑’의 승낙없이 제3자에게 처분(매매,증여,담보 등) 할 수 없다.\n\n8. 유골을 봉안 후 봉안당의 모든 권리는 영구사용승인서에 기재된 ‘을’에게 있고 ‘을’의 사망시 민법상 상속을 준용한다.\n\n9. ‘을’은 유골 봉안, 유골 반출, 계약 해지 등의 사무를 볼 경우 반드시 ‘갑’에게 먼저 연락하여 필요서류를 확인하고 제출하여야 한다.\n\n10. ‘을’은 유골을 봉안할 때 반드시 진공유골함을 사용하여야 한다. ‘갑’에게 진공유골함 구입 시 비용은 별도 지급한다.\n\n11. ‘갑’은 안치단 내에 비치되어 있는 귀중품에 대한 분실, 훼손에 대하여 책임지지 않는다.\n\n12. ‘을’이 납부한 봉안당 보시금에 장례비용은 포함되지 않는다.\n\n13. ‘갑’은 ‘을’이 유골을 안치 할 때 반혼제(봉안제)를 봉행해야 하며 영가를 안치 후 1년에 18번 합동 축원을 행한다. 반혼제와 합동축원의 절차는 ‘갑’의 방식에 따른다.", "traffpublic": null, "traffowner": null, "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 100, "waitroom": false, "handicap": false}, "lastUpdateDate": "2026/04/07", "priceitemdate": "2026/04/07"}'::jsonb, '{"hallRent": [{"item": "극락4호 부도탑(개인)", "category": "기타", "subcategory": null, "rentcontent": "(영구봉안)", "facilityamt": 10000000, "facilityamtm": "10,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "극락4호 부도탑(부부)", "category": "기타", "subcategory": null, "rentcontent": "(영구봉안)", "facilityamt": 20000000, "facilityamtm": "20,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "극락4호 부도탑(부부 특별)", "category": "기타", "subcategory": null, "rentcontent": "(영구봉안)", "facilityamt": 25000000, "facilityamtm": "25,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "극락4호 부도탑(가족 12기)", "category": "기타", "subcategory": null, "rentcontent": "(영구봉안)", "facilityamt": 35000000, "facilityamtm": "35,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "극락4호 부도탑(문중 32기)", "category": "기타", "subcategory": null, "rentcontent": "(영구봉안)", "facilityamt": 45000000, "facilityamtm": "45,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "유골 봉안후 영구 관리비", "category": "기타", "subcategory": null, "rentcontent": "영구", "facilityamt": 500000, "facilityamtm": "500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "진공 유골함 1기", "category": "기타", "subcategory": null, "rentcontent": "금수강산", "facilityamt": 300000, "facilityamtm": "300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "진공 유골함 1기", "category": "기타", "subcategory": null, "rentcontent": "극락정토", "facilityamt": 500000, "facilityamt