INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000170', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "효심추모관", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "김대인", "companyno": "615-82-08590", "telephone": "02-1644-1103", "faxnum": null, "homepage": "hyosimchoomo.com", "fulladdress": "경상남도 밀양시 삼랑진읍 삼랑진로 605 (미전리)", "zipcd": "50465", "latitude": "35.4135072", "longitude": "128.8094289", "sidonm": "경상남도 밀양시", "orgid": "5360000", "orgidnm": "경상남도 밀양시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "그 분의 품격을 그대로 살렸습니다.\r\n전문가의 설계기술과 첨단 기술의 조화, 집처럼 아늑하고 호텔처럼 세련된 최상의 공간을 제공합니다.\r\n\r\n경부선 철도와 국도 24,25,26 호선을 이용하실 수 있으며,2006년 2월 개통된 부산~대구간 \r\n고속도로의 삼랑진 IC 에서 약 1KM 이내 위치하여 부산, 대구, 울산, 창녕, 마산, 창원, 김해, 진해 권내로\r\n시간상 30분 내외, 거리상으로 10~80KM 내에 포함되어 있으며, 울산 능동터널 개통으로 언양 밀양간 \r\n10분 거리에 위치해있습니다.\r\n\r\n대표문의 전화 : 1644 - 1103", "traffpublic": null, "traffowner": "부산-대구간 고속도로 삼랑진IC에서 약 1km 이내 위치\r\n\r\n부산에서 오시는길\r\n동김해IC->가야IC->생림->삼량진읍->밀양,청도방면->효심추모공원\r\n\r\n울산에서오시는길\r\n울산->언양->가지산터널->밀양->삼량진IC->효심추모공원\r\n", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 120, "waitroom": true, "handicap": true}, "lastUpdateDate": "2016/06/13", "priceitemdate": "2016/06/13"}'::jsonb, '{"hallRent": [{"item": "일반실(지상-개인단)", "category": "개인단", "subcategory": null, "rentcontent": "1단~8단(100만원~500만원)/관리비 1기당 3만원 10년 분 선납 30만원", "facilityamt": 1300000, "facilityamtm": "1,300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반실(지상-부부단)", "category": "부부단", "subcategory": null, "rentcontent": "1단~8단(200만원~800만원)/관리비 1기당 3만원 10년 분 선납 30만원", "facilityamt": 2300000, "facilityamtm": "2,300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반실(지하-개인단)", "category": "개인단", "subcategory": null, "rentcontent": "1단~8단(50만원~350만원)/관리비 1기당 3만원 10년 분 선납 30만원", "facilityamt": 800000, "facilityamtm": "800,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반실(지하-부부단)", "category": "부부단", "subcategory": null, "rentcontent": "1단~8단(100만원~600만원)/관리비 1기당 3만원 10년 분 선납 30만원", "facilityamt": 1300000, "facilityamtm": "1,300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "특실(일반-개인단)", "category": "개인단", "subcategory": null, "rentcontent": "1단,8단(250만원)/관리비 1기당 3만원 10년 분 선납 30만원", "facilityamt": 2800000, "facilityamtm": "2,800,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "특실(일반-부부단)", "category": "부부단", "subcategory": null, "rentcontent": "2단,7단(600만원~1000만원)/관리비 1기당 3만원 10년 분 선납 30만원", "facilityamt": 6300000, "facilityamtm": "6,300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "특실(가족)", "category": "개인단", "subcategory": null, "rentcontent": "1단~8단(300만원~1200만원)/관리비 1기당 3만원 10년 분 선납 30만원", "facilityamt": 3300000, "facilityamtm": "3,300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "전경", "filename": "hyosimchoomo_com_20160613_145910.jpg", "fileurl": "/BCUser/facilitypic/3000000170/1465797635597.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000170/1465797635597.jpg", "filesize": 59034}, {"fileorder": 2, "filetitle": "내부", "filename": "hyosimchoomo_com_20160613_145922.jpg", "fileurl": "/BCUser/facilitypic/3000000170/1465797646882.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000170/1465797646882.jpg", "filesize": 203412}, {"fileorder": 3, "filetitle": "내부", "filename": "hyosimchoomo_com_20160613_145927.jpg", "fileurl": "/BCUser/facilitypic/3000000170/1465797781395.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000170/1465797781395.jpg", "filesize": 190131}, {"fileorder": 4, "filetitle": "내부", "filename": "hyosimchoomo_com_20160613_145939.jpg", "fileurl": "/BCUser/facilitypic/3000000170/1465797791029.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000170/1465797791029.jpg", "filesize": 181471}]'::jsonb, '[{"facilitycd": "3000000170", "facilitygroupcd": "TBC0700003", "companyname": "효심추모관", "type": "CharnelDet", "fulladdress": "경상남도 밀양시 삼랑진읍 삼랑진로 605 (미전리)", "telephone": "02-1644-1103", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000170/1465797635597.jpg"}, {"facilitycd": "7000002323", "facilitygroupcd": "TBC0700005", "companyname": "재단법인 효심추모관 자연장지", "type": "NaturalBurialDet", "fulladdress": "경상남도 밀양시 삼랑진읍 삼랑진로 605 (미전리)", "telephone": "055-802-7091", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/7000002323/1709603733433.PNG"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001891', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "재단법인청림공원(봉안탑)", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "배동걸", "companyno": "681-82-00654", "telephone": "031-527-5678", "faxnum": null, "homepage": null, "fulladdress": "경기도 남양주시 진건읍 사릉로156번길 295 (송능리, 봉인사)", "zipcd": "12140", "latitude": null, "longitude": null, "sidonm": "경기도 남양주시", "orgid": "3990000", "orgidnm": "경기도 남양주시", "firstcharnelcnt": 99, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "청림공원은 남양주시 진건읍 송능리에 위치하고 있다.\r\n\r\n지명이 말해주듯 소나무(松)와 릉(陵)이 많은 곳이다.\r\n주변에는 홍릉, 유릉, 사릉, 성릉, 광해군, 임해군, 안빈묘 풍양조씨 시조묘 등이 청림공원 바로아래 위치하고 있다.\r\n\r\n인접한 봉인사에는 석가모니 진신사리가 모셔져 있는 곳 이기도하다.\r\n봉인사 부도암 사리탑(보물928호)은 1619년 광해군이 중국에서 석가모니 진신사리를 모셔와 1620년에 건립할 만큼 우리민족에게 소중하고 의미 있는 곳이다.\r\n\r\n청림공원 주변은 지혜로운 우리의 선조들이 선택한 최고의 길지이다.\r\n자리의 명성에 못지않게 주변 환경 및 시설 또한 국내최고의 수준으로 꾸며 놓았다.\r\n주변 환경은 유명지관의 의견을 수렴하여 자연의 지형 및 산세를 그대로 살리고 납골당 내부의 시설은 본사가 최대 / 최고의 업체와 제휴 기존의 시설과는 차별화된 한 차원 높은 시설을 국내에 도입 설치하였다.  \r\n\r\n도심권 최고의 장례 명당 길지\r\n\r\n- 고인과 후손을 위한 영원한 안식처-\r\n\r\n청림공원은 유명 지관들도 인정하는 좌청룡, 우백호, 남주작, 북현무의 형상이 뚜렷한 장례명당 길지로써 어머님의 모태형상을 갖춘 “천리원행지 응봉하강형국”의 풍수말을 가진 공원으로써 주변에 여러 왕릉이 위치한 풍수지리적 명당입니다.\r\n\r\n- 자연친화적 공원형 휴계시설\r\n\r\n추모공원내에 식당, 음료, 산책로, 폭포, 약수터, 제례실 등이 갖춰져 있어 고인과 유족들의 진정한 추모의 시간을 가질 수 있습니다.\r\n함께보냈던 많은 시간만큼 추억의 깊이도 더해집니다. 아름답게 기억할 수 있는 편히 쉴 수 있는 아늑하고 안락한 남양주 청림공원 그리움이 짙어지고, 가족 간의 사랑이 더욱 깊어집니다.\r\n\r\n- 고품격 시설의 맑은 영혼의 영원한 안식처\r\n\r\n일본 납골 최고업체 H사의 고품격 안치단과 고인의 품격을 높여주는 탑 구조물 형식의 전통적 멋을 살린 아무나 소유할 수 없는 프리미엄 묘역 남양주 청림공원에서 고품격 장례문화를 그리운 가족들과 함께 한 곳에서 만나십시오.", "traffpublic": "강변역: 9-1, 9-3, 9-7, 23, 1115-2\r\n잠실역: 1000, 1115\r\n청량리: 30, 65, 165, 165-3, 330-1\r\n           765,1330,1330-1\r\n경춘선 금곡역에서 3.5km\r\n마을버스 64번 환승시 앞마당까지", "traffowner": "네비게이션 : \r\n주소검색시 : 남양주시 진건읍 송능2리 304-14\r\n명칭검색시 : 봉인사(진건읍 송능리)", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 100, "waitroom": true, "handicap": true}, "lastUpdateDate": "2017/10/22", "priceitemdate": "2017/10/22"}'::jsonb, '{"hallRent": [{"item": "봉안탑 연립2기 ", "category": "기타", "subcategory": null, "rentcontent": "관리비 4년원/년", "facilityamt": 7000000, "facilityamtm": "7,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안탑 2기", "category": "기타", "subcategory": null, "rentcontent": "관리비 5년원/년", "facilityamt": 12000000, "facilityamtm": "12,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안탑 4기", "category": "기타", "subcategory": null, "rentcontent": "관리비 5년원/년", "facilityamt": 15000000, "facilityamtm": "15,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안탑 8기", "category": "기타", "subcategory": null, "rentcontent": "관리비 6년원/년", "facilityamt": 17000000, "facilityamtm": "17,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안탑 12기", "category": "기타", "subcategory": null, "rentcontent": "관리비 7년원/년", "facilityamt": 25000000, "facilityamtm": "25,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안탑 16기", "category": "기타", "subcategory": null, "rentcontent": "관리비 7년원/년", "facilityamt": 20000000, "facilityamtm": "20,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안탑 24기", "category": "기타", "subcategory": null, "rentcontent": "관리비 8년원/년", "facilityamt": 35000000, "facilityamtm": "35,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "봉인사 청림공원(봉안탑)", "filename": "봉인사 청림공원(봉안탑).PNG", "fileurl": "/BCUser/facilitypic/7000001891