g", "fileurl": "/BCUser/facilitypic/1701325148987.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1701325148987.jpg", "filesize": 3995079}, {"fileorder": 7, "filetitle": null, "filename": "6.jpg", "fileurl": "/BCUser/facilitypic/1701325194149.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1701325194149.jpg", "filesize": 1805337}, {"fileorder": 8, "filetitle": null, "filename": "9.jpg", "fileurl": "/BCUser/facilitypic/1701325299417.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1701325299417.jpg", "filesize": 3081778}, {"fileorder": 9, "filetitle": null, "filename": "13.jpg", "fileurl": "/BCUser/facilitypic/1701325324062.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1701325324062.jpg", "filesize": 1899688}, {"fileorder": 10, "filetitle": null, "filename": "2.jpg", "fileurl": "/BCUser/facilitypic/1701400256406.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1701400256406.jpg", "filesize": 1736240}]'::jsonb, '[{"facilitycd": "7000000229", "facilitygroupcd": "TBC0700003", "companyname": "생극납골공원", "type": "CharnelDet", "fulladdress": "충청북도 음성군 생극면 일생로 497-27 (관성리)", "telephone": "080-231-4444", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1326335282089_7000000229_0.jpg"}, {"facilitycd": "7000000230", "facilitygroupcd": "TBC0700003", "companyname": "생극추모공원", "type": "CharnelDet", "fulladdress": "충청북도 음성군 생극면 일생로 497-27 (관성리)", "telephone": "080-345-4444", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1326336275279_7000000230_0.jpg"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001582', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(재)용인공원(봉안담·묘)", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "김동균", "companyno": "208-82-00992", "telephone": "031-334-3484", "faxnum": null, "homepage": "www.yongin-park.com", "fulladdress": "경기도 용인시 처인구 모현면 새래로 158-33 (초부리, 용인공원묘지)", "zipcd": "17037", "latitude": "37.2987249", "longitude": "127.2543909", "sidonm": "경기도 용인시 처인구", "orgid": "4050001", "orgidnm": "경기도 용인시 처인구", "firstcharnelcnt": 5, "renewyears": 99, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[역  사]\r\n조선독립운동가 도산 안창호 선생의 추모사업회 ‘흥사단’에서 출발하였습니다.\r\n설립 이후 현재까지 150만m2 의 장묘 터전에 \r\n무차입 경영을 통해 지난 40년간 안정적으로 운영해 왔습니다. \r\n\r\n본 재단은 2대 김창원 회장(창업주)의 ‘自力經營精神’과 체계적인 공원묘원 운영으로 \r\n재단을 한도약 성장시켰고,지난 35년간 무차입 경영으로 안정적인 재단 운영을 하고 있습니다.\r\n전통적인 매장묘, 격조 높은 봉안묘와 더불어 고품격 봉안담, 다양한 수목장에 이르기까지 \r\n다양한 장묘법을 구현해 왔습니다. \r\n재단법인 용인공원은 정직한 경영과 끊임없이 노력하는 자세로 \r\n한국의 장묘 문화 발전을 선도해 나가겠습니다. \r\n\r\n[연  혁]\r\n1975.6. 재단법인 용인공원 설립\r\n1975.6.21. 洪碩雄 1대 이사장 취임\r\n1975.9. 1차 사설묘지 허가\r\n1976.6. 2차 사설묘지 허가\r\n1979.8. 3차 사설묘지 허가\r\n1981.9. 金昌原 2대 이사장 취임\r\n1987.1. 4차 사설묘지 허가\r\n1991.3. 5차 사설묘지 허가\r\n2002.7. 공원 관리소 신축 및 재단본부 통합\r\n2005.9 가족봉안묘 설치 판매개시\r\n2006.7. 金東均 3대 (현)이사장 취임\r\n2009.10 조직 확대개편, 마케팅본부, 건설본부 신설\r\n2010.3. 기업 new-brand B.I. 변경(KOREAN TRADITIONAL PREMIUM컨셉)\r\n2010.5 고품격 가족묘 \"정명지\"오픈\r\n2010.8 친환경 봉안담 \"하늘담재\"오픈\r\n2011.3 신개념 매장묘 \"정남지\"오픈\r\n2013.1 수목장의 새로운 기준 \"세수연\" 오픈\r\n2014.1 국내최초 묘역찾기 서비스 개시(GPS연동 용인공원 어플리케이션 출시)\r\n\r\n[공원의 특징]\r\n대한민국 공원묘원 최대 녹지비율\r\n대한민국 공원묘원 최대 규모(165만m2)\r\n서울 수도권에서 30분 거리의 대한민국 명당지\r\n기존 조성 묘역 ; 2만5천기 묘소\r\n\r\n홈페이지 : www.용인공원,com\r\n임직원수 : 김동균 이사장외 52명", "traffpub