INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001095', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "만인산 만인사 봉안당", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "김성수", "companyno": "305-89-05036", "telephone": "041-751-3755", "faxnum": null, "homepage": "만인추모관.inter114.com/", "fulladdress": "충청남도 금산군 복수면 다복로 525-35 (용진리, 만인사)", "zipcd": "312923", "latitude": "36.1855809", "longitude": "127.4439354", "sidonm": "충청남도 금산군", "orgid": "4550000", "orgidnm": "충청남도 금산군", "firstcharnelcnt": 15, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "- 만인산 만인사 봉안당은 정식허가를 받아 명당에 위치한 조용하고 가족적인  최고의 명당 봉안시설입니다.\r\n- 종교별 영구봉안 (무제한 / 봉안당) 납골당 을 운영중이며 가족 잔되장.수목장을 준비중. 묘지 이장 부터 납골당 안치까지 고인을   편안히 모시기 위해 노력하고 있습니다.\r\n- 저희 봉안당은 우리나라 장사문화의 선두적 역활과 신개념의 장사문화 정착을 위해 최저비용으로 성심성의껏 최선을 다할 것을 약속드립니다.\r\n추모관을 청결하게 관리차원에서 전국에서 최초로 .실용신안특허 도자기함.진공함.을 안내 해 드립니다.", "traffpublic": "추부버스종점 ~ 대둔산방향버스 다복 용진리하차~만인사\r\n대전출발 대둔산버스 ~복수면 삼거리 하차 ~ 추부방향 버스 ~다복로 용진리 하차 ~만인추모관", "traffowner": "대전-통영고속도로-추부 IC-복수(대둔산)방향 2.2 km~만인사\r\n대전-머들령터널-추부면-다복로복수면 방향 2.2km 만인사 \r\n서대전-복수면-추부면방향 -다복로 용진리-만인추모관", "facilities": {"mealroom": true, "supermarket": false, "parking": true, "parkingCount": 100, "waitroom": true, "handicap": true}, "lastUpdateDate": "2025/11/10", "priceitemdate": "2025/11/10"}'::jsonb, '{"hallRent": [{"item": "봉안당사용료", "category": "개인단", "subcategory": null, "rentcontent": "안치단 1 단 ~ 9 단   275mm X 275mm", "facilityamt": 1500000, "facilityamtm": "1,500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안당사용료", "category": "개인단", "subcategory": null, "rentcontent": "안치단 2단 ~ 8단   275mm X 275mm", "facilityamt": 2000000, "facilityamtm