INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000090', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "부산영락공원 봉안당", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "이해성", "companyno": "605-82-05242", "telephone": "051-790-5000", "faxnum": "051-508-6024", "homepage": "https://yeongnakpark.bisco.or.kr/yeongnakpark/index.asp", "fulladdress": "부산광역시 금정구 금정도서관로 108 (두구동)", "zipcd": "609370", "latitude": "35.2733077", "longitude": "129.1042192", "sidonm": "부산광역시 금정구", "orgid": "6260000", "orgidnm": "부산광역시", "firstcharnelcnt": 15, "renewyears": 5, "renewcount": 3, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "【 사용대상 】\r\n\r\n〇 사망 당시(사망일 현재) 부산시민(부산광역시에 주소를 둔자)\r\n\r\n【 감면대상 】\r\n\r\n〇 100% 감면\r\n - 「국민기초생활 보장법」 제7조제1항제1호 및 제3호에 따른 생계급여, 의료급여 수급자\r\n - 「국가유공자 등 예우 및 지원에 관한 법률」 의 적용을 받는 국가유공자\r\n - 연고자가 없는 부랑인 및 노숙자\r\n - 「부산광역시 일제하 일본군위안부 피해자 지원 및 기념사업에 관한 조례」 제4조에 따른 지원대상자\r\n - 「부산광역시 장기 및 인체조직 기증 장려에 관한 조례」에 따른 장기등기증자로서 뇌사 및 사망한 자와 인체조직기증자\r\n\r\n〇 50% 감면\r\n - 금정구 남산동, 청룡노포동, 선두구동 주민\r\n -「5.18 민주유공자 예우에 관한 법률」 제4조에 따른 5.18 민주유공자와 배우자", "traffpublic": "부산 지하철 1호선 범어사역 2번출구 또는\r\n부산 시내버스(52번, 148번, 1002번) 범어사 지하철역 정류장에 하차 후, 도보로 약 15분 또는 마을버스 이용", "traffowner": "경부고속도로 상행선(부산->서울)에서 진입시 고속도로 매표소 이전 약 1km지점에서 영락공원 전용도로(우측 고가도로) 이용", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 132, "waitroom": true, "handicap": true}, "lastUpdateDate": "2017/10/27", "priceitemdate": "2017/10/27"}'::jsonb, '{"hallRent": [{"item": "봉안당 사용료(부산광역시민)", "category": "개인단", "subcategory": null, "rentcontent": "1기당 최초 15년", "facilityamt": 120000, "facilityamtm": "120,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안당