INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001341', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "성북구추모의집", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "이승로", "companyno": "209-83-00013", "telephone": "031-354-2325", "faxnum": null, "homepage": "skypark2002.cafe24.com/smpark/seongbuk/standard.asp", "fulladdress": "경기도 화성시 향남읍 서봉로755번길 17-15 (동오리)", "zipcd": "18624", "latitude": "37.1432574", "longitude": "126.95489", "sidonm": "서울특별시 성북구", "orgid": "3070000", "orgidnm": "서울특별시 성북구", "firstcharnelcnt": 15, "renewyears": 5, "renewcount": 3, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[사용료 및 관리비 반환기준·방법]\n1. 사용료 반환(서울특별시 성북구 장사 등에 관한 조례) : 남은 일수에 따라 반환금액 상이\n - 제15조(사용료 등의 반환) ①구청장은 이미 납부한 사용료 등을 사용기간 이 종료되지 않음을 이유로 하여 그에 상당하는 금액을 반환하지 아니 한다. 다만 사용자가 그의 책임 없는 사유로 인하여 시설을 이용하지 못 하게 된 경우에는 그러하지 아니하다. \n2. 관리비 반환 : 남은 연수에 따라 반환금액 상이\n * 자세한 사항은 성북구추모의집에 문의필요 ", "traffpublic": null, "traffowner": null, "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 200, "waitroom": false, "handicap": true}, "lastUpdateDate": "2026/04/02", "priceitemdate": "2026/04/02"}'::jsonb, '{"hallRent": [{"item": "봉안당 사용료(1위당, 15년)", "category": "개인단", "subcategory": null, "rentcontent": "「서울특별시 성북구 장사 등에 관한 조례」제8조에 따른 사용자", "facilityamt": 200000, "facilityamtm": "200,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안당 관리비(1위당, 15년)", "category": "개인단", "subcategory": null, "rentcontent": "공통", "facilityamt": 600000, "facilityamtm": "600,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "특례적용(사용료 감면, 관리비 별도)", "category": "기타", "subcategory": null, "rentcontent": "「국민기초생활 보장법」에 따른 