INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000217', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "여주추모공원 봉안담", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "임명진", "companyno": "126-82-12541", "telephone": "031-880-4061", "faxnum": "031-887-2476", "homepage": "https://yeojuuc.or.kr/sub1/memorial/park.do", "fulladdress": "경기도 여주시 가남읍 여주남로 769 (본두리)", "zipcd": "12656", "latitude": "37.2980237", "longitude": "127.6371628", "sidonm": "경기도 여주시", "orgid": "4110000", "orgidnm": "경기도 여주시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 2, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[이용조건]\r\n- 관내자 기준\r\n  * 사망일 현재 시에 주민등록상의 주소를 두고 6개월 이상 계속하여 거주한 자\r\n  * 관내 묘지(봉안시설)의 매장(봉안) 후 개장(이전)하여 여주추모공원에 안치하는 경우\r\n  * 배우자 중 1인이 여주추모공원 봉안담 부부, 자연장 부부에 안치되어 있는 상태에서 관외 거주 배우자 또는 6개월  미만의 관내 거주 배우자가 사망하여 합장하는 경우(이용기간 : 기존 안치자)\r\n\r\n- 관외자 기준\r\n  * 사망일 현재 시에 6개월 이상 주민등록상의 주소를 둔 사람의 관외 거주 또는 6개월 미만의 관내 거주 부모(배우자의 부모 포함) 및 자녀(자녀의 배우자를 포함)가 사망 또는 관외 묘지(봉안시설)의 매장(봉안) 후 개장(이전)하여 여주추모공원에 안치하고자 하는 경우", "traffpublic": "태평터미널 930,930-1 승차 → 본두3리 정류장 하차 → 도보 이동 50m(약 6Km)\r\n시내버스(여주시) 여주종합터미널 정류장 930-1, 930 승차 →  본두3리 정류장 하차 → 도보 이동 50m (약 13Km)", "traffowner": "국도 : 음성군, 이천시, 여주시, 양평군 333번 지방도 → 가남읍 여주남로 769\r\n고속도로 : 영동고속도로 → 중부내륙고속도로 → 남녀주IC → 남여주IC교차로 가남방면 우회전 (약 3Km)", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 137, "waitroom": false, "handicap": false}, "lastUpdateDate": "2019/01/14", "priceitemdate": "2019/01/14"}'::jsonb, '{"hallRent": [{"item": "사용료/관리비", "category": "개인단", "subcategory": null, "rentcontent": "최초 15년 / 관내-개인", "facilityamt": 500000, "facilityamtm": "500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료/관리비", "category": "부부단", "subcategory": null, "rentcontent": "최초 15년 / 관내-부부", "facilityamt": 750000, "facilityamtm": "750,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료/관리비", "category": "개인단", "subcategory": null, "rentcontent": "최초 15년 / 관외-개인", "facilityamt": 1000000, "facilityamtm": "1,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료/관리비", "category": "부부단", "subcategory": null, "rentcontent": "최초 15년 / 관외-부부", "facilityamt": 1500000, "facilityamtm": "1,500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관리비", "category": "개인단", "subcategory": null, "rentcontent": "최초 15년 / 관내-개인-사망 당시 추모공원 소재지에 주민등록상 주소를 둔자", "facilityamt": 100000, "facilityamtm": "100,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관리비", "category": "부부단", "subcategory": null, "rentcontent": "최초 15년 / 관내-부부-사망 당시 추모공원 소재지에 주민등록상 주소를 둔자", "facilityamt": 150000, "facilityamtm": "150,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "자연장", "filename": "자연장지_1.JPG", "fileurl": "/BCUser/facilitypic/1464166982296_3000000217_0.JPG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1464166982296_3000000217_0.JPG", "filesize": 4393874}, {"fileorder": 2, "filetitle": "여주추모공원 전경", "filename": "파노라마 여주추모공원.jpg", "fileurl": "/BCUser/facilitypic/1464165813028_3000000217_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1464165813028_3000000217_0.jpg", "filesize": 846541}, {"fileorder": 3, "filetitle": "봉안담", "filename": "파노라마 여주추모공원_1.jpg", "fileurl": "/BCUser/facilitypic/1464166823259_3000000217_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1464166823259_3000000217_0.jpg", "filesize": 583094}, {"fileorder": 4, "filetitle": "여주추모공원", "filename": "파노라마 여주추모공원_1.jpg", "fileurl": "/BC