INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000971', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "연화추모공원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "노선근", "companyno": "2329003172", "telephone": "031-963-1141", "faxnum": null, "homepage": "www.yeonhwapark.co.kr", "fulladdress": "경기도 고양시 덕양구 성령길 2-1 (대자동)", "zipcd": "412480", "latitude": "37.6970938", "longitude": "126.8787318", "sidonm": "경기도 고양시 덕양구", "orgid": "3940000", "orgidnm": "경기도 고양시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": null, "traffpublic": "지하철 이용시\r\n3호선 삼송역 하차 후 7번출구 앞에서 마을버스 25번, 37번(정류장 : 삼송역 7번출구)필리핀 참전비마을버스 36번 환승대자동 마을회관 하차 \r\n\r\n버스 이용시\r\n3호선 삼송역 하차 후 8번출구 앞으로 50m 직진 후 건너편 버스정류장에서 탑승(정류장 : 삼송역사거리. 지축차량기지입구)\r\n일반버스 17번, 30번, 31번, 55번, 55-2번, 100번, 760번필리핀 참전비마을버스 36번 환승대자동 마을회관 하차\r\n좌석버스 909번, 9709번, 9710번, 9080번필리핀 참전비마을버스 36번 환승대자동 마을회관 하차", "traffowner": "서울역, 홍제동 방향에서 이용시\r\n구파발통일로벽제화장장필리핀 참전비최영장군묘방면 우회전 1km간촌방면 좌회전 100m연화추모공원 \r\n\r\n외곽순환도로 이용시\r\n통일로IC에서 파주,문산방향필리핀 참전비최영장군묘방면 우회전 1km간촌방면 좌회전 100m연화추모공원 ", "facilities": {"mealroom": false, "supermarket": false, "parking": false, "parkingCount": null, "waitroom": false, "handicap": false}, "lastUpdateDate": "2022/05/07", "priceitemdate": "2022/05/07"}'::jsonb, '{"hallRent": [{"item": "1층 정토실(개인단)", "category": "개인단", "subcategory": null, "rentcontent": "사용료:200만원~700만원 관리비:5년 30만원", "facilityamt": 2300000, "facilityamtm": "2,300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "1층 정토실(부부단)", "category": "부부단", "subcategory": null, "rentcontent": "사용료:400만원~1400만원 관리비:5년 60만원", "facilityamt": 4600000, "facilityamtm": "4,600,000", 