INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000819', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "울산하늘공원 추모의집", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "울산시설공단", "companyno": "620-82-0474", "telephone": "052-255-3800", "faxnum": "052-255-3809", "homepage": "https://www.uic.or.kr/skypark/enshrine/enshrine01.do", "fulladdress": "울산광역시 울주군 삼동면 보삼길 550 (조일리)", "zipcd": "44956", "latitude": "35.483402", "longitude": "129.1228652", "sidonm": "울산광역시", "orgid": "6310000", "orgidnm": "울산광역시", "firstcharnelcnt": 15, "renewyears": 5, "renewcount": 3, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[이용조건]\r\n- 사망 당시 관내에 거주한「국가보훈 기본법」에 따른 희생·공헌자와 그 배우자\r\n- 사망 당시 관내에 거주한「국민기초생활 보장법」따른 수급자\r\n- 관내에서 사망한 무연고자\r\n- 사망 당시 관내 거주자 또는「울산광역시 외국인주민 지원 조례」에 해당하는 사람\r\n- 부부단의 경우 부부 중 한명이 추모의 집 이용대상이 되면 관외자 부부단 안치가능\r\n\r\n\r\n[반액 감면대상]\r\n-「국민기초생활 보장법」에 따른 관내 생계급여 수급자 또는 의료급여 수급자\r\n-「국가보훈 기본법」에 따른 관내 희생·공헌자\r\n- 시 관내에서 사망한 무연고자, 「사회복지사업법」에 따른 사회복지시설 입소자 중 무연고자\r\n- 그 밖에 재난 등의 특별한 사유가 있다고 시장이 인정하는 자\r\n\r\n❍ 울산하늘공원은 120만 울산광역시민들의 오랜 숙원사업의 하나로  울산시민들의 뜨거운 관심속에 조성된 최첨단 종합장사시설입니다.\r\n\r\n❍ 울주군 삼동면 정족산 자락!  9만 8천여㎡ 부지에 국비144억 시비87억 복권기금 255억 총 486억원을 들여 전국 최고 시설로 우뚝선 울산하늘공원\r\n\r\n❍ 울산하늘공원은 전국 최초로 지역 주민들의 자발적인 유치의사로 건립됨에 따라 지역현안을 해결하는 동시에 지역발전을  앞당긴 전국적인 모범사례로 손꼽히고 있습니다.\r\n\r\n❍ 120만 울산시민들에게 보다 저렴한 비용으로 고품격의 장사서비스를 제공하고 있는 울산하늘공원\r\n\r\n❍ 장례, 화장, 봉안에 이르는 장례절차 전반을 한 곳에서  One-Stop으로 편리하게 이용할 수 있는 하늘공원", "traffpublic": "■ 지번 952번 버스(율리 <=> 울산하늘공원)\r\n\r\n- 신복로터리 출발 - 6:00 / 8:00 / 10:10 / 13:00 / 15:10 / 17:10\r\n\r\n- 하늘공원    출발 - 7:00 / 9:10 / 11:20 / 14:10 / 16:10 / 18:10", "traffowner": "■ 네비게이션 검색 : 울산광역시 울주군 삼동면 보삼길 550 (구, 조일리 15-22)\r\n\r\n ▷ 고속도로 : 신복로터리 → 울산고속도로 진입 → 경부고속도로 → 통도사IC(출차) → 군도34호(삼동방면) → 현대자동차출구사무소 → 조일주유소 → 울산하늘공원 \r\n\r\n ▷ 언양국도 : 신복로터리 → 범서 → 반천 → 언양 → 삼성SDI → 통도사방면 →군도34호(삼동방면) → 현대자동차출구사무소 → 조일주유소 → 울산하늘공원 \r\n\r\n ▷ 삼동로 : 신복로터리 → 울산대학교 → 대복 → 삼동면사무소 → 조일주유소 → 울산하늘공원 ", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 419, "waitroom": true, "handicap": true}, "lastUpdateDate": "2026/01/10", "priceitemdate": "2026/01/10"}'::jsonb, '{"hallRent": [{"item": "추모의 집(봉안당) 이용료", "category": "개인단", "subcategory": null, "rentcontent": "개인단 1구당- 관내(15년)", "facilityamt": 330000, "facilityamtm": "330,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "추모의 집(봉안당) 연장 이용료", "category": "개인단", "subcategory": null, "rentcontent": "개인단 1구당- 관내(5년)", "facilityamt": 110000, "facilityamtm": "110,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "추모의 집(봉안당) 이용료", "category": "부부단", "subcategory": null, "rentcontent": "부부단 1구당- 관내(15년)", "facilityamt": 330000, "facilityamtm": "330,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "추모의 집(봉안당) 연장 이용료", "category": "부부단", "subcategory": null, "rentcontent": "부부단 1구당- 관내(5년)", "facilityamt": 110000, "facilityamtm": "110,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "추모의 집(봉안당) 이용료", "category": "부부단", "subcategory": null, "rentcontent": "부부단 1구당- 관외(15년)", "facilityamt": 1000000, "facilityamtm": "1,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "추모의 집(봉안당) 연장 이용료", "category": "부부단", "subcategory": null, "rentcontent": "부부단 1구당- 관외(15년)", "facilityamt": 400000, "facilityamtm": "400,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "고인검색PC", "filename": "SAM_9423.JPG", "fileurl": "/BCUser/facilitypic/1465804828775_7000000819_0.JPG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1