INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000031', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "대전추모공원 영락원", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "임재남", "companyno": "314-82-07247", "telephone": "042-602-2500", "faxnum": null, "homepage": "www.djsiseol.or.kr/portal/sub040203.asp", "fulladdress": "대전광역시 서구 상보안윗길 160 (괴곡동)", "zipcd": "302110", "latitude": "36.2840164", "longitude": "127.3397916", "sidonm": "대전광역시 서구", "orgid": "6300000", "orgidnm": "대전광역시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 1, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[이용조건]\r\n- 사망자가 사망일 현재 대전시에 1개월 이상 주민등록한 자\r\n- 부모, 자녀, 배우자 중 6개월 이상 주민등록한 자\r\n- 관내 소재 분묘 개장유골\r\n- 관외 소재 분묘 중 사망 직전 관내에 주민등록 되어 있던 유골\r\n- 부부 중 1명이 추모공원 봉안당,자연장지에 안치되어 있는 경우 그 배유자\r\n\r\n[전액 감면대상]\r\n- 관내 주민등록자\r\n . 국가유공자, 기초생활수급자, 독립유공자, 장기기증자\r\n . 무의탁 사회복지시설 입소자\r\n . 연고자가 없는 행려사망자\r\n . 천재지변의 사유로 납부능력 없는 자\r\n- 관외 주민등록자로 부모, 자녀, 배우자 중 6개월 이상 관내 주민등록자인 경우의 국가유공자, 독립유공자", "traffpublic": "- 외곽버스 21번,25번 (서남부터미널 → 도마동 → 정림동 → 가수원 → 괴곡동 →대전추모공원)\n   대전추모공원 정류장에서 하차 → 도보 150M\n\n- 외곽버스 22번~ 24번(서남부터미널 → 도마동 → 정림동 → 가수원 → 괴곡동)\n   벌말 정류장에서 하차 → 도보 1,800M", "traffowner": "대덕대로(2.5km)  → 동서대로(2.2km)  → 도안동로(3.1km)  → 벌곡로(3.7km) ", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 418, "waitroom": true, "handicap": true}, "lastUpdateDate": "2020/08/28", "priceitemdate": "2020/08/28"}'::jsonb, '{"hallRent": [{"item": "봉안(관내)", "category": "기타", "subcategory": null, "rentcontent": "1구당/15년기한", "facilityamt": 200000, "facilityamtm": "200,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉인(관외)", "category": "기타", "subcategory"