INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000132', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "제천시영원한쉼터봉안당", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "제천시장", "companyno": "304-83-02387", "telephone": null, "faxnum": null, "homepage": "www.okjc.net/welfare/contents.do?key=771", "fulladdress": "충청북도 제천시 송학면 포전리 373번지 외", "zipcd": "27122", "latitude": "37.1922395", "longitude": "128.2282397", "sidonm": "충청북도 제천시", "orgid": "4400000", "orgidnm": "충청북도 제천시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 3, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "◈ 이용자격 \n (1) 사망일 현재 제천시에 6개월이상 주민등록이 되어 있는 사람\n (2) 제천시에 6개월이상 주민등록이 되어 있는 사람의 부모, 배우자, 자녀\n (3) 이미 안치되어 있는 사망자의 배우자\n (4) 제천시 관내 거주 외국인\n◈ 감면대상\n (1) 사망일 현재 기준 1년이상 제천시 송학면 포전리로 주민등록이 되어 있는 사람 - 전액감면\n (2) 장기등기증자 중 사망일 현재 기준 1년 이상 제천시에 주민등록이 되어 있는 사람 - 50% 감면\n◈ 결재방법 : 카드 수납만 가능(현금 수납 불가)", "traffpublic": "일반버스:제천역출발 330,335,340,350,360 → 포전리,영원한쉼터입구 정류장 하차(하차후 도보 15분 이동) ", "traffowner": "제천IC(시내방면)-법흥사방면(외곽도로를거쳐 주천,평창가는길)-두번째 고개에서 좌회전<제천시 영원한쉼터>                             \n\n네비게이션검색\n주소:제천시 송학면 송학주천로9길 122(포전리 594번지)\n명칭:제천시 영원한쉼터", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 150, "waitroom": true, "handicap": true}, "lastUpdateDate": "2016/06/13", "priceitemdate": "2016/06/13"}'::jsonb, '{"hallRent": [{"item": "개인(관내)", "category": "개인단", "subcategory": null, "rentcontent": "사용료:10만원 관리비:6만", "facilityamt": 160000, "facilityamtm": "160,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "개인(준관내)", "category": "개인단", "subcategory": null, "rentcontent": "충북도 관내, 중부내륙중심권행정협력 시ㆍ군/사용료:30만원,관리비:6만원", "facilityamt": 360000,