INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000527', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "재단법인청림공원(봉안당)", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "배동걸", "companyno": "681-82-00654", "telephone": "031-527-5678", "faxnum": null, "homepage": null, "fulladdress": "경기도 남양주시 진건읍 사릉로156번길 295 (송능리, 봉인사)", "zipcd": "12140", "latitude": "37.6620835", "longitude": "127.2178016", "sidonm": "경기도 남양주시", "orgid": "3990000", "orgidnm": "경기도 남양주시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "청림공원은 남양주시 진건읍 송능리에 위치하고 있다.\r\n\r\n지명이 말해주듯 소나무(松)와 릉(陵)이 많은 곳이다.\r\n주변에는 홍릉, 유릉, 사릉, 성릉, 광해군, 임해군, 안빈묘 풍양조씨 시조묘 등이 청림공원 바로아래 위치하고 있다.\r\n\r\n인접한 봉인사에는 석가모니 진신사리가 모셔져 있는 곳 이기도하다.\r\n봉인사 부도암 사리탑(보물928호)은 1619년 광해군이 중국에서 석가모니 진신사리를 모셔와 1620년에 건립할 만큼 우리민족에게 소중하고 의미 있는 곳이다.\r\n\r\n청림공원 주변은 지혜로운 우리의 선조들이 선택한 최고의 길지이다.\r\n자리의 명성에 못지않게 주변 환경 및 시설 또한 국내최고의 수준으로 꾸며 놓았다.\r\n주변 환경은 유명지관의 의견을 수렴하여 자연의 지형 및 산세를 그대로 살리고 납골당 내부의 시설은 본사가 최대 / 최고의 업체와 제휴 기존의 시설과는 차별화된 한 차원 높은 시설을 국내에 도입 설치하였다.  \r\n\r\n도심권 최고의 장례 명당 길지\r\n\r\n- 고인과 후손을 위한 영원한 안식처-\r\n\r\n청림공원은 유명 지관들도 인정하는 좌청룡, 우백호, 남주작, 북현무의 형상이 뚜렷한 장례명당 길지로써 어머님의 모태형상을 갖춘 “천리원행지 응봉하강형국”의 풍수말을 가진 공원으로써 주변에 여러 왕릉이 위치한 풍수지리적 명당입니다.\r\n\r\n- 자연친화적 공원형 휴계시설\r\n\r\n추모공원내에 식당, 음료, 산책로, 폭포, 약수터, 제례실 등이 갖춰져 있어 고인과 유족들의 진정한 추모의 시간을 가질 수 있습니다.\r\n함께보냈던 많은 시간만큼 추억의 깊이도 더해집니다. 아름답게 기억할 수 있는 편히 쉴 수 있는 아늑하고 안락한 남양주 청림공원 그리움이 짙어지고, 가족 간의 사랑이 더욱 깊어집니다.\r\n\r\n- 고품격 시설의 맑은 영혼의 영원한 안식처\r\n\r\n일본 납골 최고업체 H사의 고품격 안치단과 고인의 품격을 높여주는 탑 구조물 형식의 전통적 멋을 살린 아무나 소유할 수 없는 프리미엄 묘역 남양주 청림공원에서 고품격 장례문화를 그리운 가족들과 함께 한 곳에서 만나십시오.", "traffpublic": "강변역: 9-1, 9-3, 9-7, 23, 1115-2\r\n잠실역: 1000, 1115\r\n청량리: 30, 65, 165, 165-3, 330-1\r\n           765,1330,1330-1\r\n경춘선 금곡역에서 3.5km\r\n마을버스 64번 환승시 앞마당까지", "traffowner": "네비게이션 : \r\n주소검색시 : 남양주시 진건읍 송능2리 304-14\r\n명칭검색시 : 봉인사(진건읍 송능리)", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 100, "waitroom": true, "handicap": true}, "lastUpdateDate": "2022/10/17", "priceitemdate": "2022/10/17"}'::jsonb, '{"hallRent": [{"item": "개인단", "category": "개인단", "subcategory": null, "rentcontent": "사용료:250만원~600만원/ 관리비 년 5만원", "facilityamt": 2700000, "facilityamtm": "2,700,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "부부단", "category": "부부단", "subcategory": null, "rentcontent": "사용료:450만원~1100만원/ 관리비 년 5만원", "facilityamt": 4700000, "facilityamtm": "4,700,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [{"item": "5년", "category": "기타", "subcategory": "-", "rentcontent": null, "facilityamt": 250000, "facilityamtm": "250,000", "sale": true, "saleNm": "판매"}, {"item": "10년", "category": "기타", "subcategory": "-", "rentcontent": null, "facilityamt": 500000, "facilityamtm": "500,000", "sale": true, "saleNm": "판매"}, {"item": "5년", "category": "기타", "subcategory": "-", "rentcontent": null, "facilityamt": 500000, "facilityamtm": "500,000", "sale": true, "saleNm": "판매"}, {"item": "10년", "category": "기타", "subcategory": "-", "rentcontent": null, "facilityamt": 1000000, "facilityamtm": "1,000,000", "sale": true, "saleNm": "판매"}], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "추모관 전경", "filename": "납골당전경바닥.jpg", "fileurl": "/BCUser/facilitypic/1331258839498_7000000527_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1331258839498_7000000527_0.jpg", "filesize": 181836}, {"fileorder": 2, "filetitle": "추모관 내부", "filename": "IMG_9833.JPG", "fileurl": "/BCUser/facilitypic/1331258903614_7000000527_0.JPG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1331258903614_7000000527_0.JPG", "filesize": 4153554}, {"fileorder": 3, "filetitle": "추모관 제례단", "filename": "IMG_9899.JPG", "fileurl": "/BCUser/facilitypic/1331258956249_7000000527_0.JPG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1331258956249_7000000527_0.JPG", "filesize": 2796296}, {"fileorder": 4, "filetitle": "추모관 데크", "filename": "001.JPG", "fileurl": "/BCUser/facilitypic/1331259119870_7000000527_0.JPG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1331259119870_7000000527_0.JPG", "filesize": 2374607}, {"fileorder": 5, "filetitle": "추모관 식당", "filename": "식당.jpg", "fileurl": "/BCUser/facilitypic/1331259143193_7000000527_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1331259143193_7000000527_0.jpg", "filesize": 294882}, {"fileorder": 6, "filetitle": "추모관 메인", "filename": "PB090862 수정본.JPG", "fileurl": "/BCUser/facilitypic/1334215410982_7000000527_0.JPG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1334215410982_7000000527_0.JPG", "filesize": 151753}]'::jsonb, '[{"facilitycd": "7000000527", "facilitygroupcd": "TBC0700003", "companyname": "재단법인청림공원(봉안당)", "type": "CharnelDet", "fulladdress": "경기도 남양주시 진건읍 사릉로156번길 295 (송능리, 봉인사)", "telephone": "031-527-5678", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1331258839498_7000000527_0.jpg"}, {"facilitycd": "7000001891", "facilitygroupcd": "TBC0700003", "companyname": "재단법인청림공원(봉안탑)", "type": "CharnelDet", "fulladdress": "경기도 남양주시 진건읍 사릉로156번길 295 (송능리, 봉인사)", "telephone": "031-527-5678", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/7000001891/1707874127804.PNG"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
