INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000002528', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "용산성당 베다니아의집", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "정순택", "companyno": "695-82-00503", "telephone": "02-719-3301", "faxnum": null, "homepage": "www.yongsanch.or.kr", "fulladdress": "서울특별시 용산구 효창원로15길 37 (산천동, 용산천주교회)", "zipcd": "04357", "latitude": null, "longitude": null, "sidonm": "서울특별시 용산구", "orgid": "3020000", "orgidnm": "서울특별시 용산구", "firstcharnelcnt": 15, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": null, "traffpublic": "■ 버스이용시   \n\nØ 마포, 공덕동, 도화동 방향 \n  ○ 마포역 하차 : 160, 260, 261 263, 600 7013, 7016 ≫ 도보 10분\n  ○ 공덕동 하차 : 163, 261, 263, 604, 1711              ≫  도보 10분\n  ○ 용마루고개  : 110A,B(용마루고개), 163(서울대 동창회관), 730(용마루고개), 163(서울대 동창회관)         \n\n     ≫  도보 7분\n\nØ 용산, 원효로, 용문동, 효창동 방향\n  ○ 용문동 : 0016(용문시장), 1711(용문시장), 0211(용산구청 앞, 전자상가 입구) ≫  도보10분\n  ○ 원효로 : 7011(원효로 1-2가, 용문동), 7016(원효로 3-4가, 산천동), 0015(원효로 3가),\n                  262(원효로 3-4가), 162(원효로 3가),503(원효로 3가), 405(원효로 3-4가, 산천동)\n\n                  ≫ 도보 10분\n\n \n\n■ 지하철 이용시\n\nØ 마포, 공덕동 방향   \n  ○ 5호선 : 마포역(3번 출구) 공덕역(8번 출구)\n  ○ 6호선, 공항철도, 경의선 : 공덕역(9,10번 출구) ≫ 도보 10분\n      ※ 마포역 하차시 가든호텔 뒤편 샛별문구 앞에서 마을버스 02번\n      ※ 공덕역 하차시 S오일 본사 앞 정류소(7,8번 출구) 또는 10번 출구 맞은편에서\n\n         마을버스 마포 02번으로 환승", "traffowner": "자동차 네비게이션으로 ''용산성당'' 검색", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 30, "waitroom": false, "handicap": false}, "lastUpdateDate": "2025/09/20", "priceitemdate": "2025/09/20"}'::jsonb, '{"hallRent": [{"item": "봉안단", "category": "개인단", "subcategory": null, "rentcontent": "300*300(3,4,5단)", "