INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000013', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "광명메모리얼파크", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "경기도 광명시", "companyno": "133-83-00244", "telephone": "02-2610-7380", "faxnum": null, "homepage": "www.gmuc.co.kr/user/conn/memoFaq.do?pmn=23000", "fulladdress": "경기도 광명시 자경로 153 (일직동)", "zipcd": "423090", "latitude": "37.431528", "longitude": "126.8922823", "sidonm": "경기도 광명시", "orgid": "3900000", "orgidnm": "경기도 광명시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 2, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": null, "traffpublic": "일번버스\r\n3-1(삼영운수), 11-2(화영운수), 22(화영운수), 5633(범일운수)\r\n→기아자동차 기아사거리 정류소에서 하차, 도보로 1km\r\n\r\n마을버스\r\n1-3, 금천04\r\n →메모리얼파크 정류장에서 하차, 도보로 1km\r\n88(메모리얼파크 입구에서 하차, 도보로 500m)\r\n\r\n지하철 이용시\r\n 지하철 1호선 석수역 하차 2km\r\n", "traffowner": "제2 경인고속도로 이용시\r\n 제 2경인고속도로 110번 고속도로 석수ic에서 우측고속도로 출구 →경수산업도로 1번국도 석수ic에서 서울방면으로 좌회전 →기아대교 광명역(고속철도) 방면으로 좌회전 →기아자동차 기아사거리 좌회전 →광명메모리얼파크\r\n\r\n서해안고속도로 이용시\r\n 서해안 고속도로 15번 고속도로 광명역ic에서 고속도로 출구 →광명역(고속철도)방면 서독터널 방향으로 직진 →양지사거리 우회전 →덕안사거리 경유 →소하사거리 우회전 →기아자동차 기아사거리 우회전 →광명메모리얼파크", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 76, "waitroom": true, "handicap": false}, "lastUpdateDate": "2023/11/23", "priceitemdate": "2023/11/23"}'::jsonb, '{"hallRent": [{"item": "개인단(관내)", "category": "개인단", "subcategory": null, "rentcontent": "1회 15년, 2회 연장가능(총45년)", "facilityamt": 750000, "facilityamtm": "750,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "개인단(관외)", "category": "개인단", "subcategory": null, "rentcontent": "1회 15년, 2회 연장가능(총45년)", "facilityamt": 1500000, "facility