INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000690', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "공주나래원 봉안당", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "충청남도 공주시", "companyno": "307-83-03046", "telephone": "041-840-8980", "faxnum": null, "homepage": "https://www.gongju.go.kr/naraewon/index.do", "fulladdress": "충청남도 공주시 이인면 삼배실길 70 (운암리, 나래원)", "zipcd": "32604", "latitude": "36.3994367", "longitude": "127.0448625", "sidonm": "충청남도 공주시", "orgid": "4500000", "orgidnm": "충청남도 공주시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[이용조건]\r\n- 제한없이 이용가능\r\n- 사망일 현재 공주시에 주민등록한 자 이거나 직계존비속 또는 배우자가 1년이상 주민등록자인 경우 관내 요금 적용\r\n\r\n[감면대상]\r\n- 해당사항없음", "traffpublic": "경부고속도로 → 천안논산고속도로 → 공주IC로 나와서 백제큰길 부여방면", "traffowner": "서울 : 경부고속도로 → 천안논산고속도로 → 공주IC로 나와서 백제큰길 부여방면</br>\r\n인천 : 서해안고속도로 → 서평택분기점 → 안성분기점 → 경부고속도로 → 천안논산고속도로 →공주IC로 나와서 국도이용(약 1시간 30분 소요)</br>\r\n논산천안고속도로(32.8km)  → 경부고속도로(16.8km)  → 평택제천고속도로(44.0km)  → 중원대로(21.5km)</br>", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 297, "waitroom": true, "handicap": true}, "lastUpdateDate": "2022/01/07", "priceitemdate": "2022/01/07"}'::jsonb, '{"hallRent": [{"item": "일반(관내)", "category": "개인단", "subcategory": null, "rentcontent": "1위, 30년", "facilityamt": 1000000, "facilityamtm": "1,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반(관외)", "category": "개인단", "subcategory": null, "rentcontent": "1위, 30년", "facilityamt": 2000000, "facilityamtm": "2,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "부부(관내)", "category": "부부단", "subcategory": null, "