INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000232', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "함안군공설봉안당", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "함안군수", "companyno": null, "telephone": "055-585-5114", "faxnum": "055-584-2102", "homepage": null, "fulladdress": "경상남도 함안군 군북면 하림2길 181-78 (하림리, 마애사)", "zipcd": "52068", "latitude": "35.2443148", "longitude": "128.3026714", "sidonm": "경상남도 함안군", "orgid": "5400000", "orgidnm": "경상남도 함안군", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 3, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[함안군공설봉안당 이용안내]\n - 접수 및 수납 : 함안군 주민복지과 주민복지계(055-580-2351~4) \n\n[이용조건]\n① 함안군에 주소(주민등록법상 주소)를 둔 사망자\n② 함안군에 주소를 둔 자의 배우자 및 직계존비속 중 사망자\n ※ ①항,②항의 주소란, 사망한 날을 기준으로 1개월전부터 계속해서 함안군에 주소를 둔 경우\n   단, 거주지에 따라 이용료 차등\n\n[전액 감면대상]\n-「국가보훈 기본법」에 따른 희생 · 공헌자 및 그 배우자\n-「국민기초생활보장법」에 따른  생계급여 및 수급자\n-「함안군 의로운 군민 등에 대한 예우 및 지원에 관한 조례」에 따른 의사상자\n- 사회복지시설 수용자 중 무연고자", "traffpublic": "\r\n", "traffowner": "함안대로(0.6km)  → 가야로(0.3km)  → 함마대로(3.7km)", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": null, "waitroom": false, "handicap": false}, "lastUpdateDate": "2020/10/24", "priceitemdate": "2020/10/24"}'::jsonb, '{"hallRent": [{"item": "일반(관내)", "category": "개인단", "subcategory": null, "rentcontent": "최초 15년 사용료", "facilityamt": 200000, "facilityamtm": "200,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반(관외)", "category": "개인단", "subcategory": null, "rentcontent": "최초 15년 사용료", "facilityamt": 600000, "facilityamtm": "600,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "일반(관내)", "category": "개인단", "subcategory": null, "rent