INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000591', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "창원시립상복공원 제1봉안당", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "허환구", "companyno": "609-82-07688", "telephone": "055-712-0925", "faxnum": null, "homepage": "https://www.cwsisul.or.kr/_sangbok/_sub02/sub02_03_01.html", "fulladdress": "경상남도 창원시 성산구 공단로474번길 160 (상복동, 창원시립상복공원)", "zipcd": "51577", "latitude": "35.19185", "longitude": "128.66492", "sidonm": "경상남도 창원시 성산구", "orgid": "5270000", "orgidnm": "경상남도 창원시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 3, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "제1봉안당 : 26실:1층 12실(개인단:7실, 부부단:5실), 2층 14실\r\n제2봉안당 : 20실:1층 9실, 2층 11실(개인단:7실, 부부단:4실)\r\n\r\n제례실(실내) : 10개소 - 영정을 모시고 간단한 제와 분향을 하는 장소\r\n제레실(실외) :  5개소 - 영정을 모시고 간단한 제와 분향을 하는 장소\r\n\r\n헌화대 : 2개소\r\n\r\n봉안담 : 13담(야외)\r\n\r\n유택동산 : 37.39㎡\r\n\r\n\r\n◎ 전액감면(관내, 관외 전액감면) \r\n「국민기초생활보장법」에 따른 국민기초생활수급자 \r\n「독립유공자 예우에 관한 법률」 제4조에 따른 독립유공자와 그 배우자 \r\n「국가유공자 등 예우 및 지원에 관한 법률」 제4조제1항에 따른 국가유공자와 그 배우자 \r\n  국가보훈처에 등록된 6.25 및 월남전 참전용사 \r\n「참전유공자예우 및 단체설립에 관한 법률」제3조에 따른 참전군인 \r\n\r\n\r\n\r\n◎ 50% 감면(관내, 관외 구분하여 50% 감면) \r\n「독립유공자 예우에 관한 법률」 제4조와 제5에 따른 독립유공자의 유족 \r\n「국가유공자 등 예우 및 지원에 관한 법률」 제4조제1항과 제5조에 따른 국가유공자의 유족 \r\n  국가보훈처에 등록된 6.25 및 월남전 참전용사의 배우자 \r\n「창원시 장기기증 등록 장려에 관한 조례」에 따른 장기 기증자에 대한 봉안시설 사용료 \r\n", "traffpublic": "일반버스 : 150, 504번 → LG산전에서 하차 후 도보(40분) \r\n", "traffowner": "부산방면 : 남해고속도로 진입 →''장유''인터체인지(창원진입) → 창원터널 통과 \r\n광주, 진주방면 : 남해고속도로 → ''북창원''인터체인지 → 창원방면 \r\n서울/대전방면 : 경부고속도로 또는 중부고속도로 → 구마고속도로 →남해고속도로 → ''동마산''인터체인지(마산진입) \r\n통영, 고성지역 : 마창대교 통과 → 양곡IC에서 시청방향 → 신촌광장 삼거리에서 우회전 → 이후 상복사거리에서 우회전 \r\n", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 450, "waitroom": true, "handicap": true}, "lastUpdateDate": "2021/09/22", "priceitemdate": "2021/09/22"}'::jsonb, '{"hallRent": [{"item": "유연유골(관내)", "category": "기타", "subcategory": null, "rentcontent": "1구/15년", "facilityamt": 170000, "facilityamtm": "170,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "유연유골(관외)", "category": "기타", "subcategory": null, "rentcontent": "1구/15년", "facilityamt": 1000000, "facilityamtm": "1,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "무연유골(관내)", "category": "기타", "subcategory": null, "rentcontent": "1구/5년", "facilityamt": 45000, "facilityamtm": "45,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "무연분묘(관내)", "category": "기타", "subcategory": null, "rentcontent": "1구/10년", "facilityamt": 90000, "facilityamtm": "90,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [{"item": "제례실", "category": "기타", "subcategory": "-", "rentcontent": null, "facilityamt": 0, "facilityamtm": "0", "sale": true, "saleNm": "판매"}], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "봉안당 전경", "filename": "img04_01_01.jpg", "fileurl": "/BCUser/facilitypic/1346737425297_7000000591_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1346737425297_7000000591_0.jpg", "filesize": 66837}, {"fileorder": 2, "filetitle": "봉안당 실내제례실", "filename": "img04_01_02.jpg", "fileurl": "/BCUser/facilitypic/1346737435817_7000000591_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1346737435817_7000000591_0.jpg", "filesize": 56440}, {"fileorder": 3, "filetitle": "봉안당 로비", "filename": "img04_01_03.jpg", "fileurl": "/BCUser/facilitypic/1346737449241_7000000591_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1346737449241_7000000591_0.jpg", "filesize": 67016}, {"fileorder": 4, "filetitle": "봉안당 헌화대", "filename": "img04_01_07.jpg", "fileurl":