INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001338', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "하늘공원(부곡동공설공원묘지)", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "윤화섭", "companyno": "134-83-00039", "telephone": "031-481-3257", "faxnum": null, "homepage": null, "fulladdress": "경기도 안산시 상록구 수인로 1824 (부곡동)", "zipcd": "15301", "latitude": "37.3463951", "longitude": "126.8706288", "sidonm": "경기도 안산시", "orgid": "3930000", "orgidnm": "경기도 안산시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 2, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "■ 안산시 공설 장사시설 사용자격  \r\n- 사망자가 사망 당시 안산시에 6개월이상 계속 주민등록을 두고 거주한 경우\r\n- 관외사망자로서 그 배우자가 이미 안산시 공설장사시설에 안치되어 합장하는 경우\r\n- 시에 6개월 이상 계속하여 주민등록을 두고 거주한 주민의 배우자 또는 부모가      관외에서 사망한 경우\r\n- 관내에서 유골을 개장한 경우\r\n- 관외개장유골로 사용허가를 신청한 연고자(배우자,직계자녀)가 신청당시 시에 6개월    이상 계속하여 주민등록을 두고 거주한 경우\r\n- 관외 봉안시설에서 사용중인 유골로 사용허가를 신청한 연고자(배우자,직계자녀)가     신청당시에 안산시에 10년이상 계속하여 주민등록을 두고 거주한 경우\r\n\r\n■ 감면대상  \r\n-사망자 또는 연고자 중 최우선 순위자로서「국민기초생활보장법」에 따른 생계,의료급여 및 보장시설 수급자\r\n-사망자로서「안산시 국가보훈대상자등 예우 및 지원에 관한 조례」제2조 제2호에 해당하는 자(유가족 제외)\r\n\r\n■ 기타 자세한 사항은  자치법규정보시스템(http://www.elis.go.kr)접속→안산시 장사시설 설치 및 운영조례 검색\r\n\r\n■ 사용료 참고사항 : 최초에는 사망자기준, 연장신청시 연고자 기준으로 관내/외 적용함", "traffpublic": null, "traffowner": null, "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 30, "waitroom": false, "handicap": false}, "lastUpdateDate": "2018/12/06", "priceitemdate": "2018/12/06"}'::jsonb, '{"hallRent": [{"item": "봉안 개인단(관내)", "category": "개인단", "subcategory": null, "rentcontent": "유골1구", "facilityamt": 367000, "facilityamtm": "367,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안 부부단(관내)", "categor