INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000077', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "남해추모누리 안락원", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "남해군", "companyno": "614-83-00743", "telephone": "055-860-3681", "faxnum": null, "homepage": "https://www.namhae.go.kr/depart/Index.do?c=DE0202010300", "fulladdress": "경상남도 남해군 서면 연죽로 46-77 (연죽리, 남해공설종합묘원추모누리)", "zipcd": "52411", "latitude": "34.8226109", "longitude": "127.8709945", "sidonm": "경상남도 남해군", "orgid": "5430000", "orgidnm": "경상남도 남해군", "firstcharnelcnt": 60, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[이용제한]\r\n- 군 관할구역 밖에서 각종 개발행위 등의 사유로 발굴된 무연분묘의 개장유골인 경우\r\n- 군 관할구역 밖의 의료기관 등에서 발생된 적출물 등\r\n- 그 밖에 군수가 사용을 제한할 필요가 있다고 인정하는 경우\r\n\r\n[전액 감면대상]\r\n- 「국민기초생활 보장법」에 따른 수급자는 전액 감면\r\n- 그 밖에 군수가 사용료의 감면이 필요하다고 인정하는 경우\r\n\r\n[반액 감면대상]\r\n- 「국가유공자 등 예우 및 지원에 관한 법률」에 따른 국가유공자\r\n- 「참전유공자예우 및 단체설립에 관한 법률」에 따른 참전유공자", "traffpublic": "남해-우물(대정.서상.정포.우...)(남해공용터미널) → 평현 정류장 하차 ", "traffowner": "남해대로(1.0km)  → 스포츠로(0.8km)  → 평현로124번길(0.7km)  → 평현로(0.6km) ", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 100, "waitroom": true, "handicap": true}, "lastUpdateDate": "2021/02/08", "priceitemdate": "2021/02/08"}'::jsonb, '{"hallRent": [{"item": "사용료", "category": "개인단", "subcategory": null, "rentcontent": "사용자격:남해군민 사용기간:30년 1회연장가능", "facilityamt": 160000, "facilityamtm": "160,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관리비", "category": "개인단", "subcategory": null, "rentcontent": "사용자격:남해군민 관리기간:30년 1회연장가능", "facilityamt": 300000, "facilityamtm": "300,000", "sale": true, "saleNm": "판매", "avgPric