INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000068', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "수원시연화장 추모의집", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "수원도시공사", "companyno": "124-82-11056", "telephone": "031-218-6524", "faxnum": null, "homepage": "https://www.suwonudc.co.kr/suwonyhj/mainPage.do", "fulladdress": "경기도 수원시 영통구 광교호수로 278 (하동, 수원시연화장)", "zipcd": "16511", "latitude": "37.2904662", "longitude": "127.0846006", "sidonm": "경기도 수원시 영통구", "orgid": "3740007", "orgidnm": "경기도 수원시 영통구", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 1, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "  - 2015. 4. 1일부터 수원시 장례식장이 새롭게 출발합니다 -\n\n  2015년 4월 1일부터 수원시 장례식장은 수원도시공사에서 운영합니다. \n \n  《이렇게 달라집니다》\n \n ○ 장례비용 절감으로 시민들의 부담이 경감됩니다.\n ○ [ 장례▶화장▶봉안 ] 통합운영으로 장례절차가 간편해 집니다. \n ○ 청렴경영, 고품격 서비스를 통해 시민들의 부담을 덜어드립니다.\n ○ 공정하고 투명하게 장례식장이 운영됩니다.\n ○ 각종 부조리 근절과 친절한 서비스로 시민 만족도가 향상됩니다. ", "traffpublic": "홈페이지 참조\n", "traffowner": "홈페이지 참조", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 400, "waitroom": false, "handicap": true}, "lastUpdateDate": "2022/05/26", "priceitemdate": "2022/05/26"}'::jsonb, '{"hallRent": [{"item": "관내", "category": "개인단", "subcategory": null, "rentcontent": "고인이 수원에 주민등록을 두고 1년이상 거주", "facilityamt": 800000, "facilityamtm": "800,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관외", "category": "개인단", "subcategory": null, "rentcontent": "고인의 직계가족이 수원에 주민등록을 두고 1년이상 거주", "facilityamt": 1300000, "facilityamtm": "1,300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관내", "category": "부부단", "subcategory": null, "rentcontent": "고인이 수원에 주민등록