INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000086', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "여수시 제1추모의 집", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "여수시장", "companyno": "417-83-00216", "telephone": "061-659-1795", "faxnum": "061-659-5889", "homepage": null, "fulladdress": "전라남도 여수시 소라면 의곡길 494 (봉두리, 영락공원)", "zipcd": "59608", "latitude": "34.831555", "longitude": "127.5804819", "sidonm": "전라남도 여수시", "orgid": "4810000", "orgidnm": "전라남도 여수시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 2, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[이용조건]\r\n- 일반 시민(관내에 주민등록을 두고 1년 이상 거주하고 있는 자)\r\n- 관내에 소재한 분묘에서 개장한 유골을 공설장사시설에 매장·화장 또는 봉안/자연장 하고자 하는 자\r\n- 관내에서 발생한 무연고 변사자\r\n- 특례자\r\n . 여수시에 주민등록을 두고 1년 미만 거주하고 있는 자\r\n . 여수시에 주민등록이 된 자의 2촌 이내 직계 존·비속 또는 배우자\r\n . 등록기준지가 여수시인 자\r\n . 여수시 관할구역 내에서 사망한 외국인\r\n\r\n[반액감면]\r\n-「국민기초생활 보장법」에 의한 수급자\r\n-「국가유공자 등 예우 및 지원에 관한 법률」에 의한 국가유공자\r\n-「재해구호법」에 의한 구호대상자\r\n-「여수시 헌혈 및 장기기증 등록 권장에 관한 조례」에 따른 장기 기증자\r\n-「의사상자 등 예우 및 지원에 관한 법률」제2조제4호의 의사상자, 「상훈법」에 따른 훈장 또는 포장을 받은 사람, 여수시민의 상 수상자 및 이에 준하는 사람 중 국가 또는 시 발전에 공로가 있다고 인정되는 사람\r\n- 여수시 관내에서 발생한 무연고 변사자", "traffpublic": "- 시내버스(36번) 11회 운행\r\n- 출발지 : 미평(차고지)\r\n- 도착지 : 봉두상의곡", "traffowner": "- 국도17호선(자동차전용도로)\r\n  율촌교차로→율촌봉두마을→연화마을입구→봉두상의곡→영락공원\r\n- 국도17호선\r\n  대포사거리→봉두상의곡→영락공원\r\n- 지방도863호선\r\n  율촌상봉삼거리→연화마을입구→봉두상의곡→영락공원", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 457, "waitroom": true, "handicap": true}, "lastUpdateDate": "2016/07/19", "priceitemdate": "2016/07/19"}'::jsonb, '{"hallRent": [{"item": "사용료 및 관리비", "category": "개인단", "subcategory": null, "rentcontent": "최초 15년(관내)", "facilityamt": 120000, "facilityamtm": "120,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료 및 관리비 ", "category": "부부단", "subcategory": null, "rentcontent": "최초 15년(관내)", "facilityamt": 240000, "facilityamtm": "240,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료 및 관리비", "category": "개인단", "subcategory": null, "rentcontent": "최초 15년(관내) 국가유공자 및 수급자", "facilityamt": 60000, "facilityamtm": "60,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료 및 관리비", "category": "개인단", "subcategory": null, "rentcontent": "최초 15년(특례)", "facilityamt": 500000, "facilityamtm": "500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": null, "filename": "제1봉안당 전경사진.jpg", "fileurl": "/BCUser/facilitypic/1468895056066_3000000086_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1468895056066_3000000086_0.jpg", "filesize": 499639}, {"fileorder": 2, "filetitle": "제1봉안당", "filename": "제1봉안당 전경사진.jpg", "fileurl": "/BCUser/facilitypic/1468895205460_3000000086_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1468895205460_3000000086_0.jpg", "filesize": 499639}]'::jsonb, '[{"facilitycd": "2000000312", "facilitygroupcd": "TBC0700002", "companyname": "여수시공설묘지공원", "type": "CemeteryDet", "fulladdress": "전라남도 여수시 소라면 봉두리 산190 ", "telephone": "061-685-8100", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1465867829184_2000000312_0.jpg"}, {"facilitycd": "3000000086", "facilitygroupcd": "TBC0700003", "companyname": "여수시 제1추모의 집", "type": "CharnelDet", "fulladdress": "전라남도 여수시 소라면 의곡길 494 (봉두리, 영락공원)", "telephone": "061-659-1795", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1468895056066_3000000086_0.jpg"}, {"facilitycd": "3000000206", "facilitygroupcd": "TBC0700003", "companyname": "여수시 제2추모의 집", "type": "CharnelDet", "fulladdress": "전라남도 여수시 소라면 의곡길 494 (봉두리, 영락공원)", "teleph