INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000047', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "무주추모의집(봉안)", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "무주군수", "companyno": "406-83-01118", "telephone": "063-322-2302", "faxnum": null, "homepage": null, "fulladdress": "전라북도 무주군 무주읍 괴목로 1359-72 (당산리)", "zipcd": "55513", "latitude": "36.0000467", "longitude": "127.6825412", "sidonm": "전북특별자치도 무주군", "orgid": "4740000", "orgidnm": "전북특별자치도 무주군", "firstcharnelcnt": 15, "renewyears": 10, "renewcount": 4, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[이용조건]\r\n- 제한없이 이용가능\r\n- 단, 거주지에 따라 이용료 차등\r\n\r\n[전액 감면대상]\r\n-「국민기초생활 보장법」제2조제2호에 따른 관내 수급자\r\n-「국가유공자 등 예우 및 지원에 관한 법률」제4조에 따른 관내 국가유공자\r\n-「독립유공자 예우에 관한 법률」제4조에 따른 관내 독립유공자\r\n-「5·18민주유공자 예우에 관한 법률」제4조에 따른 관내 5·18민주유공자\r\n- 천재·지변의 사유 등으로 사용료를 납부할 능력이 없다고 인정되는 사람\r\n\r\n[반액 감면대상]\r\n- 「재해구호법」제2조제1호의 관내 이재민\r\n- 「국민기초생활 보장법」제2조제11호에 따른 관내 차상위계층\r\n- 그 밖에 군수가 공익상 필요하다고 인정하는 사람\r\n\r\nㅁ사용료(15년기준)\r\n - 관내 : 150,000원\r\n - 관외 : 400,000원\r\nㅁ사용연장 10년단위로 4회 연장 가능\r\n - 관내 : 150,000원\r\n - 관외 : 400,000원", "traffpublic": "무주터미널->무주(상조.치목)(순환버스승강장) → 유속 정류장 하차 -> 무주추모의집까지 약 600m이동", "traffowner": "무주터미널 ->당산강변로(1.6km)  → 괴목로(0.8km) ", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": null, "waitroom": false, "handicap": false}, "lastUpdateDate": "2016/06/22", "priceitemdate": "2016/06/22"}'::jsonb, '{"hallRent": [{"item": "추모의 집 사용료(관내)", "category": "기타", "subcategory": null, "rentcontent": "최초 15년", "facilityamt": 150000, "facilityamtm": "150,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "추모의 집 사용료(관외)", "category": "기타", "subcategory": null, "rentcontent": "최초 15년", "facilityamt": 400000, "facilityamtm": "400,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료", "category": "개인단", "subcategory": null, "rentcontent": "관내", "facilityamt": 150000, "facilityamtm": "150,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료", "category": "개인단", "subcategory": null, "rentcontent": "관외", "facilityamt": 400000, "facilityamtm": "400,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "1", "filename": "무주추모의집.PNG", "fileurl": "/BCUser/facilitypic/3000000047/1724811096742.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000047/1724811096742.PNG", "filesize": 356013}, {"fileorder": 2, "filetitle": "1", "filename": "e하늘-팝업.jpg", "fileurl": "/BCUser/facilitypic/1468308166530_3000000047_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1468308166530_3000000047_0.jpg", "filesize": 35903}, {"fileorder": 3, "filetitle": "1", "filename": "popip13.jpg", "fileurl": "/BCUser/facilitypic/1468308222135_3000000047_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1468308222135_3000000047_0.jpg", "filesize": 55696}, {"fileorder": 4, "filetitle": "개인단전경", "filename": "개인단 전경.jpg", "fileurl": "/BCUser/facilitypic/3000000047/1468308588829.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000047/1468308588829.jpg", "filesize": 2414406}, {"fileorder": 5, "filetitle": "개인단", "filename": "개인단.jpg", "fileurl": "/BCUser/facilitypic/3000000047/1468308611533.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000047/1468308611533.jpg", "filesize": 2351461}, {"fileorder": 6, "filetitle": "복도", "filename": "복도.jpg", "fileurl": "/BCUser/facilitypic/3000000047/1468308624872.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000047/1468308624872.jpg", "filesize": 2062609}, {"