"subcategory": null, "rentcontent": "관외(15년)", "facilityamt": 1000000, "facilityamtm": "1,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료(무연고)", "category": "기타", "subcategory": null, "rentcontent": "관내(5년)", "facilityamt": 100000, "facilityamtm": "100,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "천안추모공원 봉안당", "filename": "천안추모공원 봉안당.PNG", "fileurl": "/BCUser/facilitypic/3000000092/1707875554011.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000092/1707875554011.PNG", "filesize": 1173009}]'::jsonb, '[{"facilitycd": "3000000092", "facilitygroupcd": "TBC0700003", "companyname": "천안추모공원 봉안당", "type": "CharnelDet", "fulladdress": "충청남도 천안시 동남구 광덕면 밤나무골길 38 (원덕리)", "telephone": "041-529-5142", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000092/1707875554011.PNG"}, {"facilitycd": "4000000051", "facilitygroupcd": "TBC0700004", "companyname": "천안추모공원", "type": "CrematoriumDet", "fulladdress": "충청남도 천안시 동남구 광덕면 밤나무골길 38 (원덕리, 천안추모공원)", "telephone": "041-529-5141", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1464324710671_4000000051_0.jpg"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001779', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "나주납골당", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "이용재", "companyno": "412-90-36871", "telephone": "061-334-0048", "faxnum": "061-332-6330", "homepage": "www.내영사.kr", "fulladdress": "전라남도 나주시 내영산1길 12-3 (삼영동, 내영사)", "zipcd": "58263", "latitude": "35.0050008", "longitude": "126.6996173", "sidonm": "전라남도 나주시", "orgid": "4830000", "orgidnm": "전라남도 나주시", "firstcharnelcnt": 99, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "안녕하십니까? \r\n\r\n삼가 고인의 명복을 빕니다.\r\n\r\n장묘문화에 많은 변화가 생기고 있습니다. 예전에는 매장 위주이었으나 요즘에는 화장위주로 바뀌는 것을 보니 시대와 함께 장묘문화도 바뀌는가 봅니다. 부처님 당시 인도에서도 매장 보다는 화장이 더 수승한 장례방법이었다고 했습니다. 화장할 나무를 살 돈이 없는 사람들이 매장을 하였고 반면에 여유 있는 사람들이 화장을 하였다고 하니 우리나라의 현실과 정 반대 이었음을 알 수 있습니다. \r\n\r\n내영사 ( www.내영사.kr ) 는 전라도의 중심지인 나주의 역사 특히 영산강유역의 문화와 함께 긴 세월을 지냈고 현 사회에서 내영사(內榮寺)의 사명을 살펴보면 󰡒안으로 영화가 있다.󰡓이것은 부유한사람, 권력이 있는 사람, 명예가 있는 사람 또한 그렇지 않는 사람 모두가 원하 는 내용이겠지요? 그래서 현(사바)세계에서는 편안한 삶을 갖는 것이며 사후(죽음)세계에서는 영화는 극락입니다.\r\n오래전부터 내영사는 사는 자와 가는 자의 길을 닦는 도량입니다. \r\n\r\n불교에서는 지은 업에 따라 3계를 윤회 한다고 합니다. 인생이 단 한번만 살다 가는 것이 아니고 살면서 지은 업에 따라 새롭게 태어나기를 수 억겁동안 반복하는 것 입이다. 궁극적으로는 이러한 윤회의 고리를 끊어 버리고 해탈 한다면 다시는 생을 반복 하지 않을 것입니다. 그러나 무명에서 헤어 나오지 못하고 되는 대로 살다간 사람들에게는 죽어서 어떤 과보를 받을지 두렵지 않을 수 없다. 이승에서 탐, 진, 치에 물들어 몸과 입과 마음으로 잔뜩 업만 짓고 간 사람들도 있을 것이고 반면에 보시하고 지계하며 보살행을 하다 간 사람들도 있을 것입니다. 모두다 자신이 지은 업을 짊어지고 또 다른 세계로 가는 것입니다. \r\n\r\n비록 업만 잔뜩 지고 다른 세상으로 갖지만 좀 더 좋은 곳에서 태어나기를 바라는 마음에서 법당에 영가를 모시는 것이고 법당에 모셔진 영가들은 몸만 없을 뿐이지 식은 남아 있어서 아침저녁으로 예불문을 듣고 또 좋은 법문과 경전을 들을 수 있다고 한다. 사람이 죽으면 식이 9배나 각성이 되어서 그 어려운 경전내용도 다 이해 할 수 있다고 합니다. 이렇게 죽어서도 부처님과 함께 하여 불국토에 태어나기를 바라는 마음으로 우리는 함께 할 것입니다.\r\n\r\n함께 하는 마음이 고인의 명복을 빌어 봅니다. 성불하십시오.\r\n\r\n                                    내영사 주지 만허 합장", "traffpublic": "※ 광주에서 한시간, 나주 전 지역에서 10분 거리\r\n    영산포삼거리 하차 운전면허시험장으로 보도를 이용 약20분 ~ 30분 거리\r\n※ 풍수지리사상으로 유명한 도선대사가 세우신 명당자리\r\n※ 삼한지테마파크, 금성관, 목사내아, 영산강황포돛배, 골든스파리조트, 골든레이크골프장, 반남면대안리, 덕산리, 신촌리 고분군, 복암리고분군, 만봉리석조여래입상, 영산포등대, 완사천, 미천서원", "traffowner": "※ 나주시청을 경유하여 영산포삼거리에서 운전면허시험장쪽으로 이동하여 운전면허시험장사거리에서 약100m 직진하여 우회전 하면 우측에 있는 천년고찰 내영사 입니다.", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 5, "waitroom": true, "handicap": false}, "lastUpdateDate": "2025/12/15", "priceitemdate": "2025/12/15"}'::jsonb, '{"hallRent": [{"item": "단기(15년)", "category": "개인단", "subcategory": null, "rentcontent": "관리비 미포함(1년30,000원)", "facilityamt": 1500000, "facilityamtm": "1,500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "영구", "category": "개인단", "subcategory": null, "rentcontent": "관리비 미포함(1년30,000원)", "facilityamt": 4000000, "facilityamtm": "4,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "단기(15년)", "category": "부부단", "subcategory": null, "rentcontent": "관리비 미포함(1년30,000원)", "facilityamt": 3000000, "facilityamtm": "3,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "영구", "category": "부부단", "subcategory": null, "rentcontent": "관리비 미포함(1년30,000원)", "facilityamt": 8000000, "facilityamtm": "8,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "미륵부처님", "filename": "1558.jpg", "fileurl": "/BCUser/facilitypic/1599797476447_7000001779_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1599797476447_7000001779_0.jpg", "filesize": 4355065}, {"fileorder": 2, "filetitle": "나주납골당 외부사진", "filename": "1559.jpg", "fileurl": "/BCUser/facilitypic/1599797549620_7000001779_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1599797549620_7000001779_0.jpg", "filesize": 3671386}, {"fileorder": 3, "filetitle": "나주납골당 내부사진", "filename": "1560.jpg", "fileurl": "/BCUser/facilitypic/1599797641688_7000001779_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1599797641688_7000001779_0.jpg", "filesize": 4370567}, {"fileorder": 4, "filetitle": "나주납골당 내부사진", "filename": "1561.jpg", "fileurl": "/BCUser/facilitypic/1599797721500_7000001779_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1599797721500_7000001779_0.jpg", "filesize": 5154930}]'::jsonb, '[{"facilitycd": "7000001779", "facilitygroupcd": "TBC0700003", "companyname": "나주납골당", "type": "CharnelDet", "fulladdress": "전라남도 나주시 내영산1길 12-3 (삼영동, 내영사)", "telephone": "061-334-0048", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1599797476447_7000001779_0.jpg"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000125', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "전주효자공원봉안당", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "전주시시설관리공단", "companyno": "418-82-06007", "telephone": "063-239-2690", "faxnum": null, "homepage": "https://www.jjss.or.kr/index.9is?contentUid=ff8080816c5f9de6016cb28f27280028", "fulladdress": "전라북도 전주시 완산구 콩쥐팥쥐로 1705-138 (효자동3가, 전주승화원)", "zipcd": "54878", "latitude": "35.8244584", "longitude": "127.0892191", "sidonm": "전북특별자치도 전주시 완산구", "orgid": "4640000", "orgidnm": "전북특별자치도 전주시", "firstcharnelcnt": 15, "renewyears": 15, "renewcount": 1, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[사용자격]\r\n- 사망일 기준 6개월 전부터 시 및 완주군에 주소를 둔 유연고 유골\r\n- (시장이 필요하다고 인정한 때) 무연고 유골\r\n* 개장유골은 제외\r\n* 부부 중 한 명만 사용자격을 갖추면 부부장 가능(부부임을 증명하는 서류 제출)\r\n\r\n[봉안시설 구분]\r\n- 효자공원봉안당(공설봉안당) : 건축물 실내에 안치 / 개인단\r\n- 효자공원봉안원(공설봉안담) : 벽과 담 형태의 구조물에 안치 / 개인단 및 부부단\r\n\r\n[사용료 반환기준]\r\n- ''5년 이내''에 중도 반납하는 경우 잔여기간에 대한 사용료 반환처리\r\n- 봉안기간별 반환비율 : 1년 이내 50%, 2년 이내 40%, 3년 이내 30%, 4년 이내 20%, 5년 이내 10%", "traffpublic": "72(전주역.지방행정연수원.이...)(시외버스터미널) → 은화학교 정류장 하차</br>\r\n3-2(금암1동사무소) → 신시가지서부파출소 정류장 하차</br>\r\n119(농협공판장.전주대)(거성고속맨션.자원봉사센) → 전주대경륜장 정류장 하차", "traffowner": "온고을로(1.4km)  → 홍산로(0.7km)  → 황강서원로(0.8km)", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 10, "waitroom": true, "handicap": true}, "lastUpdateDate": "2018/03/19", "priceitemdate": "2018/03/19"}'::jsonb, '{"hallRent": [{"item": "봉안 사용료", "category": "개인단", "subcategory": null, "rentcontent": "개인단", "facilityamt": 225000, "facilityamtm": "225,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안 사용료", "cat