INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000198', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "경신하늘뜰공원 봉안당", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "경기도 양주시", "companyno": null, "telephone": "031-861-5791", "faxnum": null, "homepage": "https://changucchin.yangju.go.kr/www/contents.do?key=503", "fulladdress": "경기도 양주시 남면 화합로430번길 98(경신리, 경신하늘뜰공원)", "zipcd": "11413", "latitude": "37.8615562", "longitude": "126.9775963", "sidonm": "경기도 양주시", "orgid": "5590000", "orgidnm": "경기도 양주시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "관내</br>\r\n사망자가 사망당시 양주시에 주민등록상의 주소를 두고 1년 이상 거주한 경우</br>\r\n시에 설치된 묘지에서 개장된 유골의 경우 </br>\r\n</br>\r\n관외</br>\r\n시 외의 지역에 거주하는 사람이 사망시 배우자가 기존의 묘지 및 봉안당에 안치되어 있거나 자연장 되어있는 경우</br>\r\n관외 거주하는 사람이 사망시 관내 거주자인 연고자가 안치하거나 자연장 하는 경우</br>\r\n관외지역에 설치된 묘지에서 개장된 유골 및 봉안당에 안치된 유골을 관내 거주자인 연고자가 안치하거나 \r\n자연장 하는 경우</br>\r\n관내에 주민등록을 두고 3년 이상 계속하여 거주한 사실이 있는 경우</br>\r\n(연고자는 망자의 부모 또는 자 및 배우자에 한하며 양주시에 주민등록상의 주소를 두고 1년 이상 거주한 경우이어야 함)</br>", "traffpublic": "1호선 양주역 하차→양주시청 방면 버스(일반35,133/마을3-5,3-6,51)→광적면 행정복지센터, 가래비시장 하차\r\n→하나로마트 방면 버스승차(마을16,16-1)→경신하늘뜰공원 앞 하차", "traffowner": "부흥로(6.4km)  → 백은로(0.8km)  → 삼일로(4.4km) ", "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 10, "waitroom": true, "handicap": true}, "lastUpdateDate": "2021/01/04", "priceitemdate": "2021/01/04"}'::jsonb, '{"hallRent": [{"item": "개인단(관내)", "category": "개인단", "subcategory": null, "rentcontent": "사용기간:15년 1회 연장가능", "facilityamt": 500000, "facilityamtm": "500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "개인단(관외)", "category": "개인단", "s