INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000003004', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "(재)신어공원추모관", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "현조희", "companyno": "264-82-00783", "telephone": "055-329-4844", "faxnum": "055-329-4853", "homepage": "wwwsineoparkcokr ", "fulladdress": "경상남도 김해시 상동면 소락로 23 신어공원추모관", "zipcd": "50805", "latitude": null, "longitude": null, "sidonm": "경상남도 김해시", "orgid": "5350000", "orgidnm": "경상남도 김해시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "부산-경남 교통의 중심에 위치한 신어공원추모관에서 품위있는 당신에게 특별한 영혼의 쉼터를 선물합니다.\n모두가 각자의 삶에서 언젠가는 맞이하게 되는 죽음, 한분 한분 소중한 삶을 영위하신 만큼 \n품격있는 곳에서 쉬기를 바라는 마음으로 안락하고 격조높은 추모관에서 소중히 모시겠습니다.\n", "traffpublic": "<무료 셔틀버스 1호선, 2호선 운행>\n\n노선 : 양산, 노포, 동래, 구포, 대저, 사하, 사상, 김해 등\n*자세한 노선은 공지사항 및 블로그 참조\n\n<시내버스 이용시>\n-부산김해 경전철 ''봉황역''에서 시내버스(상동1번) 이용\n-인제대학교 정문에서 시내버스(상동1번) 이용", "traffowner": null, "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 450, "waitroom": false, "handicap": false}, "lastUpdateDate": "2026/01/07", "priceitemdate": "2026/01/07"}'::jsonb, '{"hallRent": [{"item": "개방형 (유리)", "category": "개인단", "subcategory": null, "rentcontent": "1,000,000원부터 7,000,000원", "facilityamt": 1000000, "facilityamtm": "1,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "개방형 (유리)", "category": "부부단", "subcategory": null, "rentcontent": "2,000,000원부터 14,000,000원", "facilityamt": 2000000, "facilityamtm": "2,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "폐쇄형 (옥문형)", "category": "개인단", "subcategory": null, "rentcontent": "1,000,000원부터 4,000,000원