INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000927', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "대한불교조계종 신흥사", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "신흥사", "companyno": "558-82-64590", "telephone": "061-554-2634", "faxnum": null, "homepage": "www.sinheungsa.net ", "fulladdress": "전라남도 완도군 완도읍 청해진남로 101-1 (군내리, 신흥사)", "zipcd": "59124", "latitude": "34.3167159", "longitude": "126.7455808", "sidonm": "전라남도 완도군", "orgid": "4990000", "orgidnm": "전라남도 완도군", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "영구보관  350만원 \r\n관리비   년 6만원\r\n1년에 3번 (정월초하루, 추석, 백중) 합동제사", "traffpublic": " 고속버스 : 서울강남, 동서울, 상봉터미널에서 운행 \r\n 직행버스 : 광주, 부산, 목포, 강진, 영암에서 완도행 운행 \r\n 철도여행 : 호남선 이용 → 송정리, 나주, 목포, 광주역 → 완도행 버스 탑승 \r\n※ 완도터미널에서 택시로 5분 거리 / 도보 30분 \r\n", "traffowner": " 경부고속도로(호남고속도로) : 서울톨게이트 → 대전 → 광주 → (해남·강진) → 완도 \r\n 서해안고속도로 : 서울톨게이트 → 목포 → (해남·강진) → 완도 \r\n 남해고속도로 : (부산)대저톨게이트 → 순천 → 강진 → 완도  \r\n", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 20, "waitroom": false, "handicap": false}, "lastUpdateDate": "2017/11/13", "priceitemdate": "2017/11/13"}'::jsonb, '{"hallRent": [{"item": "봉안당(일반)영구 ", "category": "개인단", "subcategory": null, "rentcontent": "1단", "facilityamt": 3500000, "facilityamtm": "3,500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안당(일반) 30년", "category": "개인단", "subcategory": null, "rentcontent": "1단", "facilityamt": 2000000, "facilityamtm": "2,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관리비", "category": "개인단", "subcategory": null, "rentcontent": "1년", "facilityamt": 60000