INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001685', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "존제산 일월사 설법전", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "정순식", "companyno": "416-89-08920", "telephone": "061-853-2003", "faxnum": null, "homepage": "www.ilwolsa.co.kr", "fulladdress": "전라남도 보성군 율어면 유신길 195 (유신리)", "zipcd": "59409", "latitude": "34.866969", "longitude": "127.228267", "sidonm": "전라남도 보성군", "orgid": "4890000", "orgidnm": "전라남도 보성군", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "백두대간의 호남정맥이 바다에 닿을 듯 우뚝 솟은 존제산(尊帝山)은 예로부터 명당(明堂)과 길지(吉地)로 유명합니다.\r\n특히, 일월사 \"설법전\"은 뒤로 존제산을 주산으로 \"좌청룡-우백호-북현무-남주작\" 을 이루는 주변 산들이 전각을 마치병풍처럼 감싸 안고 있어 풍수지리학에서 연화지(蓮花池=연꽃터)라 표현하는 명당 중의 명당입니다.\r\n존제산 일월사에서 새롭게 조성한 \"설법전\"은 고인의 편안한 안식과 유족들의 휴식공간을 배려한 최고의 시설로 조성되었습니다. 고인의 추모를 위한 최신 시설과 역사, 문화, 종교 컨텐츠의 결합을 통하여 고인을 기리고 가족이 함께 할 수 있는 종합 추념 공간입니다.\r\n\r\n", "traffpublic": "- 벌교역, 벌교 버스터미널에서 버스/택시 이용\r\n- 복내면 시외버스터미널에서 택시 이용\r\n", "traffowner": "호남고속도로 주암 IC - 벌교방향 - 석거리재 - 추동삼거리(추동저수지) - 유신저수지 - 일월사\r\n남해고속도로 주암 IC - 순천·벌교방향 - 광주 - 추동삼거리(추동저수지) - 유신저수지 - 일월사", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 200, "waitroom": true, "handicap": false}, "lastUpdateDate": "2016/10/27", "priceitemdate": "2016/10/27"}'::jsonb, '{"hallRent": [{"item": "사용료 ", "category": "개인단", "subcategory": null, "rentcontent": "개인단", "facilityamt": 5000000, "facilityamtm": "5,000,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관리비", "category": "개인단", "subcategory": null, "rentcontent": "개인단 (영구)", "facilityamt": 500000, "facilityamtm": "500,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": [{"category": "유골함", "rentcontent": null, "sale": true, "saleNm": "판매"}]}'::jsonb, '[{"fileorder": 1, "filetitle": "연꽃모양의 봉안함", "filename": "크기변환_3731920701_uSemDw0F_DSC_0104.jpg", "fileurl": "/BCUser/facilitypic/1477300517908_7000001685_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1477300517908_7000001685_0.jpg", "filesize": 168234}, {"fileorder": 2, "filetitle": "봉안실 내부", "filename": "크기변환_3731920701_BlOP9JwE_DSC_0055.jpg", "fileurl": "/BCUser/facilitypic/1477300619326_7000001685_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1477300619326_7000001685_0.jpg", "filesize": 296231}, {"fileorder": 3, "filetitle": "위치전송 시스템", "filename": "크기변환_3731920701_Tt4V215q_DSC_0183.jpg", "fileurl": "/BCUser/facilitypic/1477300689304_7000001685_0.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1477300689304_7000001685_0.jpg", "filesize": 242447}]'::jsonb, '[{"facilitycd": "7000001685", "facilitygroupcd": "TBC0700003", "companyname": "존제산 일월사 설법전", "type": "CharnelDet", "fulladdress": "전라남도 보성군 율어면 유신길 195 (유신리)", "telephone": "061-853-2003", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/1477300517908_7000001685_0.jpg"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
