INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001037', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "합천추모공원 봉안당 ", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "윤중묵", "companyno": "6118208680", "telephone": "055-931-4000", "faxnum": null, "homepage": "www.hcpark.kr", "fulladdress": "경상남도 합천군 합천읍 합천호수로 1633 (합천리)", "zipcd": "50229", "latitude": "35.5648121", "longitude": "128.1469732", "sidonm": "경상남도 합천군", "orgid": "5480000", "orgidnm": "경상남도 합천군", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "경상남도 허가 재단법인이 운영하는 합천추모공원 봉안당(납골당)입니다.\r\n기독교,불교,천주교등 종교에 제약이 없으며 안치기간의 제한이 없는 영구적인 봉안시설입니다.\r\n합천추모공원장례식장(구.새천년장례식장)과의 일원화 시스템으로  종합장례서비스를 제공하고\r\n있으며 봉안당,장례식장을 따로 알아볼 필요 없이 한곳에서 모든 장례절차를 마무리 하실 수 있습니다.\r\n합천읍 도심속 추모공원 시외버스터미널 5분거리 , 남대구IC,진주,거창,의령,산청 30분에 도착 하실 수 있습니다.", "traffpublic": "합천시외버스터미널 에서\r\n합천공설운동장 방향 5분거리\r\n", "traffowner": null, "facilities": {"mealroom": false, "supermarket": true, "parking": true, "parkingCount": 100, "waitroom": true, "handicap": true}, "lastUpdateDate": "2016/06/13", "priceitemdate": "2016/06/13"}'::jsonb, '{"hallRent": [{"item": "개인단(1단~8단)", "category": "개인단", "subcategory": null, "rentcontent": "사용료:150만원~550만원/관리비:5만원(1년)이며 5년치(25만원) 선납", "facilityamt": 1750000, "facilityamtm": "1,750,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "부부단(1단~8단)", "category": "부부단", "subcategory": null, "rentcontent": "사용료:250만원~1050만원/관리비:5만원(1년)이며 5년치(25만원)", "facilityamt": 2750000, "facilityamtm": "2,750,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle"