INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000000649', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "달마사봉안당", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "오대세", "companyno": "108-89-02587", "telephone": "02-822-8771", "faxnum": null, "homepage": "www.dalmasa.org", "fulladdress": "서울특별시 동작구 서달로 50-26 (흑석동, 달마사)", "zipcd": "06987", "latitude": "37.4984973", "longitude": "126.9626582", "sidonm": "서울특별시 동작구", "orgid": "3190000", "orgidnm": "서울특별시 동작구", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "- 최고의 입지조건 : \r\n 서울시내 한복판에 위치, 현충원과 맞닿은 천하명당터, 한강 및 서울시내를 바라보는 빼어난 경관 및 조망권,  사통팔달의 교통편의성 및 우수한 접근성\r\n\r\n- 공신력을 갖춘 사찰봉안당 : \r\n   대한불교조계종 소속 전통사찰 달마사(전통사찰 등록번호 제13호)\r\n   종교단체 봉안당 설치신고 증명서 취득(동작구 제2호)\r\n   전통사찰 건축양식과 첨단 봉안시스템(질소치환 특허)\r\n   매일 끊이지 않는 염불과 기도소리로 영가의 편안한 안식처 ", "traffpublic": "노량진역 1번출구 ->마을버스1번->달마사 종점하차\r\n\r\n낙성대역 5번출구-> 마을버스14번 ->달마사 종점하차\r\n\r\n흑석역 중대병원앞 이동->마을버스1번->달마사 종점하차\r\n", "traffowner": "흑석동 중앙대병원앞 ->서달로 진입->삼성래미안 상도2차 직전, 아치형 육교앞에서 좌회전 ->150미터 직진하면 달마사", "facilities": {"mealroom": true, "supermarket": false, "parking": true, "parkingCount": 30, "waitroom": true, "handicap": false}, "lastUpdateDate": "2017/12/03", "priceitemdate": "2017/12/03"}'::jsonb, '{"hallRent": [{"item": "개인단", "category": "개인단", "subcategory": null, "rentcontent": "영구임대 300만원~950만원", "facilityamt": 0, "facilityamtm": "0", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [{"item": "안치단관리비", "category": "기타", "subcategory": "-", "rentcontent": null, "facilityamt": 500000, "facilityamtm": "500,000", "sale": true, "saleNm": "판매"}], "funeralItem": []}'::jsonb, '[{"fileorder": 