INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001050', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "광릉추모공원 봉안묘", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "이해연", "companyno": "102-82-00525", "telephone": "031-532-2520", "faxnum": "031-534-3116", "homepage": "www.gmemorialpark.com", "fulladdress": "경기도 포천시 내촌면 부마로 341 (마명리)", "zipcd": "11191", "latitude": null, "longitude": null, "sidonm": "경기도 포천시", "orgid": "5600000", "orgidnm": "경기도 포천시", "firstcharnelcnt": 99, "renewyears": 99, "renewcount": 99, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "1969 년 설립된 재단법인 서능공원묘지운영회(광릉추모공원) 내 봉안묘 시설\n", "traffpublic": " 강변역에서 11번 내촌면 하차 택시이용 </br>\n 청량리역에서 707,88번 종점 하차 택시이용  </br>\n 의정부역에서 에서 21번 광릉내 하차 택시이용  </br>\n 동서울터미널에서 3000번 내촌면 하차 택시이용  </br>\n 강남역/잠실역에서 7007번 광릉내 종점 하차 택시이용  </br>\n 태릉역에서 73번 광릉내 종점 하차 택시이용", "traffowner": "ㅁ서울 → 광릉추모공원   </br>\n서울 외곽순환로 → 47번 국도(일동방향) → 내촌/포천시청(87번) → 내촌삼거리 좌회전 → 500미터 전방 우회전 → 내촌교 건너자마자 좌회전 → 1.6km 직진 후 서운동산을 지나 우회전 진입 \n </br>\nㅁ의정부 → 광릉추모공원   </br>\n의정부 → 포천 방향 43번 국도 → 부인터사거리 진접/구리방향 우회전 → 87번 국도 사거리에서 직진 → 내촌교 직전에서 우회전 → 1.6km 직진 후 서운동산을 지나 우회전 진입 ", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 200, "waitroom": false, "handicap": false}, "lastUpdateDate": "2015/06/19", "priceitemdate": "2015/06/19"}'::jsonb, '{"hallRent": [{"item": "사용료", "category": "기타", "subcategory": null, "rentcontent": "제곱미터기준", "facilityamt": 883000, "facilityamtm": "883,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "관리비", "category": "기타", "subcategory": null, "rentcontent": "제곱미터기준(년)", "facilityamt": 9030, "facilityamtm": "9,030", "sale": true, "saleNm": "판매", "avg