INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000093', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "서천군영명각", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "서천군", "companyno": "3098300026--", "telephone": "041-950-4347", "faxnum": null, "homepage": null, "fulladdress": "충청남도 서천군 판교면 심동리 산 73-1번지", "zipcd": "325823", "latitude": "36.1776848", "longitude": "126.6524536", "sidonm": "충청남도 서천군", "orgid": "4580000", "orgidnm": "충청남도 서천군", "firstcharnelcnt": 10, "renewyears": 10, "renewcount": 5, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "ㅁ시 설 명 : 영명각\r\nㅁ소 재 지 : 판교면 심동리 산73-1 (☎ 041-951-4440) \r\nㅁ규     모 : 28,950㎡ (봉안능력 4,000기)\r\nㅁ개관일 : 2001.1.1.\r\nㅁ현 안치기수 : 3,063기(유연2,669기, 무연394기) \r\nㅁ이용대상  \r\n    - 사망자 또는 직계존비속이 사망일 현재 서천군에 본적 또는 \r\n      주민등록이 된 자\r\n    - 군내 기존묘지에서 개장된 유골을 화장 후 안치하려는 자\r\nㅁ안치기간 : 기본 10년(만료후 10년이하 단위로 연장가능)\r\nㅁ사용요금 : 150천원(사용료100천원, 관리료50천원)\r\nㅁ명패비용 20,000원 ", "traffpublic": "<고속버스이용안내>\r\nㅁ시외버스이용시\r\n   서울→천안→예산→대천→서천 (4시간 소요)\r\n   서울→천안→공주→부여→서천 (4시간 소요)\r\nㅁ시내버스이용시\r\n   서천→판교면→심동리→영명각 (30분 소요)\r\n   부여 홍산면→옥산면→판교면→심동리→영명각(40분 소요)\r\n   서천버스터미널(041-953-0776)", "traffowner": "<자가용이용안내>\r\nㅁ서해안고속도로이용시\r\n   서울→평택→당진→홍성→대천→서천IC→판교면→심동리→영명각 (3시간 소요)\r\nㅁ경부고속도로→논산천안고속도로→당진영덕고속도로-공주서천고속도로\r\n   서울→논산천안고속도로(천안JC)→당진영덕고속도로(공주JC)→공주서천고속도로(서공주JC)→\r\n   서천IC→판교면→심동리→영명각 (3시간 소요)\r\nㅁ경부고속도로→호남고속도로→국도\r\n   서울→대전(회덕IC)→호남고속도로→논산(연무IC) →부여(대백제로)→서천IC\r\n   →판교면→심동리→영명각 (3시간30분 소요)\r\n<국도이용시>\r\n  서울→천안→공주→부여→서천IC→판교면→심동리→영명각 (3시간30분 소요)\r\n자가용이용안내\r\n\r\n서해안고속도로이용시\r\n서울→평택→당진→홍성→대천→서천 (2시간30분 소요)\r\n\r\n경부고속도로→논산천안고속도로→당진영덕고속도로-공주서천고속도로\r\n서울→논산천안고속도로(천안JC)→당진영덕고속도로(공주JC)→공주서천고속도로(서공주JC)→서천(2시간30분 소요)\r\n\r\n경부고속도로→호남고속도로→국도\r\n서울→대전(회덕IC)→호남고속도로→논산(연무IC) →부여(대백제로)→서천(3시간소요)\r\n\r\n국도이용시\r\n서울→천안→공주→부여→서천 (3시간 소요)\r\n서천IC⇒판교면⇒심동리(산73-1)\r\n부여군 홍산면⇒부여군 옥산면⇒서천 판교면⇒심동리(산73-1)", "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 50, "waitroom": true, "handicap": false}, "lastUpdateDate": "2026/04/01", "priceitemdate": "2026/04/01"}'::jsonb, '{"hallRent": [{"item": "봉안당 사용료(개인단, 10년)", "category": "개인단", "subcategory": null, "rentcontent": "공통", "facilityamt": 200000, "facilityamtm": "200,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "봉안당 사용료(부부단, 10년)", "category": "부부단", "subcategory": null, "rentcontent": "공통", "facilityamt": 300000, "facilityamtm": "300,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "서천군 영명각", "filename": "서천군 영명각.PNG", "fileurl": "/BCUser/facilitypic/3000000093/1707892039166.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000093/1707892039166.PNG", "filesize": 1449839}]'::jsonb, '[{"facilitycd": "3000000093", "facilitygroupcd": "TBC0700003", "companyname": "서천군영명각", "type": "CharnelDet", "fulladdress": "충청남도 서천군 판교면 심동리 산 73-1번지", "telephone": "041-950-4347", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000093/1707892039166.PNG"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
