INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000039', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "동해시하늘정원봉안당", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "동해시", "companyno": "2228301937", "telephone": "033-530-2894", "faxnum": "033-530-2735", "homepage": null, "fulladdress": "강원특별자치도 동해시 강원남부로 4589 (단봉동, 동해시하늘정원)", "zipcd": "25820", "latitude": "37.4626824", "longitude": "129.1075408", "sidonm": "강원특별자치도 동해시", "orgid": "4210000", "orgidnm": "강원특별자치도 동해시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 130, "innerrenewamt": 0, "innerfeeamt": 60, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "[이용조건]\r\n- 사망자나 지계 존비속이 6개월 이상 동해시에 주민등록한 자\r\n- 타지역에서 사망 했으나 동해시 공설묘지에 가족이 매장되어 있는자\r\n- 시 지역에 매장된 유골을 화장하여 시설에 안치 하는 경우\r\n- 동해시 사망 외국인 및 행려 사망자\r\n- 공공의 목적으로 국가 및 지자체가 시행하는 관내사업장내 분묘에서 발굴된 유골을 화장하여 안치하는 경우\r\n\r\n[사용료 감면대상]\r\n- 기초생활 수급자\r\n- 국가유공자\r\n- 행려사망자\r\n- 단봉동 벽오마을 주민(1년 이상 거주)", "traffpublic": null, "traffowner": null, "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": null, "waitroom": true, "handicap": false}, "lastUpdateDate": "2012/09/05", "priceitemdate": "2012/09/05"}'::jsonb, '{"hallRent": [{"item": "사용료 및 관리비(봉안당)", "category": "개인단", "subcategory": null, "rentcontent": "관내 15년(단장)", "facilityamt": 190000, "facilityamtm": "190,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}, {"item": "사용료 및 관리비(봉안당)", "category": "부부단", "subcategory": null, "rentcontent": "관내 15년(합장)", "facilityamt": 380000, "facilityamtm": "380,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "동해시매화당", "filename": "동해시매화당.jpg", "fileurl": "/BCUser/f