INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000001896', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "대구광역시 낙산추모의집", "publiccode": "TCM0100001", "publiccodeLabel": "공설", "representativename": "대구광역시", "companyno": "501-83-00016", "telephone": "053-312-0348", "faxnum": null, "homepage": null, "fulladdress": "경상북도 칠곡군 지천면 낙산로 87 (낙산리)", "zipcd": "39865", "latitude": "35.9340451", "longitude": "128.5287947", "sidonm": "대구광역시", "orgid": "6270000", "orgidnm": "대구광역시", "firstcharnelcnt": 10, "renewyears": 10, "renewcount": 2, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "「대구광역시 공원묘지ㆍ봉안당」\n1. 사전 참배 ㆍ성묘기간 운영 : 2026.2.7.(토)~2.13.(금) 08:00~17:00\n2. 설날 연휴 정상 운영 ( 2026.2.14.(토) ~ 2.18.(수) 08:00~17:00 )\n\n1. 운영시간 : 08:00~17:00\n\n2003년 11월10일  이후 봉안 햔 유족들께서는 10년이 지나면 연장 신청 및 관리비를 납부 하셔야 합니다. \n명절 기간 봉안 연장 하실분은 통장입금 후 유선으로 신청해 주시기 바랍니다.\n Ex)2010-05-12 봉안한 경우\n2020-01-12(前 4개월)~2020-09-11(後 4개월)\n*연장비용:사망자가 사망당시\n  일반 20만원.\n  차상위,수급자,유공자,유공자 배우자(서류:유공자확인서,혼인관계증명서) 10만원\n\n\n1. 운영시간 : 08:00~17:00\n2. 안치대상 : 사용 신청당시 시 관할구역 안에 주민등록이 되어있는 자 중 사망자\n\n<<대구광역시 공설 봉안당 사용 제한 안내>>\n ○ 제한기간 : 2012. 8. 1. ~\n ○ 제한사유 : 봉안여력 부족\n ○ 제한대상 : 다음 대상자 외 사용을 제한함\n    - 국가유공자(배우자), 기초생활수급자\n    - 시 관할구역 내 사회복지지설 수용자 중 사망자\n    - 시 관할구역 내 사망한 외국인 및 무연고자\n    - 기타 재난 등 특별한 사유가 있다고 시장이 인정하는 사망자", "traffpublic": null, "traffowner": null, "facilities": {"mealroom": false, "supermarket": false, "parking": true, "parkingCount": 223, "waitroom": false, "handicap": false}, "lastUpdateDate": "2018/02/26", "priceitemdate": "2018/02/26"}'::jsonb, '{"hallRent": [{"item": "사용료 및 관리비", "category": "개인단", "subcategory": null, "rentcontent": "10년 / 국가유공자(배우자), 수급자 외 사용제한", "facilityamt": 200000, "facilityamtm": "200,000", "sale": true, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "대구광역시 낙산추모의집", "filename": "대구광역시 낙산추모의집.PNG", "fileurl": "/BCUser/facilitypic/7000001896/1707890128597.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/7000001896/1707890128597.PNG", "filesize": 1437174}]'::jsonb, '[{"facilitycd": "2000000033", "facilitygroupcd": "TBC0700002", "companyname": "대구시립공원묘지", "type": "CemeteryDet", "fulladdress": "경상북도 칠곡군 지천면 낙산로 87 (낙산리)", "telephone": "053-312-0348", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/2000000033/1707287497938.PNG"}, {"facilitycd": "2000000132", "facilitygroupcd": "TBC0700002", "companyname": "동명가족묘지", "type": "CemeteryDet", "fulladdress": "경상북도 칠곡군 동명면 경북대로 456-6 (금암리)", "telephone": "054-977-6377", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/2000000132/1707358035813.PNG"}, {"facilitycd": "2000000133", "facilitygroupcd": "TBC0700002", "companyname": "동명공동묘지", "type": "CemeteryDet", "fulladdress": "경상북도 칠곡군 동명면 학명리 산145-1", "telephone": "054-977-6377", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/2000000133/1711435377730.PNG"}, {"facilitycd": "2000000252", "facilitygroupcd": "TBC0700002", "companyname": "성서공동묘지", "type": "CemeteryDet", "fulladdress": "대구광역시 달서구 달구벌대로276길 122 (장동)", "telephone": "053-586-6444", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/2000000252/1707294430910.PNG"}, {"facilitycd": "7000001896", "facilitygroupcd": "TBC0700003", "companyname": "대구광역시 낙산추모의집", "type": "CharnelDet", "fulladdress": "경상북도 칠곡군 지천면 낙산로 87 (낙산리)", "telephone": "053-312-0348", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/7000001896/1707890128597.PNG"}, {"facilitycd": "7000001897", "facilitygroupcd": "TBC0700003", "companyname": "대구광역시 낙산제2추모의집", "type": "CharnelDet", "fulladdress": "경상북도 칠곡군 지천면 낙산로 87 (낙산리)", "telephone": "053-312-0348", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/700