e, "saleNm": "판매", "avgPriceIn": 0, "avgPriceAll": 0}], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "대구광역시 낙산제2추모의집", "filename": "대구광역시 낙산제2추모의집.PNG", "fileurl": "/BCUser/facilitypic/7000001897/1708306675962.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/7000001897/1708306675962.PNG", "filesize": 502228}]'::jsonb, '[{"facilitycd": "2000000033", "facilitygroupcd": "TBC0700002", "companyname": "대구시립공원묘지", "type": "CemeteryDet", "fulladdress": "경상북도 칠곡군 지천면 낙산로 87 (낙산리)", "telephone": "053-312-0348", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/2000000033/1707287497938.PNG"}, {"facilitycd": "2000000132", "facilitygroupcd": "TBC0700002", "companyname": "동명가족묘지", "type": "CemeteryDet", "fulladdress": "경상북도 칠곡군 동명면 경북대로 456-6 (금암리)", "telephone": "054-977-6377", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/2000000132/1707358035813.PNG"}, {"facilitycd": "2000000133", "facilitygroupcd": "TBC0700002", "companyname": "동명공동묘지", "type": "CemeteryDet", "fulladdress": "경상북도 칠곡군 동명면 학명리 산145-1", "telephone": "054-977-6377", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/2000000133/1711435377730.PNG"}, {"facilitycd": "2000000252", "facilitygroupcd": "TBC0700002", "companyname": "성서공동묘지", "type": "CemeteryDet", "fulladdress": "대구광역시 달서구 달구벌대로276길 122 (장동)", "telephone": "053-586-6444", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/2000000252/1707294430910.PNG"}, {"facilitycd": "7000001896", "facilitygroupcd": "TBC0700003", "companyname": "대구광역시 낙산추모의집", "type": "CharnelDet", "fulladdress": "경상북도 칠곡군 지천면 낙산로 87 (낙산리)", "telephone": "053-312-0348", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/7000001896/1707890128597.PNG"}, {"facilitycd": "7000001897", "facilitygroupcd": "TBC0700003", "companyname": "대구광역시 낙산제2추모의집", "type": "CharnelDet", "fulladdress": "경상북도 칠곡군 지천면 낙산로 87 (낙산리)", "telephone": "053-312-0348", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypi