INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('3000000178', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "보광사 봉안당", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "강대진", "companyno": null, "telephone": "031-948-4440", "faxnum": null, "homepage": "bogwangsa.co.kr/", "fulladdress": "경기도 파주시 광탄면 보광로474번길 87 (영장리)", "zipcd": "10953", "latitude": "37.7529024", "longitude": "126.9198735", "sidonm": "경기도 파주시", "orgid": "4060000", "orgidnm": "경기도 파주시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "※ 보광사까지 오시는 분들은 고양동에서 하차하시어 택시 또는 333번을 이용하시길 \r\n    바랍니다.(택시 이용시 6천원~7천원) ", "traffpublic": "703번 (운행간격: 10 ~ 12분)\r\n\r\n광 탄 : [첫차] 04시30분 [막차] 22시20분,서울역 : [첫차] 05시30분 [막차] 23시20분\r\n\r\n7731번  (운행간격: 5 ~ 6분)\r\n\r\n광 탄 : [첫차] 04시30분 [막차] 22시20분,고양동: [첫차] 04시30분 [막차] 11시50분\r\n\r\n85번 (운행간격: 11 ~ 12분)\r\n\r\n고양동 : [첫차] 05시00분 [막차] 22시00분,송정역 : [첫차] 05시45분 [막차] 12시20분", "traffowner": "의정부 방향에서 오실때\r\n\r\n\r\n\r\n39번국도 이용시 장흥유원지 지나서, 서울시립 용미리 묘지방향우회전(315번도로)후 약1Km지나 벽제동 삼거리(아시아호텔앞)에서 시립 벽제리묘지방향 우회전후 약 2Km\r\n\r\n\r\n\r\n구파발 방향에서 오실때\r\n\r\n\r\n\r\n1번국도 이용시 벽제 승화장 지나서 우회전, 서울시립 용미리 묘지방향우회전(315번도로)후 약1Km지나 벽제동 삼거리(아시아호텔앞)에서 시립 벽제리묘지방향 우회전후 약 2Km\r\n\r\n\r\n\r\n원당(일산)방향에서 오실때\r\n\r\n\r\n\r\n39번국도 이용시 벽제 승화장 고가도로지나 서울시립 용미리 묘지방향우회전(315번도로)후 약1Km지나 벽제동 삼거리(아시아호텔앞)에서 시립 벽제리묘지방향 우회전후 약 2Km\r\n\r\n\r\n\r\n좌석버스 333번 이용시\r\n\r\n\r\n\r\n불광동 시외버스터미널에서 출발 보광사 일주문을 경유하여 광탄까지 운행(오전 6시부터 40분간격 운행 문의: 02)355-5103\r\n", "facilities": {"mealroom": false, "supermarket": false, "parking": false, "parkingCount": null, "waitroom": false, "handicap": false}, "lastUpdateDate": "2010/01/01", "priceitemdate": null}'::jsonb, '{"hallRent": [], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "봉안당", "filename": "2016-07-13 10;12;10.jpg", "fileurl": "/BCUser/facilitypic/3000000178/1468372440653.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000178/1468372440653.jpg", "filesize": 78171}, {"fileorder": 2, "filetitle": "봉안당", "filename": "2016-07-13 10;12;14.jpg", "fileurl": "/BCUser/facilitypic/3000000178/1468372450570.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000178/1468372450570.jpg", "filesize": 87659}, {"fileorder": 3, "filetitle": "봉안당", "filename": "2016-07-13 10;12;24.jpg", "fileurl": "/BCUser/facilitypic/3000000178/1468372461543.jpg", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000178/1468372461543.jpg", "filesize": 88975}]'::jsonb, '[{"facilitycd": "3000000178", "facilitygroupcd": "TBC0700003", "companyname": "보광사 봉안당", "type": "CharnelDet", "fulladdress": "경기도 파주시 광탄면 보광로474번길 87 (영장리)", "telephone": "031-948-4440", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/3000000178/1468372440653.jpg"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
