INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000002114', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "대원정사 봉안당", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "박경자", "companyno": "127-82-78736", "telephone": "031-855-5501", "faxnum": null, "homepage": "www.daewonjungsa.co.kr/", "fulladdress": "경기도 양주시 장흥면 권율로309번길 317-214 (석현리)", "zipcd": "11519", "latitude": null, "longitude": null, "sidonm": "경기도 양주시", "orgid": "5590000", "orgidnm": "경기도 양주시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "양주 장흥면에 위치한 대원정사는 빼어난 아름다운 경관과 차분한 분위기의 사찰입니다.\r\n수목장과 봉안당의 장례시설을 운영하고 있으며 \r\n항상 불자분들에 열려있는곳입니다. ", "traffpublic": "대중교통으로 오시는길\r\n서울출발\r\n지하철 3호선 구파발역 2,3번 출구 버스정류장에서 360번 장흥하차후 택시이용 0318556622 장흥콜택시 번호\r\n버스 704번 송추 플러스마트 하차후 택시이용 0318266888 콜택시 번호\r\n인천출발\r\n인천터미널 부평에서 3700번버스 장흥하차후 택시이용 0318556622 장흥콜택시 번호\r\n의정부 출발\r\n지하철 2호선 의정부역 동부광장 버스 23번 송추하차후 0318266888 콜택시 번호\r\n부대찌개거리 앞 360번 장흥하차 0318556622 장흥콜택시 번호\r\n​", "traffowner": "승용차로 오시는길\r\n서울역\r\n강변북로 자유로 서울외곽순화고속도로 의정부 방면 송추IC 장흥관광지 장흥수목원 대원정사\r\n의정부출발\r\n경민대학교 장흥관광지 장흥수목원 대원정사\r\n일산출발\r\n일산IC 서울 외곽순환도로 송추IC 장흥관광지 장흥수목원 대원정사\r\n네비에 대원정사 입력 양주 장흥면 석현리 304-2\r\n​", "facilities": {"mealroom": true, "supermarket": true, "parking": true, "parkingCount": 50, "waitroom": true, "handicap": false}, "lastUpdateDate": "2010/01/01", "priceitemdate": null}'::jsonb, '{"hallRent": [], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "대원정사 봉안당", "filename": "대원정사 봉안당.PNG", "fileurl": "/BCUser/facilitypic/7000002114/1708481529262.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/7000002114/1708481529262.PNG", "filesize": 1747923}]'