INSERT INTO bp_products (facility_cd, menu_id, facility_group_cd, categories, intro, price, photos, related_facilities, package_list, source_extracted_at) VALUES ('7000002251', 'M0001000100000000', 'TBC0700003', ARRAY['봉안당']::bp_category[], '{"companyname": "묘통사 납골공원", "publiccode": "TCM0100002", "publiccodeLabel": "사설", "representativename": "이무용", "companyno": "613-82-66236", "telephone": "055-855-4050", "faxnum": null, "homepage": "www.myotongsa.co.kr", "fulladdress": "경상남도 사천시 곤명면 세종태실로 106 (은사리)", "zipcd": "52500", "latitude": null, "longitude": null, "sidonm": "경상남도 사천시", "orgid": "5340000", "orgidnm": "경상남도 사천시", "firstcharnelcnt": 0, "renewyears": 0, "renewcount": 0, "innerfirstamt": 0, "innerrenewamt": 0, "innerfeeamt": 0, "inneryearcnt": 0, "outsidefirstamt": 0, "outsiderenewamt": 0, "outsidefeeamt": 0, "outsideyearcnt": 0, "etcinfw": "세종대왕태실지 인근에 건립한 전국 제일의 명당!!\r\n묘통사 납골공원은 경남 사천시 곤명면 은사리 덕재산에 위치한, 서방 극락정토의 주재자인 아미타불을 모시고 안치단에 지장보살 좌상이 모셔진 사찰 납골공원 입니다.\r\n​묘통사 납골공원은 대자연과 어울려져 고인은 물론 모시는 이의 마음까지 정화하여 고인을 안심하고 모실 수 있습니다. 또한 지형적으로 천혜의 명당자리로 예로 부터 경남 사천 곤명 은사는 논두렁에 묘를 써도 명당이라고 하였습니다. 자자손손 부귀영화를 누리는 대자대비하신 부처님의 자비가 어린 땅 입니다.", "traffpublic": "진주 시외버스 주차장 오전/오후 하루 2편 운행\r\n사천 시외버스 주차장=> 진주 시외버스 주차장\r\n", "traffowner": "진주=>완사=>(구) 곤명면사무소=>송림마을=>마곡마을", "facilities": {"mealroom": true, "supermarket": false, "parking": true, "parkingCount": null, "waitroom": true, "handicap": true}, "lastUpdateDate": "2010/01/01", "priceitemdate": null}'::jsonb, '{"hallRent": [], "commission": [], "funeralItem": []}'::jsonb, '[{"fileorder": 1, "filetitle": "묘통사 납골공원", "filename": "묘통사 납골공원.PNG", "fileurl": "/BCUser/facilitypic/7000002251/1708317488445.PNG", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/7000002251/1708317488445.PNG", "filesize": 1847220}]'::jsonb, '[{"facilitycd": "7000002251", "facilitygroupcd": "TBC0700003", "companyname": "묘통사 납골공원", "type": "CharnelDet", "fulladdress": "경상남도 사천시 곤명면 세종태실로 106 (은사리)", "telephone": "055-855-4050", "fileurl_full": "https://15774129.go.kr/BCUser/facilitypic/7000002251/1708317488445.PNG"}]'::jsonb, '[]'::jsonb, '2026-04-17 01:11:26+09') ON CONFLICT (facility_cd) DO UPDATE SET menu_id=EXCLUDED.menu_id, facility_group_cd=EXCLUDED.facility_group_cd, categories=EXCLUDED.categories, intro=EXCLUDED.intro, price=EXCLUDED.price, photos=EXCLUDED.photos, related_facilities=EXCLUDED.related_facilities, package_list=EXCLUDED.package_list, source_extracted_at=EXCLUDED.source_extracted_at;
